        // ── QUIÉNES SOMOS (página) ────────────────────────────────
        'nav.quienes'      => [ 'es'=>'Quiénes somos','en'=>'About us','fr'=>'À propos','de'=>'Über uns','ru'=>'О нас' ],
        'qs.kicker'        => [ 'es'=>'Quiénes somos','en'=>'About us','fr'=>'Qui sommes-nous','de'=>'Wer wir sind','ru'=>'О нас' ],
        'qs.h1.a'          => [ 'es'=>'La información cambia','en'=>'Information changes','fr'=>'L\'information change','de'=>'Information verändert','ru'=>'Информация меняет' ],
        'qs.h1.b'          => [ 'es'=>'el rumbo de una vida.','en'=>'the course of a life.','fr'=>'le cours d\'une vie.','de'=>'den Lauf eines Lebens.','ru'=>'ход целой жизни.' ],
        'qs.lead'          => [ 'es'=>'Las decisiones que más pesan —dónde vivir, dónde invertir, dónde establecerse— se toman demasiadas veces a ciegas. Y muchas salen mal no por mala suerte, sino por falta de información.','en'=>'The decisions that weigh the most —where to live, where to invest, where to settle— are too often made blindly. And many go wrong not through bad luck, but through lack of information.','fr'=>'Les décisions qui pèsent le plus —où vivre, où investir, où s\'établir— se prennent trop souvent à l\'aveugle. Et beaucoup échouent non par malchance, mais par manque d\'information.','de'=>'Die schwersten Entscheidungen —wo man lebt, wo man investiert, wo man sich niederlässt— werden zu oft blind getroffen. Und viele scheitern nicht an Pech, sondern an fehlender Information.','ru'=>'Самые важные решения —где жить, где инвестировать, где обосноваться— слишком часто принимаются вслепую. И многие оказываются неверными не из-за невезения, а из-за нехватки информации.' ],
        'qs.lead.b'        => [ 'es'=>'Por eso existe ROMVILL.','en'=>'That is why ROMVILL exists.','fr'=>'C\'est pourquoi ROMVILL existe.','de'=>'Dafür gibt es ROMVILL.','ru'=>'Именно поэтому существует ROMVILL.' ],
        'qs.trust1'        => [ 'es'=>'Seguridad y análisis de riesgo','en'=>'Security and risk analysis','fr'=>'Sécurité et analyse du risque','de'=>'Sicherheit und Risikoanalyse','ru'=>'Безопасность и анализ рисков' ],
        'qs.trust2'        => [ 'es'=>'Análisis OSINT','en'=>'OSINT analysis','fr'=>'Analyse OSINT','de'=>'OSINT-Analyse','ru'=>'OSINT-анализ' ],
        'qs.trust3'        => [ 'es'=>'Trabajo de campo','en'=>'Field work','fr'=>'Travail de terrain','de'=>'Feldarbeit','ru'=>'Полевая работа' ],
        'qs.trust4'        => [ 'es'=>'Confidencialidad total','en'=>'Total confidentiality','fr'=>'Confidentialité totale','de'=>'Absolute Vertraulichkeit','ru'=>'Полная конфиденциальность' ],
        'qs.s1.title'      => [ 'es'=>'Nacimos sobre el terreno, no en un despacho','en'=>'Born in the field, not behind a desk','fr'=>'Nés sur le terrain, pas dans un bureau','de'=>'Entstanden im Feld, nicht am Schreibtisch','ru'=>'Мы выросли на местах, а не в кабинете' ],
        'qs.s1.p1'         => [ 'es'=>'Detrás de ROMVILL hay años de experiencia real en dirección de seguridad, análisis de riesgo e inteligencia, en entornos exigentes y de alto nivel, en España e internacionalmente. Una trayectoria que nos enseñó una lección que se repetía siempre.','en'=>'Behind ROMVILL lie years of real experience in security management, risk analysis and intelligence, in demanding, high-level environments, in Spain and internationally. A career that taught us one lesson that kept repeating itself.','fr'=>'Derrière ROMVILL, des années d\'expérience réelle en direction de la sécurité, analyse du risque et renseignement, dans des environnements exigeants et de haut niveau, en Espagne et à l\'international. Un parcours qui nous a enseigné une leçon toujours répétée.','de'=>'Hinter ROMVILL stehen Jahre echter Erfahrung in Sicherheitsleitung, Risikoanalyse und Aufklärung, in anspruchsvollen Umgebungen auf hohem Niveau, in Spanien und international. Ein Werdegang, der uns eine Lektion lehrte, die sich stets wiederholte.','ru'=>'За ROMVILL — годы реального опыта в управлении безопасностью, анализе рисков и разведке, в требовательных условиях высокого уровня, в Испании и за рубежом. Путь, который преподал нам урок, повторявшийся снова и снова.' ],
        'qs.s1.p2'         => [ 'es'=>'Cuando proteges a personas y evalúas amenazas, aprendes que la diferencia entre acertar y equivocarse casi nunca es la suerte. Es la información.','en'=>'When you protect people and assess threats, you learn that the difference between getting it right and getting it wrong is almost never luck. It is information.','fr'=>'Quand on protège des personnes et qu\'on évalue des menaces, on apprend que la différence entre réussir et se tromper n\'est presque jamais la chance. C\'est l\'information.','de'=>'Wenn man Menschen schützt und Bedrohungen bewertet, lernt man, dass der Unterschied zwischen richtig und falsch fast nie Glück ist. Es ist die Information.','ru'=>'Когда вы защищаете людей и оцениваете угрозы, вы понимаете, что разница между верным и ошибочным решением почти никогда не в удаче. Дело в информации.' ],
        'qs.quote'         => [ 'es'=>'El mayor riesgo no es el que se ve, sino el que se desconoce.','en'=>'The greatest risk is not the one you see, but the one you do not know.','fr'=>'Le plus grand risque n\'est pas celui que l\'on voit, mais celui que l\'on ignore.','de'=>'Das größte Risiko ist nicht das sichtbare, sondern das unbekannte.','ru'=>'Самый большой риск — не тот, что виден, а тот, о котором не знаешь.' ],
        'qs.s2.title'      => [ 'es'=>'Somos analistas, no vendedores','en'=>'We are analysts, not salespeople','fr'=>'Nous sommes des analystes, pas des vendeurs','de'=>'Wir sind Analysten, keine Verkäufer','ru'=>'Мы аналитики, а не продавцы' ],
        'qs.s2.p1'         => [ 'es'=>'Aplicamos esa misma disciplina al análisis del territorio de la Costa Mediterránea —Alicante, Málaga y Marbella—: metodología de inteligencia, fuentes oficiales contrastadas (OSINT) y verificación directa sobre el terreno. No somos una inmobiliaria ni un buscador de datos genéricos.','en'=>'We apply that same discipline to analysing the Mediterranean Coast —Alicante, Málaga and Marbella—: intelligence methodology, verified official sources (OSINT) and direct on-site verification. We are not a real-estate agency or a generic data search.','fr'=>'Nous appliquons cette même rigueur à l\'analyse de la Côte méditerranéenne —Alicante, Málaga et Marbella—: méthodologie de renseignement, sources officielles recoupées (OSINT) et vérification directe sur le terrain. Nous ne sommes ni une agence immobilière ni un moteur de données génériques.','de'=>'Dieselbe Disziplin wenden wir auf die Analyse der Mittelmeerküste an —Alicante, Málaga und Marbella—: Aufklärungsmethodik, geprüfte amtliche Quellen (OSINT) und direkte Verifizierung vor Ort. Wir sind keine Immobilienagentur und keine generische Datensuche.','ru'=>'Ту же дисциплину мы применяем к анализу Средиземноморского побережья —Аликанте, Малага и Марбелья—: методология разведки, проверенные официальные источники (OSINT) и прямая проверка на месте. Мы не агентство недвижимости и не поиск общих данных.' ],
        'qs.s2.p2'         => [ 'es'=>'Estudiamos una zona con el mismo rigor con el que se evalúa un entorno antes de una decisión crítica: sin atajos, sin intereses ocultos y con los pies en el suelo.','en'=>'We study an area with the same rigour used to assess an environment before a critical decision: no shortcuts, no hidden interests, with both feet on the ground.','fr'=>'Nous étudions une zone avec la même rigueur qu\'on évalue un environnement avant une décision critique : sans raccourcis, sans intérêts cachés et les pieds sur terre.','de'=>'Wir untersuchen ein Gebiet mit derselben Strenge, mit der man ein Umfeld vor einer kritischen Entscheidung bewertet: ohne Abkürzungen, ohne verborgene Interessen und mit beiden Füßen auf dem Boden.','ru'=>'Мы изучаем район с той же строгостью, с какой оценивают обстановку перед критическим решением: без сокращённых путей, без скрытых интересов и твёрдо стоя на земле.' ],
        'qs.values.kicker' => [ 'es'=>'Nuestros principios','en'=>'Our principles','fr'=>'Nos principes','de'=>'Unsere Prinzipien','ru'=>'Наши принципы' ],
        'qs.values.title'  => [ 'es'=>'En qué creemos','en'=>'What we believe in','fr'=>'Ce en quoi nous croyons','de'=>'Woran wir glauben','ru'=>'Во что мы верим' ],
        'qs.v1.t'          => [ 'es'=>'Independencia','en'=>'Independence','fr'=>'Indépendance','de'=>'Unabhängigkeit','ru'=>'Независимость' ],
        'qs.v1.d'          => [ 'es'=>'No vendemos inmuebles ni cobramos comisiones. Nuestro único interés es que usted tenga la verdad.','en'=>'We do not sell property or earn commissions. Our only interest is that you have the truth.','fr'=>'Nous ne vendons aucun bien et ne touchons aucune commission. Notre seul intérêt est que vous ayez la vérité.','de'=>'Wir verkaufen keine Immobilien und erhalten keine Provisionen. Unser einziges Interesse ist, dass Sie die Wahrheit kennen.','ru'=>'Мы не продаём недвижимость и не берём комиссий. Наш единственный интерес — чтобы вы знали правду.' ],
        'qs.v2.t'          => [ 'es'=>'Rigor','en'=>'Rigour','fr'=>'Rigueur','de'=>'Sorgfalt','ru'=>'Строгость' ],
        'qs.v2.d'          => [ 'es'=>'Cruzamos fuentes oficiales con comprobación presencial. Datos, no rumores.','en'=>'We cross-check official sources with on-site checks. Data, not rumours.','fr'=>'Nous croisons les sources officielles avec une vérification sur place. Des données, pas des rumeurs.','de'=>'Wir verknüpfen amtliche Quellen mit Prüfungen vor Ort. Daten, keine Gerüchte.','ru'=>'Мы сверяем официальные источники с проверкой на месте. Данные, а не слухи.' ],
        'qs.v3.t'          => [ 'es'=>'Discreción','en'=>'Discretion','fr'=>'Discrétion','de'=>'Diskretion','ru'=>'Сдержанность' ],
        'qs.v3.d'          => [ 'es'=>'Confidencialidad absoluta. Forma parte de nuestro oficio.','en'=>'Absolute confidentiality. It is part of our craft.','fr'=>'Confidentialité absolue. Cela fait partie de notre métier.','de'=>'Absolute Vertraulichkeit. Das gehört zu unserem Handwerk.','ru'=>'Абсолютная конфиденциальность. Это часть нашего ремесла.' ],
        'qs.v4.t'          => [ 'es'=>'Criterio','en'=>'Judgement','fr'=>'Discernement','de'=>'Urteilsvermögen','ru'=>'Здравый смысл' ],
        'qs.v4.d'          => [ 'es'=>'Le damos información para decidir, no para impresionar.','en'=>'We give you information to decide, not to impress.','fr'=>'Nous vous donnons de l\'information pour décider, pas pour impressionner.','de'=>'Wir geben Ihnen Informationen zum Entscheiden, nicht zum Beeindrucken.','ru'=>'Мы даём информацию, чтобы вы решали, а не чтобы впечатлить.' ],
        'qs.close1'        => [ 'es'=>'Nadie debería jugarse una decisión que cambia su vida por falta de información.','en'=>'No one should have to gamble on a life-changing decision for lack of information.','fr'=>'Personne ne devrait risquer une décision qui change sa vie par manque d\'information.','de'=>'Niemand sollte eine lebensverändernde Entscheidung aus Mangel an Information aufs Spiel setzen.','ru'=>'Никто не должен ставить под угрозу решение, меняющее жизнь, из-за нехватки информации.' ],
        'qs.close2'        => [ 'es'=>'Para eso estamos: para que usted decida con criterio, no con esperanza.','en'=>'That is what we are here for: so you decide with judgement, not with hope.','fr'=>'C\'est notre raison d\'être : que vous décidiez avec discernement, non avec espoir.','de'=>'Dafür sind wir da: damit Sie mit Urteil entscheiden, nicht mit Hoffnung.','ru'=>'Для этого мы и существуем: чтобы вы принимали решение взвешенно, а не в надежде на удачу.' ],
        'qs.sign'          => [ 'es'=>'— El equipo de ROMVILL','en'=>'— The ROMVILL team','fr'=>'— L\'équipe ROMVILL','de'=>'— Das ROMVILL-Team','ru'=>'— Команда ROMVILL' ],
        'qs.cta'           => [ 'es'=>'Solicitar mi informe','en'=>'Request my report','fr'=>'Demander mon rapport','de'=>'Meinen Bericht anfordern','ru'=>'Запросить мой отчёт' ],
        'qs.midcta'        => [ 'es'=>'Hablar con nosotros','en'=>'Talk to us','fr'=>'Parlons-en','de'=>'Sprechen Sie mit uns','ru'=>'Поговорить с нами' ],

