        'ix.sl.help'     => [ 'es'=>'Pasa el ratón sobre la imagen; el control se mueve solo (o desliza el dedo en móvil).','en'=>'Move your cursor over the image; the slider follows it (or swipe on mobile).','fr'=>'Passez le curseur sur l\'image ; la glissière suit (ou faites glisser le doigt sur mobile).','de'=>'Bewegen Sie den Mauszeiger über das Bild; der Regler folgt (oder wischen Sie am Handy).','ru'=>'Наведите курсор на изображение — ползунок следует за ним (или проведите пальцем на телефоне).' ],
