        'ix.sl.seg.t'    => [ 'es'=>'Seguridad','en'=>'Safety','fr'=>'Sécurité','de'=>'Sicherheit','ru'=>'Безопасность' ],
        'ix.sl.seg.d'    => [ 'es'=>'Conocer cómo es la seguridad real de una zona, no solo lo que aparenta a simple vista','en'=>'Knowing what an area\'s real safety is like, not just how it looks at first glance','fr'=>'Connaître la vraie sécurité d\'une zone, pas seulement son apparence au premier coup d\'œil','de'=>'Wissen, wie sicher eine Gegend wirklich ist — nicht nur, wie sie auf den ersten Blick wirkt','ru'=>'Узнать, какова безопасность района на самом деле, а не только как он выглядит на первый взгляд' ],
        'ix.sl.dem.t'    => [ 'es'=>'Demografía','en'=>'Demographics','fr'=>'Démographie','de'=>'Demografie','ru'=>'Демография' ],
        'ix.sl.dem.d'    => [ 'es'=>'Saber quién vive realmente en la zona y si encaja con tu estilo de vida','en'=>'Knowing who really lives in the area and whether it fits your lifestyle','fr'=>'Savoir qui vit vraiment dans la zone et si elle correspond à votre mode de vie','de'=>'Wissen, wer wirklich in der Gegend lebt und ob sie zu Ihrem Lebensstil passt','ru'=>'Узнать, кто на самом деле живёт в районе и подходит ли он вашему образу жизни' ],
        'ix.sl.san.t'    => [ 'es'=>'Sanidad','en'=>'Healthcare','fr'=>'Santé','de'=>'Gesundheit','ru'=>'Здравоохранение' ],
        'ix.sl.san.d'    => [ 'es'=>'Tener claro qué cobertura médica y de urgencias hay de verdad cerca','en'=>'Being clear about what medical and emergency care is really nearby','fr'=>'Savoir clairement quelle couverture médicale et d\'urgence se trouve vraiment à proximité','de'=>'Klar wissen, welche medizinische und Notfallversorgung wirklich in der Nähe ist','ru'=>'Чётко понимать, какая медицинская и неотложная помощь действительно есть рядом' ],
        'ix.sl.mov.t'    => [ 'es'=>'Movilidad','en'=>'Mobility','fr'=>'Mobilité','de'=>'Mobilität','ru'=>'Мобильность' ],
        'ix.sl.mov.d'    => [ 'es'=>'Saber lo bien o mal conectada que está la zona en tu día a día','en'=>'Knowing how well or poorly connected the area is for your daily life','fr'=>'Savoir à quel point la zone est bien ou mal connectée au quotidien','de'=>'Wissen, wie gut oder schlecht die Gegend im Alltag angebunden ist','ru'=>'Узнать, насколько хорошо или плохо район связан в повседневной жизни' ],
        'ix.sl.dev.t'    => [ 'es'=>'Desarrollo futuro','en'=>'Future development','fr'=>'Développement futur','de'=>'Zukünftige Entwicklung','ru'=>'Будущее развитие' ],
        'ix.sl.dev.d'    => [ 'es'=>'Conocer qué va a cambiar en la zona antes de que te afecte','en'=>'Knowing what will change in the area before it affects you','fr'=>'Savoir ce qui va changer dans la zone avant que cela vous touche','de'=>'Wissen, was sich in der Gegend ändern wird, bevor es Sie betrifft','ru'=>'Узнать, что изменится в районе, прежде чем это вас коснётся' ],
        'ix.hs.kicker'   => [ 'es'=>'Trabajo de campo','en'=>'Field work','fr'=>'Travail de terrain','de'=>'Feldarbeit','ru'=>'Полевая работа' ],
        'ix.hs.title'    => [ 'es'=>'Verificación sobre el terreno','en'=>'On-the-ground verification','fr'=>'Vérification sur le terrain','de'=>'Überprüfung vor Ort','ru'=>'Проверка на месте' ],
        'ix.hs.help'     => [ 'es'=>'No analizamos una zona desde un despacho. Toca cada punto y mira qué comprobamos en la propia zona.','en'=>'We do not analyse an area from a desk. Tap each point and see what we verify in the area itself.','fr'=>'Nous n\'analysons pas une zone depuis un bureau. Touchez chaque point et voyez ce que nous vérifions sur place.','de'=>'Wir analysieren ein Gebiet nicht vom Schreibtisch aus. Tippen Sie auf jeden Punkt und sehen Sie, was wir vor Ort prüfen.','ru'=>'Мы не анализируем район из кабинета. Нажмите на каждую точку и посмотрите, что мы проверяем на месте.' ],
        'ix.hs.hint'     => [ 'es'=>'Toca un punto','en'=>'Tap a point','fr'=>'Touchez un point','de'=>'Tippen Sie auf einen Punkt','ru'=>'Нажмите на точку' ],
        'ix.hs.seg.t'    => [ 'es'=>'Seguridad y convivencia','en'=>'Safety and community','fr'=>'Sécurité et vie locale','de'=>'Sicherheit und Zusammenleben','ru'=>'Безопасность и сосуществование' ],
        'ix.hs.seg.d'    => [ 'es'=>'Describimos el contexto de convivencia y seguridad con datos de fuentes oficiales (Policía y Guardia Civil), de forma objetiva y sin clasificar la zona por peligrosidad.','en'=>'We describe the safety and community context using official sources (Police and Guardia Civil), objectively and without rating the area by danger.','fr'=>'Nous décrivons le contexte de sécurité et de vie locale à partir de sources officielles (Police et Guardia Civil), de façon objective et sans classer la zone par dangerosité.','de'=>'Wir beschreiben den Sicherheits- und Zusammenlebenskontext anhand offizieller Quellen (Polizei und Guardia Civil), objektiv und ohne die Gegend nach Gefährlichkeit einzustufen.','ru'=>'Мы описываем контекст безопасности и сосуществования по официальным источникам (полиция и Guardia Civil), объективно и без классификации района по опасности.' ],
        'ix.hs.dem.t'    => [ 'es'=>'Perfil demográfico','en'=>'Demographic profile','fr'=>'Profil démographique','de'=>'Demografisches Profil','ru'=>'Демографический профиль' ],
        'ix.hs.dem.d'    => [ 'es'=>'Mostramos cómo es la comunidad que vive en la zona —edad, origen y renta media del entorno— y qué ambiente social predomina, para saber si encaja contigo.','en'=>'We show what the local community is like —age, origin and average income of the area— and the prevailing social environment, so you know if it fits you.','fr'=>'Nous montrons à quoi ressemble la communauté locale —âge, origine et revenu moyen— et l\'ambiance sociale dominante, pour savoir si elle vous convient.','de'=>'Wir zeigen, wie die örtliche Gemeinschaft ist —Alter, Herkunft und Durchschnittseinkommen— und welche soziale Atmosphäre vorherrscht, damit Sie wissen, ob es zu Ihnen passt.','ru'=>'Мы показываем, каково местное сообщество —возраст, происхождение и средний доход— и какая социальная атмосфера преобладает, чтобы понять, подходит ли она вам.' ],
        'ix.hs.san.t'    => [ 'es'=>'Sanidad y emergencias','en'=>'Healthcare and emergencies','fr'=>'Santé et urgences','de'=>'Gesundheit und Notfälle','ru'=>'Здравоохранение и экстренные службы' ],
        'ix.hs.san.d'    => [ 'es'=>'Reunimos la cobertura sanitaria y de emergencias accesible desde la zona: hospitales, centros de salud y distancias reales a urgencias.','en'=>'We gather the healthcare and emergency coverage reachable from the area: hospitals, health centres and real distances to emergency care.','fr'=>'Nous réunissons la couverture sanitaire et d\'urgence accessible depuis la zone : hôpitaux, centres de santé et distances réelles aux urgences.','de'=>'Wir erfassen die von der Gegend aus erreichbare Gesundheits- und Notfallversorgung: Krankenhäuser, Gesundheitszentren und reale Entfernungen zur Notaufnahme.','ru'=>'Мы сводим воедино данные о медицинской и экстренной помощи, доступной из района: больницы, медцентры и реальные расстояния до неотложной помощи.' ],
        'ix.hs.mov.t'    => [ 'es'=>'Movilidad','en'=>'Mobility','fr'=>'Mobilité','de'=>'Mobilität','ru'=>'Мобильность' ],
        'ix.hs.mov.d'    => [ 'es'=>'Explicamos cómo te mueves por la zona y cómo de conectada está: accesos, transporte público y conexión con aeropuertos y núcleos cercanos.','en'=>'We explain how you get around the area and how connected it is: access roads, public transport and links to airports and nearby towns.','fr'=>'Nous expliquons comment on se déplace dans la zone et son niveau de connexion : accès, transports publics et liaisons aux aéroports et villes proches.','de'=>'Wir erklären, wie man sich in der Gegend bewegt und wie gut sie angebunden ist: Zufahrten, öffentlicher Verkehr und Verbindungen zu Flughäfen und nahen Orten.','ru'=>'Мы объясняем, как передвигаться по району и насколько он связан: подъезды, общественный транспорт и сообщение с аэропортами и соседними городами.' ],
        'ix.hs.dev.t'    => [ 'es'=>'Desarrollo futuro','en'=>'Future development','fr'=>'Développement futur','de'=>'Zukünftige Entwicklung','ru'=>'Будущее развитие' ],
        'ix.hs.dev.d'    => [ 'es'=>'Reunimos los cambios previstos por la planificación pública oficial —obras e infraestructuras— sin hacer proyecciones de revalorización.','en'=>'We gather the changes planned by official public planning —works and infrastructure— without making property-value forecasts.','fr'=>'Nous réunissons les changements prévus par la planification publique officielle —travaux et infrastructures— sans projections de revalorisation.','de'=>'Wir erfassen die von der offiziellen öffentlichen Planung vorgesehenen Änderungen —Bauarbeiten und Infrastruktur— ohne Wertsteigerungsprognosen.','ru'=>'Мы собираем изменения, предусмотренные официальным государственным планированием —работы и инфраструктуру— без прогнозов роста стоимости.' ],
        'qs.teaser.title'  => [ 'es'=>'No somos una inmobiliaria. Somos analistas.','en'=>'We are not a real-estate agency. We are analysts.','fr'=>'Nous ne sommes pas une agence immobilière. Nous sommes des analystes.','de'=>'Wir sind keine Immobilienagentur. Wir sind Analysten.','ru'=>'Мы не агентство недвижимости. Мы аналитики.' ],
        'qs.teaser.desc'   => [ 'es'=>'Detrás de ROMVILL hay experiencia real en seguridad e inteligencia, aplicada a una sola cosa: que usted decida con información, no a ciegas.','en'=>'Behind ROMVILL lies real experience in security and intelligence, applied to one thing: that you decide with information, not blindly.','fr'=>'Derrière ROMVILL, une expérience réelle en sécurité et renseignement, au service d\'une seule chose : que vous décidiez avec de l\'information, pas à l\'aveugle.','de'=>'Hinter ROMVILL steht echte Erfahrung in Sicherheit und Aufklärung — für eine einzige Sache: dass Sie mit Information entscheiden, nicht blind.','ru'=>'За ROMVILL — реальный опыт в безопасности и разведке, направленный на одно: чтобы вы решали с информацией, а не вслепую.' ],
        'qs.teaser.cta'    => [ 'es'=>'Conócenos','en'=>'Get to know us','fr'=>'Découvrez-nous','de'=>'Lernen Sie uns kennen','ru'=>'Узнать о нас' ],
        'seo.title.quienes-somos' => [ 'es'=>'Quiénes somos — ROMVILL · Inteligencia territorial independiente','en'=>'About us — ROMVILL · Independent territorial intelligence','fr'=>'Qui sommes-nous — ROMVILL · Intelligence territoriale indépendante','de'=>'Über uns — ROMVILL · Unabhängige territoriale Standortanalyse','ru'=>'О нас — ROMVILL · Независимая территориальная аналитика' ],
        'seo.desc.quienes-somos'  => [ 'es'=>'Detrás de ROMVILL: experiencia real en seguridad, análisis de riesgo e inteligencia, aplicada al análisis independiente de zonas en Alicante, Málaga y Marbella.','en'=>'Behind ROMVILL: real experience in security, risk analysis and intelligence, applied to the independent analysis of areas in Alicante, Málaga and Marbella.','fr'=>'Derrière ROMVILL : une expérience réelle en sécurité, analyse du risque et renseignement, appliquée à l\'analyse indépendante de zones à Alicante, Málaga et Marbella.','de'=>'Hinter ROMVILL: echte Erfahrung in Sicherheit, Risikoanalyse und Aufklärung, angewandt auf die unabhängige Analyse von Gebieten in Alicante, Málaga und Marbella.','ru'=>'За ROMVILL: реальный опыт в безопасности, анализе рисков и разведке, применённый к независимому анализу районов в Аликанте, Малаге и Марбелье.' ],

