        'zona.hero.kicker' => [ 'es'=>'Zona de análisis','en'=>'Area analysis','fr'=>'Zone d\'analyse','de'=>'Analysegebiet','ru'=>'Зона анализа' ],
        'zona.hero.cta'    => [ 'es'=>'Solicitar informe de zona','en'=>'Request area report','fr'=>'Demander le rapport de zone','de'=>'Gebietsbericht anfordern','ru'=>'Запросить отчёт по зоне' ],
        'zona.intro.kicker'=> [ 'es'=>'Por qué importa la zona exacta','en'=>'Why the exact area matters','fr'=>'Pourquoi la zone exacte compte','de'=>'Warum das genaue Gebiet zählt','ru'=>'Почему важен точный район' ],
        'zona.dim.kicker'  => [ 'es'=>'Qué estudiamos en tu zona','en'=>'What we study in your area','fr'=>'Ce que nous étudions dans votre zone','de'=>'Was wir in Ihrem Gebiet untersuchen','ru'=>'Что мы изучаем в вашем районе' ],
        'zona.dim.title'   => [ 'es'=>'Seis miradas sobre el mismo lugar','en'=>'Six angles on the same place','fr'=>'Six regards sur le même lieu','de'=>'Sechs Blicke auf denselben Ort','ru'=>'Шесть взглядов на одно место' ],
        'zona.dim.seg.t'   => [ 'es'=>'Seguridad y convivencia','en'=>'Safety and community','fr'=>'Sécurité et vie locale','de'=>'Sicherheit und Zusammenleben','ru'=>'Безопасность и сосуществование' ],
        'zona.dim.seg.d'   => [ 'es'=>'El contexto real de convivencia y seguridad de la zona, con datos de fuentes oficiales. Sin juicios ni etiquetas.','en'=>'The real safety and community context of the area, from official sources. No judgements or labels.','fr'=>'Le vrai contexte de sécurité et de vie locale de la zone, à partir de sources officielles. Sans jugements ni étiquettes.','de'=>'Der reale Sicherheits- und Zusammenlebenskontext des Gebiets, aus offiziellen Quellen. Ohne Urteile oder Etiketten.','ru'=>'Реальный контекст безопасности и сосуществования района по официальным источникам. Без оценок и ярлыков.' ],
        'zona.dim.dem.t'   => [ 'es'=>'Quién vive aquí','en'=>'Who lives here','fr'=>'Qui vit ici','de'=>'Wer hier lebt','ru'=>'Кто здесь живёт' ],
        'zona.dim.dem.d'   => [ 'es'=>'El perfil de cada urbanización o barrio: ambiente, residentes fijos frente a temporada, y si encaja contigo.','en'=>'The profile of each urbanisation or neighbourhood: atmosphere, permanent versus seasonal residents, and whether it fits you.','fr'=>'Le profil de chaque résidence ou quartier : ambiance, résidents permanents ou saisonniers, et si cela vous convient.','de'=>'Das Profil jeder Wohnanlage oder jedes Viertels: Atmosphäre, Dauer- gegenüber Saisonbewohnern, und ob es zu Ihnen passt.','ru'=>'Профиль каждого посёлка или района: атмосфера, постоянные и сезонные жители и подходит ли он вам.' ],
        'zona.dim.san.t'   => [ 'es'=>'Sanidad y emergencias','en'=>'Healthcare and emergencies','fr'=>'Santé et urgences','de'=>'Gesundheit und Notfälle','ru'=>'Здравоохранение и экстренные службы' ],
        'zona.dim.san.d'   => [ 'es'=>'Hospitales, urgencias y tiempos reales de respuesta desde la zona.','en'=>'Hospitals, emergency care and real response times from the area.','fr'=>'Hôpitaux, urgences et temps de réponse réels depuis la zone.','de'=>'Krankenhäuser, Notaufnahmen und reale Reaktionszeiten vom Gebiet aus.','ru'=>'Больницы, неотложная помощь и реальное время реагирования из района.' ],
        'zona.dim.mov.t'   => [ 'es'=>'Movilidad y accesos','en'=>'Mobility and access','fr'=>'Mobilité et accès','de'=>'Mobilität und Zufahrten','ru'=>'Мобильность и доступ' ],
        'zona.dim.mov.d'   => [ 'es'=>'Conexión con los núcleos cercanos y el aeropuerto, y cómo cambian los accesos en temporada.','en'=>'Links to nearby towns and the airport, and how access changes in high season.','fr'=>'Liaisons avec les villes proches et l\'aéroport, et comment les accès changent en haute saison.','de'=>'Verbindungen zu nahen Orten und zum Flughafen und wie sich die Zufahrten in der Hochsaison ändern.','ru'=>'Связь с ближайшими городами и аэропортом и как меняется доступ в высокий сезон.' ],
        'zona.dim.serv.t'  => [ 'es'=>'Servicios y vida diaria','en'=>'Services and daily life','fr'=>'Services et vie quotidienne','de'=>'Dienstleistungen und Alltag','ru'=>'Услуги и повседневная жизнь' ],
        'zona.dim.serv.d'  => [ 'es'=>'Colegios, comercio y servicios reales de la zona, para el día a día, no solo para las vacaciones.','en'=>'Schools, shops and real services in the area, for daily life, not just for the holidays.','fr'=>'Écoles, commerces et services réels de la zone, pour le quotidien, pas seulement pour les vacances.','de'=>'Schulen, Geschäfte und echte Dienstleistungen des Gebiets, für den Alltag, nicht nur für den Urlaub.','ru'=>'Школы, магазины и реальные услуги района для повседневной жизни, а не только для отпуска.' ],
        'zona.dim.dev.t'   => [ 'es'=>'Desarrollo futuro','en'=>'Future development','fr'=>'Développement futur','de'=>'Zukünftige Entwicklung','ru'=>'Будущее развитие' ],
        'zona.dim.dev.d'   => [ 'es'=>'Qué proyectos y planes urbanísticos oficiales afectan a la zona, sin especular con la revalorización.','en'=>'Which official projects and urban plans affect the area, without speculating on property values.','fr'=>'Quels projets et plans d\'urbanisme officiels touchent la zone, sans spéculer sur la revalorisation.','de'=>'Welche offiziellen Projekte und Bebauungspläne das Gebiet betreffen, ohne über Wertsteigerung zu spekulieren.','ru'=>'Какие официальные проекты и градостроительные планы затрагивают район, без спекуляций о росте стоимости.' ],
        'zona.why.kicker'  => [ 'es'=>'Por qué ROMVILL y no una inmobiliaria','en'=>'Why ROMVILL and not a real-estate agency','fr'=>'Pourquoi ROMVILL et pas une agence immobilière','de'=>'Warum ROMVILL und keine Immobilienagentur','ru'=>'Почему ROMVILL, а не агентство недвижимости' ],
        'zona.why.title'   => [ 'es'=>'Nuestro único interés es que tengas la verdad','en'=>'Our only interest is that you have the truth','fr'=>'Notre seul intérêt est que vous ayez la vérité','de'=>'Unser einziges Interesse ist, dass Sie die Wahrheit kennen','ru'=>'Наш единственный интерес — чтобы вы знали правду' ],
        'zona.why.p1'      => [ 'es'=>'No vendemos inmuebles ni cobramos comisiones por ninguna operación. Eso nos deja libres para contarte lo que realmente hay en cada zona, incluido lo que un vendedor preferiría que no supieras.','en'=>'We do not sell property or earn commissions on any deal. That leaves us free to tell you what is really in each area, including what a seller would rather you did not know.','fr'=>'Nous ne vendons aucun bien et ne touchons aucune commission sur aucune opération. Cela nous laisse libres de vous dire ce qu\'il y a vraiment dans chaque zone, y compris ce qu\'un vendeur préférerait que vous ignoriez.','de'=>'Wir verkaufen keine Immobilien und erhalten bei keinem Geschäft Provisionen. Das lässt uns frei, Ihnen zu sagen, was in jedem Gebiet wirklich los ist — auch das, was ein Verkäufer lieber verschweigen würde.','ru'=>'Мы не продаём недвижимость и не получаем комиссий ни с одной сделки. Это позволяет нам честно рассказать, что на самом деле есть в каждом районе, включая то, о чём продавец предпочёл бы умолчать.' ],
        'zona.why.p2'      => [ 'es'=>'Cruzamos <b>fuentes oficiales contrastadas</b> con <b>verificación sobre el terreno</b>. El mismo método de inteligencia con el que se evalúa un entorno antes de una decisión crítica.','en'=>'We cross <b>verified official sources</b> with <b>on-the-ground verification</b>. The same intelligence method used to assess an environment before a critical decision.','fr'=>'Nous croisons des <b>sources officielles recoupées</b> avec une <b>vérification sur le terrain</b>. La même méthode de renseignement qu\'on emploie avant une décision critique.','de'=>'Wir verknüpfen <b>geprüfte amtliche Quellen</b> mit <b>Verifizierung vor Ort</b>. Dieselbe Aufklärungsmethode, mit der man ein Umfeld vor einer kritischen Entscheidung bewertet.','ru'=>'Мы сверяем <b>проверенные официальные источники</b> с <b>проверкой на месте</b>. Тот же метод разведки, которым оценивают обстановку перед критическим решением.' ],
        'zona.close.title' => [ 'es'=>'¿Vas a invertir o mudarte a la zona?','en'=>'Thinking of investing or moving to the area?','fr'=>'Vous comptez investir ou vous installer dans la zone ?','de'=>'Wollen Sie in dem Gebiet investieren oder dorthin ziehen?','ru'=>'Собираетесь инвестировать или переехать в район?' ],
        'zona.close.p'     => [ 'es'=>'Pídenos el análisis independiente de la zona exacta que te interesa. Sabrás lo que hay antes de decidir.','en'=>'Ask us for an independent analysis of the exact area you are interested in. You will know what is there before you decide.','fr'=>'Demandez-nous l\'analyse indépendante de la zone exacte qui vous intéresse. Vous saurez ce qu\'il en est avant de décider.','de'=>'Fordern Sie eine unabhängige Analyse des genauen Gebiets an, das Sie interessiert. Sie wissen Bescheid, bevor Sie entscheiden.','ru'=>'Закажите независимый анализ именно того района, который вас интересует. Вы будете знать, что там, до принятия решения.' ],
        'zona.close.cta'   => [ 'es'=>'Solicitar mi informe de zona','en'=>'Request my area report','fr'=>'Demander mon rapport de zone','de'=>'Meinen Gebietsbericht anfordern','ru'=>'Запросить мой отчёт по зоне' ],
        'zona.link.ver'    => [ 'es'=>'Ver análisis de zona','en'=>'See area analysis','fr'=>'Voir l\'analyse de zone','de'=>'Gebietsanalyse ansehen','ru'=>'Смотреть анализ зоны' ],

