        'nav.faq'          => [ 'es'=>'FAQ','en'=>'FAQ','fr'=>'FAQ','de'=>'FAQ','ru'=>'FAQ' ],
        'nav.faq.full'     => [ 'es'=>'Preguntas frecuentes','en'=>'Frequently asked questions','fr'=>'Questions fréquentes','de'=>'Häufige Fragen','ru'=>'Частые вопросы' ],
        'seo.title.preguntas-frecuentes' => [ 'es'=>'Preguntas frecuentes | ROMVILL','en'=>'FAQ | ROMVILL','fr'=>'Questions fréquentes | ROMVILL','de'=>'Häufige Fragen | ROMVILL','ru'=>'Частые вопросы | ROMVILL' ],
        'seo.desc.preguntas-frecuentes' => [ 'es'=>'Resolvemos tus dudas sobre los informes de zona de ROMVILL: qué analizamos, de dónde salen los datos, independencia, plazos, precios y zonas de la Costa Mediterránea.','en'=>'Answers about ROMVILL area reports: what we analyse, where the data comes from, our independence, turnaround times, pricing and the Mediterranean Coast areas we cover.','fr'=>'Réponses sur les rapports de zone de ROMVILL : ce que nous analysons, l\'origine des données, notre indépendance, les délais, les tarifs et les zones de la Côte Méditerranéenne.','de'=>'Antworten zu den Gebietsberichten von ROMVILL: was wir analysieren, woher die Daten stammen, unsere Unabhängigkeit, Fristen, Preise und die Gebiete an der Mittelmeerküste.','ru'=>'Ответы о зональных отчётах ROMVILL: что мы анализируем, откуда данные, наша независимость, сроки, цены и районы Средиземноморского побережья.' ],

        'faq.hero.kicker'  => [ 'es'=>'Antes de decidir','en'=>'Before you decide','fr'=>'Avant de décider','de'=>'Bevor Sie entscheiden','ru'=>'Прежде чем решить' ],
        'faq.hero.title'   => [ 'es'=>'Preguntas frecuentes','en'=>'Frequently asked questions','fr'=>'Questions fréquentes','de'=>'Häufige Fragen','ru'=>'Частые вопросы' ],
        'faq.hero.sub'     => [ 'es'=>'Todo lo que conviene saber sobre cómo trabajamos, qué recibe y por qué puede confiar en un análisis independiente.','en'=>'Everything worth knowing about how we work, what you receive and why you can trust an independent analysis.','fr'=>'Tout ce qu\'il faut savoir sur notre façon de travailler, ce que vous recevez et pourquoi vous pouvez faire confiance à une analyse indépendante.','de'=>'Alles Wissenswerte darüber, wie wir arbeiten, was Sie erhalten und warum Sie einer unabhängigen Analyse vertrauen können.','ru'=>'Всё, что стоит знать о том, как мы работаем, что вы получаете и почему можно доверять независимому анализу.' ],
        'faq.search.ph'    => [ 'es'=>'Busca tu pregunta…','en'=>'Search your question…','fr'=>'Cherchez votre question…','de'=>'Suchen Sie Ihre Frage…','ru'=>'Найдите свой вопрос…' ],
        'faq.permalink'    => [ 'es'=>'Enlace a esta pregunta','en'=>'Link to this question','fr'=>'Lien vers cette question','de'=>'Link zu dieser Frage','ru'=>'Ссылка на этот вопрос' ],
        'faq.noresult'     => [ 'es'=>'No encontramos ninguna pregunta con esas palabras. Prueba con otro término o <a href="https://romvill.com/contacto/">escríbenos directamente</a>.','en'=>'We found no question matching those words. Try another term or <a href="https://romvill.com/contacto/">write to us directly</a>.','fr'=>'Aucune question ne correspond à ces mots. Essayez un autre terme ou <a href="https://romvill.com/contacto/">écrivez-nous directement</a>.','de'=>'Keine Frage passt zu diesen Wörtern. Versuchen Sie einen anderen Begriff oder <a href="https://romvill.com/contacto/">schreiben Sie uns direkt</a>.','ru'=>'Не нашли вопрос по этим словам. Попробуйте другой запрос или <a href="https://romvill.com/contacto/">напишите нам напрямую</a>.' ],
        'faq.cta.title'    => [ 'es'=>'¿Le queda alguna duda por resolver?','en'=>'Still have a question?','fr'=>'Une question sans réponse ?','de'=>'Bleibt eine Frage offen?','ru'=>'Остался вопрос?' ],
        'faq.cta.p'        => [ 'es'=>'Cuéntenos qué zona le interesa y reciba un análisis independiente, sin compromiso.','en'=>'Tell us which area interests you and receive an independent analysis, with no commitment.','fr'=>'Dites-nous quelle zone vous intéresse et recevez une analyse indépendante, sans engagement.','de'=>'Sagen Sie uns, welches Gebiet Sie interessiert, und erhalten Sie eine unabhängige Analyse – unverbindlich.','ru'=>'Скажите, какой район вас интересует, и получите независимый анализ без обязательств.' ],

        'faq.cat.antes'    => [ 'es'=>'Antes de comprar o invertir','en'=>'Before buying or investing','fr'=>'Avant d\'acheter ou d\'investir','de'=>'Vor dem Kauf oder der Investition','ru'=>'Перед покупкой или инвестицией' ],
        'faq.cat.hacemos'  => [ 'es'=>'Qué hacemos','en'=>'What we do','fr'=>'Ce que nous faisons','de'=>'Was wir tun','ru'=>'Что мы делаем' ],
        'faq.cat.rigor'    => [ 'es'=>'Independencia y rigor','en'=>'Independence and rigour','fr'=>'Indépendance et rigueur','de'=>'Unabhängigkeit und Sorgfalt','ru'=>'Независимость и строгость' ],
        'faq.cat.alcance'  => [ 'es'=>'Alcance y contratación','en'=>'Scope and engagement','fr'=>'Portée et prestation','de'=>'Umfang und Beauftragung','ru'=>'Объём и оформление' ],

        'faq.q.que-comprobar' => [ 'es'=>'¿Qué debería comprobar antes de comprar una vivienda en la Costa Mediterránea?','en'=>'What should I check before buying a home on the Mediterranean Coast?','fr'=>'Que faut-il vérifier avant d\'acheter un logement sur la Côte Méditerranéenne ?','de'=>'Was sollte ich vor dem Kauf einer Immobilie an der Mittelmeerküste prüfen?','ru'=>'Что проверить перед покупкой жилья на Средиземноморском побережье?' ],
        'faq.a.que-comprobar' => [ 'es'=>'Más allá de la vivienda en sí, conviene mirar el <b>entorno</b>: seguridad y convivencia, servicios y sanidad cercanos, movilidad y accesos, perfil de la población y qué obras o proyectos oficiales están previstos. Es justamente lo que reunimos en un <a href="https://romvill.com/analisis/">análisis de zona</a>, con datos de fuentes oficiales y verificación sobre el terreno, para que no decida solo por lo que se ve en una visita.','en'=>'Beyond the property itself, it pays to look at the <b>surroundings</b>: safety and community, nearby services and healthcare, mobility and access, the population profile and which official works or projects are planned. That is exactly what we gather in an <a href="https://romvill.com/analisis/">area analysis</a>, using official sources and on-site verification, so you don\'t decide on a single visit alone.','fr'=>'Au-delà du logement lui-même, il faut regarder l\'<b>environnement</b> : sécurité et vie de quartier, services et santé à proximité, mobilité et accès, profil de la population et quels travaux ou projets officiels sont prévus. C\'est précisément ce que nous réunissons dans une <a href="https://romvill.com/analisis/">analyse de zone</a>, à partir de sources officielles et d\'une vérification sur le terrain, pour ne pas décider sur une seule visite.','de'=>'Über die Immobilie selbst hinaus lohnt der Blick auf das <b>Umfeld</b>: Sicherheit und Nachbarschaft, Dienstleistungen und Gesundheitsversorgung, Mobilität und Anbindung, das Bevölkerungsprofil und welche offiziellen Bau- oder Planungsvorhaben vorgesehen sind. Genau das bündeln wir in einer <a href="https://romvill.com/analisis/">Gebietsanalyse</a> – mit offiziellen Quellen und Prüfung vor Ort, damit Sie nicht nur nach einem Besuch entscheiden.','ru'=>'Помимо самого жилья, стоит изучить <b>окружение</b>: безопасность и соседство, услуги и медицину рядом, транспорт и доступность, состав населения и какие официальные работы или проекты запланированы. Именно это мы собираем в <a href="https://romvill.com/analisis/">анализе района</a> — по официальным источникам и с проверкой на месте, чтобы решение не строилось на одном визите.' ],

        'faq.q.zona-que-no-conozco' => [ 'es'=>'¿Cómo sé si una zona que no conozco es adecuada para mí?','en'=>'How do I know if an area I don\'t know is right for me?','fr'=>'Comment savoir si une zone que je ne connais pas me convient ?','de'=>'Woher weiß ich, ob ein mir unbekanntes Gebiet zu mir passt?','ru'=>'Как понять, подходит ли мне незнакомый район?' ],
        'faq.a.zona-que-no-conozco' => [ 'es'=>'Con información <b>ordenada y comprobable</b>, no con impresiones de una tarde. Le entregamos el contexto real de la zona —lo que hay hoy y lo que está previsto oficialmente— para que lo contraste con lo que usted necesita. <a href="https://romvill.com/contacto/">Cuéntenos qué zona le interesa</a> y lo preparamos.','en'=>'With <b>structured, verifiable information</b>, not with the impressions of one afternoon. We give you the real context of the area —what exists today and what is officially planned— so you can weigh it against what you need. <a href="https://romvill.com/contacto/">Tell us which area interests you</a> and we\'ll prepare it.','fr'=>'Avec une information <b>ordonnée et vérifiable</b>, pas avec les impressions d\'un après-midi. Nous vous livrons le contexte réel de la zone —ce qui existe aujourd\'hui et ce qui est officiellement prévu— pour le confronter à vos besoins. <a href="https://romvill.com/contacto/">Dites-nous quelle zone vous intéresse</a> et nous la préparons.','de'=>'Mit <b>geordneten, überprüfbaren Informationen</b>, nicht mit den Eindrücken eines Nachmittags. Wir liefern Ihnen den realen Kontext des Gebiets —was heute vorhanden und was offiziell geplant ist—, damit Sie ihn mit Ihren Bedürfnissen abgleichen. <a href="https://romvill.com/contacto/">Sagen Sie uns, welches Gebiet Sie interessiert</a>, und wir bereiten es auf.','ru'=>'С помощью <b>упорядоченной и проверяемой информации</b>, а не впечатлений одного вечера. Мы даём реальный контекст района — что есть сегодня и что официально запланировано, — чтобы вы сопоставили это со своими задачами. <a href="https://romvill.com/contacto/">Скажите, какой район вас интересует</a>, и мы его подготовим.' ],

        'faq.q.para-que-sirve' => [ 'es'=>'¿El informe sirve para vivir, invertir o alquiler turístico?','en'=>'Is the report useful for living, investing or holiday rentals?','fr'=>'Le rapport sert-il pour habiter, investir ou la location saisonnière ?','de'=>'Ist der Bericht zum Wohnen, Investieren oder für Ferienvermietung geeignet?','ru'=>'Отчёт подходит для проживания, инвестиций или туристической аренды?' ],
        'faq.a.para-que-sirve' => [ 'es'=>'Para los tres. El mismo rigor sirve si busca <b>dónde vivir</b>, <b>dónde invertir</b> o valorar una zona para <b>alquiler</b>; lo que cambia es el enfoque de lo que destacamos. Le mostramos el contexto real —sin prometer rentabilidad— para que decida usted. Vea los dos perfiles en <a href="https://romvill.com/sectores/">Sectores</a>.','en'=>'For all three. The same rigour applies whether you are looking for <b>where to live</b>, <b>where to invest</b> or assessing an area for <b>rental</b>; only the emphasis changes. We show you the real context —without promising returns— so you decide. See both profiles in <a href="https://romvill.com/sectores/">Sectors</a>.','fr'=>'Pour les trois. La même rigueur s\'applique que vous cherchiez <b>où vivre</b>, <b>où investir</b> ou évaluer une zone pour la <b>location</b> ; seul l\'accent change. Nous montrons le contexte réel —sans promettre de rentabilité— pour que vous décidiez. Voir les deux profils dans <a href="https://romvill.com/sectores/">Secteurs</a>.','de'=>'Für alle drei. Dieselbe Sorgfalt gilt, ob Sie einen <b>Wohnort</b> suchen, <b>investieren</b> möchten oder ein Gebiet für die <b>Vermietung</b> bewerten; nur der Schwerpunkt ändert sich. Wir zeigen den realen Kontext —ohne Rendite zu versprechen—, damit Sie entscheiden. Beide Profile unter <a href="https://romvill.com/sectores/">Sektoren</a>.','ru'=>'Для всех трёх. Та же строгость подходит, ищете ли вы, <b>где жить</b>, <b>где инвестировать</b> или оцениваете район под <b>аренду</b>; меняется лишь акцент. Мы показываем реальный контекст — не обещая доходности, — чтобы решали вы. Оба профиля см. в разделе <a href="https://romvill.com/sectores/">Секторы</a>.' ],

        'faq.q.que-es' => [ 'es'=>'¿Qué es exactamente un informe de ROMVILL?','en'=>'What exactly is a ROMVILL report?','fr'=>'Qu\'est-ce qu\'un rapport ROMVILL exactement ?','de'=>'Was genau ist ein ROMVILL-Bericht?','ru'=>'Что именно представляет собой отчёт ROMVILL?' ],
        'faq.a.que-es' => [ 'es'=>'Un análisis de inteligencia territorial de la zona que le interesa: <b>seguridad, demografía, sanidad, movilidad, servicios y planificación urbanística oficial</b>. Reunimos y cruzamos la información y se la entregamos en un <b>informe ordenado y comprensible</b>, sin tecnicismos. Puede ver <a href="https://romvill.com/analisis/">todas las dimensiones que analizamos aquí</a>.','en'=>'A territorial intelligence analysis of the area you care about: <b>safety, demographics, healthcare, mobility, services and official urban planning</b>. We gather and cross-check the information and deliver it as a <b>structured, easy-to-read report</b>, free of jargon. You can see <a href="https://romvill.com/analisis/">all the dimensions we analyse here</a>.','fr'=>'Une analyse d\'intelligence territoriale de la zone qui vous intéresse : <b>sécurité, démographie, santé, mobilité, services et urbanisme officiel</b>. Nous réunissons et croisons l\'information et vous la livrons dans un <b>rapport clair et structuré</b>, sans jargon. Vous pouvez voir <a href="https://romvill.com/analisis/">toutes les dimensions que nous analysons ici</a>.','de'=>'Eine territoriale Standortanalyse des Gebiets, das Sie interessiert: <b>Sicherheit, Demografie, Gesundheit, Mobilität, Dienstleistungen und offizielle Stadtplanung</b>. Wir sammeln und verknüpfen die Informationen und liefern sie als <b>geordneten, verständlichen Bericht</b> ohne Fachchinesisch. <a href="https://romvill.com/analisis/">Alle Dimensionen, die wir analysieren, sehen Sie hier</a>.','ru'=>'Анализ территориальной аналитики интересующего вас района: <b>безопасность, демография, здравоохранение, транспорт, услуги и официальное градостроительство</b>. Мы собираем и сверяем информацию и передаём её в виде <b>упорядоченного, понятного отчёта</b> без жаргона. <a href="https://romvill.com/analisis/">Все анализируемые нами измерения — здесь</a>.' ],

        'faq.q.vivienda-o-zona' => [ 'es'=>'¿Analizáis una vivienda concreta o solo la zona?','en'=>'Do you analyse a specific property or just the area?','fr'=>'Analysez-vous un bien précis ou seulement la zone ?','de'=>'Analysieren Sie eine konkrete Immobilie oder nur das Gebiet?','ru'=>'Вы анализируете конкретный объект или только район?' ],
        'faq.a.vivienda-o-zona' => [ 'es'=>'Nuestro trabajo es el <b>entorno</b>: la zona y todo lo que la rodea. En el nivel <b>Premium</b> añadimos además el <b>análisis de una propiedad concreta</b> dentro de ese contexto. Puede ver qué incluye cada nivel en <a href="https://romvill.com/precios/">Precios</a>.','en'=>'Our work is the <b>surroundings</b>: the area and everything around it. In the <b>Premium</b> level we also add the <b>analysis of a specific property</b> within that context. You can see what each level includes in <a href="https://romvill.com/precios/">Pricing</a>.','fr'=>'Notre travail, c\'est l\'<b>environnement</b> : la zone et tout ce qui l\'entoure. Au niveau <b>Premium</b>, nous ajoutons l\'<b>analyse d\'un bien précis</b> dans ce contexte. Vous pouvez voir ce que chaque niveau inclut dans <a href="https://romvill.com/precios/">Tarifs</a>.','de'=>'Unsere Arbeit ist das <b>Umfeld</b>: das Gebiet und alles darum herum. In der Stufe <b>Premium</b> ergänzen wir zusätzlich die <b>Analyse einer konkreten Immobilie</b> in diesem Kontext. Was jede Stufe enthält, sehen Sie unter <a href="https://romvill.com/precios/">Preise</a>.','ru'=>'Наша работа — это <b>окружение</b>: район и всё вокруг него. На уровне <b>«Премиум»</b> мы дополнительно добавляем <b>анализ конкретного объекта</b> в этом контексте. Что входит в каждый уровень, смотрите в разделе <a href="https://romvill.com/precios/">Цены</a>.' ],

        'faq.q.de-donde-datos' => [ 'es'=>'¿De dónde salen los datos?','en'=>'Where does the data come from?','fr'=>'D\'où viennent les données ?','de'=>'Woher stammen die Daten?','ru'=>'Откуда берутся данные?' ],
        'faq.a.de-donde-datos' => [ 'es'=>'De <b>fuentes oficiales y registros públicos</b> —por ejemplo Policía y Guardia Civil o la planificación urbanística oficial—, que <b>cruzamos entre sí</b> y contrastamos con <b>verificación sobre el terreno</b>. Eliminamos el "me han dicho" y el "parece que": cada dato es comprobable. Así lo explicamos en <a href="https://romvill.com/metodologia/">nuestra metodología</a>.','en'=>'From <b>official sources and public records</b> —such as the Police and Guardia Civil or official urban planning—, which we <b>cross-check against each other</b> and confirm with <b>on-site verification</b>. We remove hearsay and guesswork: every figure is verifiable. We explain it in <a href="https://romvill.com/metodologia/">our methodology</a>.','fr'=>'De <b>sources officielles et registres publics</b> —par exemple la Police et la Guardia Civil ou l\'urbanisme officiel—, que nous <b>croisons entre elles</b> et confirmons par une <b>vérification sur le terrain</b>. Nous éliminons le "on m\'a dit" et le "il paraît que" : chaque donnée est vérifiable. Nous l\'expliquons dans <a href="https://romvill.com/metodologia/">notre méthodologie</a>.','de'=>'Aus <b>offiziellen Quellen und öffentlichen Registern</b> —etwa Polizei und Guardia Civil oder der offiziellen Stadtplanung—, die wir <b>miteinander abgleichen</b> und mit <b>Prüfung vor Ort</b> bestätigen. Wir lassen Hörensagen und Vermutungen weg: jede Angabe ist überprüfbar. Wir erklären es in <a href="https://romvill.com/metodologia/">unserer Methodik</a>.','ru'=>'Из <b>официальных источников и публичных реестров</b> — например, полиции и Guardia Civil или официального градостроительства, — которые мы <b>сверяем между собой</b> и подтверждаем <b>проверкой на месте</b>. Мы убираем слухи и догадки: каждый факт проверяем. Подробнее в <a href="https://romvill.com/metodologia/">нашей методологии</a>.' ],

        'faq.q.que-recibo' => [ 'es'=>'¿Qué recibo y en qué formato?','en'=>'What do I receive and in what format?','fr'=>'Que reçois-je et sous quel format ?','de'=>'Was erhalte ich und in welchem Format?','ru'=>'Что я получаю и в каком формате?' ],
        'faq.a.que-recibo' => [ 'es'=>'Un <b>dossier estructurado, claro y sin tecnicismos</b> con todo lo relevante de la zona, elaborado a medida según sus necesidades y <b>con cada dato citado a su fuente</b>. Según el <a href="https://romvill.com/precios/">nivel que elija</a>, incluye además versión web interactiva y, en Premium, el informe en dos idiomas y acompañamiento de un analista. <a href="https://romvill.com/muestra-de-informe/">Vea aquí una muestra real del informe</a>.','en'=>'A <b>structured, clear, jargon-free dossier</b> with everything relevant about the area, tailored to your needs and <b>with every figure cited to its source</b>. Depending on the <a href="https://romvill.com/precios/">level you choose</a>, it also includes an interactive web version and, in Premium, the report in two languages and support from an analyst. <a href="https://romvill.com/muestra-de-informe/">See a real sample of the report here</a>.','fr'=>'Un <b>dossier structuré, clair et sans jargon</b> avec tout ce qui compte sur la zone, élaboré sur mesure selon vos besoins et <b>avec chaque donnée citée à sa source</b>. Selon le <a href="https://romvill.com/precios/">niveau choisi</a>, il inclut aussi une version web interactive et, en Premium, le rapport en deux langues et l\'accompagnement d\'un analyste. <a href="https://romvill.com/muestra-de-informe/">Voyez ici un exemple réel du rapport</a>.','de'=>'Ein <b>strukturiertes, klares Dossier ohne Fachjargon</b> mit allem Relevanten zum Gebiet, maßgeschneidert nach Ihren Bedürfnissen und <b>mit Quellenangabe zu jeder Angabe</b>. Je nach <a href="https://romvill.com/precios/">gewählter Stufe</a> zusätzlich eine interaktive Web-Version und in Premium der Bericht in zwei Sprachen sowie die Begleitung durch einen Analysten. <a href="https://romvill.com/muestra-de-informe/">Sehen Sie hier ein echtes Muster des Berichts</a>.','ru'=>'<b>Структурированное, понятное досье без жаргона</b> со всем важным о районе, составленное под ваши задачи и <b>со ссылкой на источник у каждого факта</b>. В зависимости от <a href="https://romvill.com/precios/">выбранного уровня</a> также интерактивная веб-версия и, на уровне «Премиум», отчёт на двух языках и сопровождение аналитика. <a href="https://romvill.com/muestra-de-informe/">Посмотрите здесь реальный образец отчёта</a>.' ],

        'faq.q.cuanto-tarda' => [ 'es'=>'¿Cuánto tarda?','en'=>'How long does it take?','fr'=>'Combien de temps cela prend-il ?','de'=>'Wie lange dauert es?','ru'=>'Сколько это занимает времени?' ],
        'faq.a.cuanto-tarda' => [ 'es'=>'Según el nivel: <b>Esencial en 3-4 días</b>, <b>Superior en 5-7 días</b> y <b>Premium en 7-14 días</b>. Le confirmamos el plazo al encargar el informe.','en'=>'Depending on the level: <b>Essential in 3-4 days</b>, <b>Superior in 5-7 days</b> and <b>Premium in 7-14 days</b>. We confirm the timeframe when you order the report.','fr'=>'Selon le niveau : <b>Essentiel en 3-4 jours</b>, <b>Supérieur en 5-7 jours</b> et <b>Premium en 7-14 jours</b>. Nous confirmons le délai à la commande du rapport.','de'=>'Je nach Stufe: <b>Essential in 3-4 Tagen</b>, <b>Superior in 5-7 Tagen</b> und <b>Premium in 7-14 Tagen</b>. Die Frist bestätigen wir bei der Beauftragung.','ru'=>'В зависимости от уровня: <b>«Основной» — 3-4 дня</b>, <b>«Супериор» — 5-7 дней</b> и <b>«Премиум» — 7-14 дней</b>. Срок подтверждаем при заказе отчёта.' ],

        'faq.q.independientes' => [ 'es'=>'¿Sois realmente independientes?','en'=>'Are you really independent?','fr'=>'Êtes-vous vraiment indépendants ?','de'=>'Sind Sie wirklich unabhängig?','ru'=>'Вы действительно независимы?' ],
        'faq.a.independientes' => [ 'es'=>'Sí. <b>No vendemos inmuebles ni cobramos comisiones</b> de agencias ni promotores, y <b>no tenemos intereses en la zona</b>. Nuestro único trabajo es analizar; por eso lo que le contamos no está orientado a venderle nada. Puede conocernos en <a href="https://romvill.com/quienes-somos/">Quiénes somos</a>.','en'=>'Yes. <b>We don\'t sell property or take commissions</b> from agencies or developers, and <b>we have no interests in the area</b>. Our only job is to analyse; that\'s why what we tell you is not geared to selling you anything. Get to know us in <a href="https://romvill.com/quienes-somos/">About us</a>.','fr'=>'Oui. <b>Nous ne vendons pas de biens et ne percevons aucune commission</b> d\'agences ou de promoteurs, et <b>nous n\'avons aucun intérêt dans la zone</b>. Notre seul métier est d\'analyser ; ce que nous vous disons ne vise donc pas à vous vendre quoi que ce soit. Découvrez-nous dans <a href="https://romvill.com/quienes-somos/">Qui sommes-nous</a>.','de'=>'Ja. <b>Wir verkaufen keine Immobilien und erhalten keine Provisionen</b> von Agenturen oder Bauträgern, und <b>wir haben keine Interessen im Gebiet</b>. Unsere einzige Aufgabe ist die Analyse; daher zielt das, was wir Ihnen sagen, nicht darauf ab, Ihnen etwas zu verkaufen. Lernen Sie uns unter <a href="https://romvill.com/quienes-somos/">Über uns</a> kennen.','ru'=>'Да. <b>Мы не продаём недвижимость и не берём комиссий</b> у агентств или застройщиков, и <b>у нас нет интересов в районе</b>. Наша единственная работа — анализировать; поэтому то, что мы сообщаем, не нацелено что-либо вам продать. Познакомьтесь с нами в разделе <a href="https://romvill.com/quienes-somos/">О нас</a>.' ],

        'faq.q.no-me-fio-inmobiliaria' => [ 'es'=>'¿Por qué no me fío solo de lo que me diga la agencia inmobiliaria?','en'=>'Why not just rely on what the estate agency tells me?','fr'=>'Pourquoi ne pas me fier uniquement à l\'agence immobilière ?','de'=>'Warum sollte ich mich nicht allein auf die Immobilienagentur verlassen?','ru'=>'Почему не полагаться только на слова агентства недвижимости?' ],
        'faq.a.no-me-fio-inmobiliaria' => [ 'es'=>'La agencia hace su trabajo: <b>vender la vivienda</b>. Nosotros hacemos otro distinto y complementario: <b>analizar el entorno sin nada que venderle</b>. No sustituimos a la inmobiliaria; le damos una <b>segunda mirada independiente</b> sobre la zona para que firme con la información completa, no solo con la del vendedor.','en'=>'The agency does its job: <b>selling the property</b>. We do a different, complementary one: <b>analysing the surroundings with nothing to sell you</b>. We don\'t replace the agency; we give you an <b>independent second opinion</b> on the area so you sign with the full picture, not only the seller\'s.','fr'=>'L\'agence fait son travail : <b>vendre le bien</b>. Nous en faisons un autre, complémentaire : <b>analyser l\'environnement sans rien à vous vendre</b>. Nous ne remplaçons pas l\'agence ; nous vous offrons un <b>second regard indépendant</b> sur la zone pour signer avec toute l\'information, pas seulement celle du vendeur.','de'=>'Die Agentur macht ihre Arbeit: <b>die Immobilie verkaufen</b>. Wir machen eine andere, ergänzende: <b>das Umfeld analysieren, ohne Ihnen etwas verkaufen zu wollen</b>. Wir ersetzen die Agentur nicht; wir geben Ihnen eine <b>unabhängige zweite Sicht</b> auf das Gebiet, damit Sie mit vollständiger Information unterschreiben, nicht nur mit der des Verkäufers.','ru'=>'Агентство делает свою работу: <b>продаёт жильё</b>. Мы делаем другую, дополняющую: <b>анализируем окружение, ничего вам не продавая</b>. Мы не заменяем агентство; мы даём <b>независимый второй взгляд</b> на район, чтобы вы подписывали договор с полной картиной, а не только со слов продавца.' ],

        'faq.q.buena-o-mala' => [ 'es'=>'¿Me decís si una zona es buena o mala?','en'=>'Will you tell me whether an area is good or bad?','fr'=>'Me direz-vous si une zone est bonne ou mauvaise ?','de'=>'Sagen Sie mir, ob ein Gebiet gut oder schlecht ist?','ru'=>'Вы скажете, хороший район или плохой?' ],
        'faq.a.buena-o-mala' => [ 'es'=>'No. <b>Describimos el contexto real con datos objetivos de fuentes oficiales, sin clasificar la zona por peligrosidad ni emitir juicios.</b> Le damos información fiable y ordenada; la decisión es suya. Nuestro papel es que decida con criterio, no decidir por usted.','en'=>'No. <b>We describe the real context with objective data from official sources, without rating the area by danger or passing judgement.</b> We give you reliable, organised information; the decision is yours. Our role is to help you decide with sound judgement, not to decide for you.','fr'=>'Non. <b>Nous décrivons le contexte réel avec des données objectives de sources officielles, sans classer la zone par dangerosité ni porter de jugement.</b> Nous vous donnons une information fiable et ordonnée ; la décision vous appartient. Notre rôle est de vous aider à décider avec discernement, pas de décider à votre place.','de'=>'Nein. <b>Wir beschreiben den realen Kontext mit objektiven Daten aus offiziellen Quellen, ohne das Gebiet nach Gefährlichkeit einzustufen oder zu urteilen.</b> Wir geben Ihnen verlässliche, geordnete Informationen; die Entscheidung liegt bei Ihnen. Unsere Aufgabe ist, dass Sie fundiert entscheiden, nicht für Sie zu entscheiden.','ru'=>'Нет. <b>Мы описываем реальный контекст объективными данными из официальных источников, не классифицируя район по опасности и не вынося оценок.</b> Мы даём надёжную, упорядоченную информацию; решение за вами. Наша роль — помочь вам решить обоснованно, а не решать за вас.' ],

        'faq.q.revalorizacion' => [ 'es'=>'¿Prometéis que una zona se revalorizará?','en'=>'Do you promise an area will increase in value?','fr'=>'Promettez-vous qu\'une zone prendra de la valeur ?','de'=>'Versprechen Sie, dass ein Gebiet an Wert gewinnt?','ru'=>'Вы обещаете, что район подорожает?' ],
        'faq.a.revalorizacion' => [ 'es'=>'No. Reunimos los <b>proyectos e infraestructuras recogidos en la planificación pública oficial</b> (obras, equipamientos, urbanismo), pero <b>no hacemos proyecciones de revalorización</b> ni promesas de rentabilidad futura. Le mostramos lo que está previsto oficialmente; interpretar su impacto es decisión suya.','en'=>'No. We compile the <b>projects and infrastructure set out in official public planning</b> (works, facilities, urban development), but <b>we make no forecasts of future property values</b> or promises of future returns. We show you what is officially planned; interpreting its impact is your decision.','fr'=>'Non. Nous réunissons les <b>projets et infrastructures prévus dans la planification publique officielle</b> (travaux, équipements, urbanisme), mais <b>nous ne faisons aucune projection de valorisation</b> ni promesse de rentabilité future. Nous montrons ce qui est officiellement prévu ; en interpréter l\'impact est votre décision.','de'=>'Nein. Wir bündeln die <b>in der offiziellen öffentlichen Planung vorgesehenen Projekte und Infrastrukturen</b> (Bauvorhaben, Einrichtungen, Stadtentwicklung), aber <b>wir erstellen keine Wertsteigerungsprognosen</b> und versprechen keine künftige Rendite. Wir zeigen, was offiziell geplant ist; die Deutung der Auswirkung ist Ihre Entscheidung.','ru'=>'Нет. Мы собираем <b>проекты и инфраструктуру, заложенные в официальном публичном планировании</b> (работы, объекты, градостроительство), но <b>не делаем прогнозов удорожания</b> и не обещаем будущей доходности. Мы показываем то, что официально запланировано; трактовать влияние — ваше решение.' ],

        'faq.q.confidencial' => [ 'es'=>'¿Es confidencial?','en'=>'Is it confidential?','fr'=>'Est-ce confidentiel ?','de'=>'Ist es vertraulich?','ru'=>'Это конфиденциально?' ],
        'faq.a.confidencial' => [ 'es'=>'<b>Confidencialidad absoluta.</b> Sus datos no se comparten con terceros y su consulta queda entre usted y nosotros. Forma parte de nuestro oficio.','en'=>'<b>Absolute confidentiality.</b> Your data is not shared with third parties and your enquiry stays between you and us. It is part of our craft.','fr'=>'<b>Confidentialité absolue.</b> Vos données ne sont pas partagées avec des tiers et votre demande reste entre vous et nous. Cela fait partie de notre métier.','de'=>'<b>Absolute Vertraulichkeit.</b> Ihre Daten werden nicht an Dritte weitergegeben, und Ihre Anfrage bleibt zwischen Ihnen und uns. Das gehört zu unserem Handwerk.','ru'=>'<b>Абсолютная конфиденциальность.</b> Ваши данные не передаются третьим лицам, и ваш запрос остаётся между вами и нами. Это часть нашего ремесла.' ],

        'faq.q.actualizacion-datos' => [ 'es'=>'¿Cada cuánto actualizáis los datos de una zona?','en'=>'How often do you update an area\'s data?','fr'=>'À quelle fréquence mettez-vous à jour les données d\'une zone ?','de'=>'Wie oft aktualisieren Sie die Daten eines Gebiets?','ru'=>'Как часто вы обновляете данные по району?' ],
        'faq.a.actualizacion-datos' => [ 'es'=>'Cada informe se elabora con datos <b>vigentes en el momento de encargarlo</b>: no reutilizamos estudios antiguos. Para cada encargo recopilamos y cruzamos de nuevo la información de fuentes oficiales. Así trabajamos, paso a paso, en <a href="https://romvill.com/metodologia/">Metodología</a>.','en'=>'Each report is built with data <b>current at the time you order it</b>: we don\'t reuse old studies. For every commission we gather and cross-check the information from official sources again. That\'s how we work, step by step, in <a href="https://romvill.com/metodologia/">Methodology</a>.','fr'=>'Chaque rapport est réalisé avec des données <b>à jour au moment de la commande</b> : nous ne réutilisons pas d\'anciennes études. Pour chaque commande, nous réunissons et recroisons l\'information de sources officielles. Voilà comment nous travaillons, étape par étape, dans <a href="https://romvill.com/metodologia/">Méthodologie</a>.','de'=>'Jeder Bericht entsteht mit Daten, die <b>zum Zeitpunkt der Beauftragung aktuell</b> sind: Wir verwenden keine alten Studien wieder. Für jeden Auftrag sammeln und verknüpfen wir die Informationen aus offiziellen Quellen erneut. So arbeiten wir, Schritt für Schritt, unter <a href="https://romvill.com/metodologia/">Methodik</a>.','ru'=>'Каждый отчёт составляется по данным, <b>актуальным на момент заказа</b>: мы не переиспользуем старые исследования. Для каждого заказа мы заново собираем и сверяем информацию из официальных источников. Так мы работаем, шаг за шагом, в разделе <a href="https://romvill.com/metodologia/">Методология</a>.' ],

        'faq.q.diferencia-tasacion' => [ 'es'=>'¿En qué se diferencia esto de una tasación o de lo que me cuenta el vendedor?','en'=>'How is this different from a valuation or what the seller tells me?','fr'=>'En quoi est-ce différent d\'une expertise ou de ce que dit le vendeur ?','de'=>'Worin unterscheidet sich das von einer Wertermittlung oder den Angaben des Verkäufers?','ru'=>'Чем это отличается от оценки или слов продавца?' ],
        'faq.a.diferencia-tasacion' => [ 'es'=>'Una tasación pone <b>precio a un inmueble</b>; el vendedor <b>quiere cerrar la venta</b>. Nosotros no hacemos ni lo uno ni lo otro: analizamos el <b>entorno</b> de forma <b>independiente y sin nada que venderle</b>, con fuentes oficiales. Es una información distinta y complementaria a las dos. Puede conocernos en <a href="https://romvill.com/quienes-somos/">Quiénes somos</a>.','en'=>'A valuation puts a <b>price on a property</b>; the seller <b>wants to close the sale</b>. We do neither: we analyse the <b>surroundings</b> in an <b>independent way, with nothing to sell you</b>, using official sources. It is information distinct from and complementary to both. Get to know us in <a href="https://romvill.com/quienes-somos/">About us</a>.','fr'=>'Une expertise met un <b>prix sur un bien</b> ; le vendeur <b>veut conclure la vente</b>. Nous ne faisons ni l\'un ni l\'autre : nous analysons l\'<b>environnement</b> de façon <b>indépendante et sans rien à vous vendre</b>, avec des sources officielles. C\'est une information distincte et complémentaire des deux. Découvrez-nous dans <a href="https://romvill.com/quienes-somos/">Qui sommes-nous</a>.','de'=>'Eine Wertermittlung setzt einen <b>Preis für eine Immobilie</b>; der Verkäufer <b>will den Verkauf abschließen</b>. Wir tun weder das eine noch das andere: Wir analysieren das <b>Umfeld</b> auf <b>unabhängige Weise, ohne Ihnen etwas zu verkaufen</b>, mit offiziellen Quellen. Es ist eine eigenständige, zu beiden ergänzende Information. Lernen Sie uns unter <a href="https://romvill.com/quienes-somos/">Über uns</a> kennen.','ru'=>'Оценка ставит <b>цену на объект</b>; продавец <b>хочет закрыть сделку</b>. Мы не делаем ни того, ни другого: мы анализируем <b>окружение</b> <b>независимо и ничего вам не продавая</b>, по официальным источникам. Это иная информация, дополняющая и то, и другое. Познакомьтесь с нами в разделе <a href="https://romvill.com/quienes-somos/">О нас</a>.' ],

        'faq.q.zonas' => [ 'es'=>'¿Sobre qué zonas trabajáis?','en'=>'Which areas do you work in?','fr'=>'Sur quelles zones travaillez-vous ?','de'=>'In welchen Gebieten arbeiten Sie?','ru'=>'С какими районами вы работаете?' ],
        'faq.a.zonas' => [ 'es'=>'Costa Mediterránea: <a href="https://romvill.com/analisis-alicante/">Alicante</a>, <a href="https://romvill.com/analisis-malaga/">Málaga</a> y <a href="https://romvill.com/analisis-marbella/">Marbella</a> y su entorno. De forma excepcional realizamos informes en otras ciudades o en el extranjero bajo <b>presupuesto personalizado</b>.','en'=>'The Mediterranean Coast: <a href="https://romvill.com/analisis-alicante/">Alicante</a>, <a href="https://romvill.com/analisis-malaga/">Málaga</a> and <a href="https://romvill.com/analisis-marbella/">Marbella</a> and their surroundings. On an exceptional basis we produce reports for other cities or abroad under a <b>custom quote</b>.','fr'=>'La Côte Méditerranéenne : <a href="https://romvill.com/analisis-alicante/">Alicante</a>, <a href="https://romvill.com/analisis-malaga/">Málaga</a> et <a href="https://romvill.com/analisis-marbella/">Marbella</a> et leurs environs. À titre exceptionnel, nous réalisons des rapports dans d\'autres villes ou à l\'étranger sur <b>devis personnalisé</b>.','de'=>'Die Mittelmeerküste: <a href="https://romvill.com/analisis-alicante/">Alicante</a>, <a href="https://romvill.com/analisis-malaga/">Málaga</a> und <a href="https://romvill.com/analisis-marbella/">Marbella</a> und ihr Umland. In Ausnahmefällen erstellen wir Berichte für andere Städte oder im Ausland gegen <b>individuelles Angebot</b>.','ru'=>'Средиземноморское побережье: <a href="https://romvill.com/analisis-alicante/">Аликанте</a>, <a href="https://romvill.com/analisis-malaga/">Малага</a> и <a href="https://romvill.com/analisis-marbella/">Марбелья</a> и их окрестности. В порядке исключения делаем отчёты по другим городам или за рубежом по <b>индивидуальному расчёту</b>.' ],

        'faq.q.desde-extranjero' => [ 'es'=>'¿Puedo contratar el informe desde el extranjero?','en'=>'Can I order the report from abroad?','fr'=>'Puis-je commander le rapport depuis l\'étranger ?','de'=>'Kann ich den Bericht aus dem Ausland beauftragen?','ru'=>'Могу ли я заказать отчёт из-за рубежа?' ],
        'faq.a.desde-extranjero' => [ 'es'=>'Sí. Todo el proceso es <b>a distancia</b>: nos dice qué zona le interesa, preparamos el informe y se lo entregamos en formato digital. <b>No necesita desplazarse.</b> Además puede tratar con nosotros en <b>español, inglés, francés, alemán o ruso</b>. <a href="https://romvill.com/contacto/">Escríbanos</a> y le respondemos en 24-48 h laborables.','en'=>'Yes. The whole process is <b>remote</b>: you tell us which area interests you, we prepare the report and deliver it digitally. <b>No need to travel.</b> You can also deal with us in <b>Spanish, English, French, German or Russian</b>. <a href="https://romvill.com/contacto/">Write to us</a> and we reply within 24-48 hours (working days).','fr'=>'Oui. Tout le processus est <b>à distance</b> : vous nous dites quelle zone vous intéresse, nous préparons le rapport et le livrons au format numérique. <b>Aucun déplacement nécessaire.</b> Vous pouvez aussi échanger avec nous en <b>espagnol, anglais, français, allemand ou russe</b>. <a href="https://romvill.com/contacto/">Écrivez-nous</a> et nous répondons sous 24-48 h ouvrées.','de'=>'Ja. Der gesamte Ablauf erfolgt <b>aus der Ferne</b>: Sie sagen uns, welches Gebiet Sie interessiert, wir erstellen den Bericht und liefern ihn digital. <b>Keine Anreise nötig.</b> Sie können mit uns auch auf <b>Spanisch, Englisch, Französisch, Deutsch oder Russisch</b> kommunizieren. <a href="https://romvill.com/contacto/">Schreiben Sie uns</a>, wir antworten innerhalb von 24–48 Stunden an Werktagen.','ru'=>'Да. Весь процесс проходит <b>дистанционно</b>: вы сообщаете, какой район интересует, мы готовим отчёт и передаём его в цифровом виде. <b>Приезжать не нужно.</b> Общаться с нами можно на <b>испанском, английском, французском, немецком или русском</b>. <a href="https://romvill.com/contacto/">Напишите нам</a>, и мы ответим в течение 24-48 рабочих часов.' ],

        'faq.q.empresas-particulares' => [ 'es'=>'¿Hacéis análisis para empresas o solo para particulares?','en'=>'Do you analyse for companies or only for individuals?','fr'=>'Réalisez-vous des analyses pour les entreprises ou seulement pour les particuliers ?','de'=>'Analysieren Sie für Unternehmen oder nur für Privatpersonen?','ru'=>'Вы работаете с компаниями или только с частными лицами?' ],
        'faq.a.empresas-particulares' => [ 'es'=>'Ambos. Trabajamos tanto para <b>particulares</b> que van a comprar, invertir o trasladarse como para <b>empresas e inversores</b> que necesitan conocer el entorno antes de una operación. Puede ver los dos enfoques en <a href="https://romvill.com/sectores/">Sectores</a>.','en'=>'Both. We work for <b>individuals</b> about to buy, invest or relocate as well as for <b>companies and investors</b> who need to understand the environment before a transaction. See both approaches in <a href="https://romvill.com/sectores/">Sectors</a>.','fr'=>'Les deux. Nous travaillons aussi bien pour des <b>particuliers</b> sur le point d\'acheter, d\'investir ou de déménager que pour des <b>entreprises et investisseurs</b> qui doivent connaître l\'environnement avant une opération. Voir les deux approches dans <a href="https://romvill.com/sectores/">Secteurs</a>.','de'=>'Beides. Wir arbeiten sowohl für <b>Privatpersonen</b>, die kaufen, investieren oder umziehen wollen, als auch für <b>Unternehmen und Investoren</b>, die das Umfeld vor einer Transaktion kennen müssen. Beide Ansätze unter <a href="https://romvill.com/sectores/">Sektoren</a>.','ru'=>'И то, и другое. Мы работаем как с <b>частными лицами</b>, которые собираются купить, инвестировать или переехать, так и с <b>компаниями и инвесторами</b>, которым нужно понять окружение перед сделкой. Оба подхода — в разделе <a href="https://romvill.com/sectores/">Секторы</a>.' ],

        'faq.q.cuanto-cuesta' => [ 'es'=>'¿Cuánto cuesta?','en'=>'How much does it cost?','fr'=>'Combien cela coûte-t-il ?','de'=>'Was kostet es?','ru'=>'Сколько это стоит?' ],
        'faq.a.cuanto-cuesta' => [ 'es'=>'Tres niveles claros: <b>Esencial, Superior y Premium</b>, desde 290&nbsp;€ — y ahora con <b>precio de lanzamiento desde 149&nbsp;€</b> para las primeras 5 plazas, a cambio de su reseña. Y si empieza por un nivel y luego quiere más, durante <b>60 días le descontamos íntegramente</b> lo ya pagado: solo abona la diferencia. <a href="https://romvill.com/precios/">Ver precios y niveles</a>.','en'=>'Three clear levels: <b>Essential, Superior and Premium</b>, from €290 — and right now a <b>launch price from €149</b> for the first 5 clients, in exchange for your review. And if you start with one level and later want more, for <b>60 days we fully deduct</b> what you already paid: you only pay the difference. <a href="https://romvill.com/precios/">See pricing and levels</a>.','fr'=>'Trois niveaux clairs : <b>Essentiel, Supérieur et Premium</b>, dès 290&nbsp;€ — et en ce moment un <b>prix de lancement dès 149&nbsp;€</b> pour les 5 premières places, en échange de votre avis. Et si vous commencez par un niveau puis en voulez plus, pendant <b>60 jours nous déduisons intégralement</b> ce que vous avez déjà payé : vous ne réglez que la différence. <a href="https://romvill.com/precios/">Voir tarifs et niveaux</a>.','de'=>'Drei klare Stufen: <b>Essential, Superior und Premium</b>, ab 290&nbsp;€ — und aktuell ein <b>Einführungspreis ab 149&nbsp;€</b> für die ersten 5 Plätze, im Tausch gegen Ihre Bewertung. Und wenn Sie mit einer Stufe beginnen und später mehr möchten, rechnen wir <b>60 Tage lang das bereits Bezahlte vollständig an</b>: Sie zahlen nur die Differenz. <a href="https://romvill.com/precios/">Preise und Stufen ansehen</a>.','ru'=>'Три понятных уровня: <b>«Основной», «Супериор» и «Премиум»</b>, от 290&nbsp;€ — а сейчас действует <b>стартовая цена от 149&nbsp;€</b> для первых 5 мест в обмен на ваш отзыв. А если начнёте с одного уровня и захотите больше, в течение <b>60 дней мы полностью зачтём</b> уже уплаченное: вы доплачиваете только разницу. <a href="https://romvill.com/precios/">Смотреть цены и уровни</a>.' ],

        'faq.q.hablar-antes' => [ 'es'=>'¿Puedo hablar con alguien antes de decidir?','en'=>'Can I speak to someone before deciding?','fr'=>'Puis-je parler à quelqu\'un avant de décider ?','de'=>'Kann ich vor der Entscheidung mit jemandem sprechen?','ru'=>'Могу ли я с кем-то поговорить перед решением?' ],
        'faq.a.hablar-antes' => [ 'es'=>'Sí. <a href="https://romvill.com/contacto/">Escríbanos contándonos su caso</a> y le <b>respondemos en 24-48&nbsp;horas laborables</b>, sin compromiso. Si su situación es distinta a lo habitual, la estudiamos igualmente.','en'=>'Yes. <a href="https://romvill.com/contacto/">Write to us with your case</a> and we <b>reply within 24-48 hours (working days)</b>, with no commitment. If your situation is out of the ordinary, we look into it just the same.','fr'=>'Oui. <a href="https://romvill.com/contacto/">Écrivez-nous en exposant votre cas</a> et nous <b>répondons sous 24-48&nbsp;heures ouvrées</b>, sans engagement. Si votre situation sort de l\'ordinaire, nous l\'étudions tout de même.','de'=>'Ja. <a href="https://romvill.com/contacto/">Schreiben Sie uns Ihren Fall</a>, und wir <b>antworten innerhalb von 24–48 Stunden an Werktagen</b>, unverbindlich. Ist Ihre Situation ungewöhnlich, prüfen wir sie ebenso.','ru'=>'Да. <a href="https://romvill.com/contacto/">Напишите нам о своей ситуации</a>, и мы <b>ответим в течение 24-48 рабочих часов</b>, без обязательств. Если ваш случай нетипичный, мы всё равно его рассмотрим.' ],

