        'mu.enc.chipk' => [ 'es'=>'Sus intereses críticos — marcan el orden del informe','en'=>'Your critical interests — they set the order of the report','fr'=>'Vos intérêts critiques — ils fixent l\'ordre du rapport','de'=>'Ihre kritischen Interessen — sie bestimmen die Reihenfolge des Berichts','ru'=>'Ваши ключевые интересы — они задают порядок отчёта' ],
        'mu.enc.chips' => [ 'es'=>'Tranquilidad y convivencia|Colegios cercanos|Sanidad a menos de 20 min|Cómo es la zona en invierno','en'=>'Peace and community|Schools nearby|Healthcare within 20 min|What the area is like in winter','fr'=>'Tranquillité et vie de quartier|Écoles à proximité|Santé à moins de 20 min|La zone en hiver','de'=>'Ruhe und Nachbarschaft|Schulen in der Nähe|Gesundheitsversorgung unter 20 Min.|Das Gebiet im Winter','ru'=>'Спокойствие и соседство|Школы рядом|Медицина в 20 минутах|Каков район зимой' ],
        'mu.enc.callout' => [ 'es'=>'<b>Cómo lo usamos.</b> Sus prioridades ordenan el informe: las dimensiones que más le importan van primero y se analizan con mayor detalle. No recibirá relleno sobre lo que no le afecta.','en'=>'<b>How we use it.</b> Your priorities order the report: the dimensions that matter most to you come first and are analysed in greater detail. You will get no filler about what does not affect you.','fr'=>'<b>Comment nous l\'utilisons.</b> Vos priorités ordonnent le rapport : les dimensions qui comptent le plus pour vous viennent en premier et sont analysées plus en détail. Aucun remplissage sur ce qui ne vous concerne pas.','de'=>'<b>So nutzen wir es.</b> Ihre Prioritäten ordnen den Bericht: Die Dimensionen, die Ihnen am wichtigsten sind, kommen zuerst und werden detaillierter analysiert. Kein Füllmaterial über Dinge, die Sie nicht betreffen.','ru'=>'<b>Как мы это используем.</b> Ваши приоритеты задают порядок отчёта: самые важные для вас измерения идут первыми и анализируются подробнее. Никакой «воды» о том, что вас не касается.' ],
        'mu.enc.fict' => [ 'es'=>'Cliente, zona y referencia son ficticios, creados únicamente para esta muestra. La referencia sigue el formato real de expediente ROMVILL.','en'=>'Client, area and reference are fictitious, created solely for this sample. The reference follows the real ROMVILL file format.','fr'=>'Client, zone et référence sont fictifs, créés uniquement pour cet exemple. La référence suit le format réel des dossiers ROMVILL.','de'=>'Kunde, Gebiet und Referenz sind fiktiv und nur für dieses Muster erstellt. Die Referenz folgt dem echten ROMVILL-Aktenformat.','ru'=>'Клиент, район и референс вымышлены и созданы только для этого образца. Референс соответствует реальному формату дел ROMVILL.' ],
        'mu.toc.h' => [ 'es'=>'Índice','en'=>'Contents','fr'=>'Sommaire','de'=>'Inhalt','ru'=>'Оглавление' ],
        'mu.toc.items' => [ 'es'=>'Su encargo y alcance|Dashboard resumen y patrones detectados|Seguridad y convivencia|Educación y centros escolares|Sanidad: centros, distancias y tiempos|Entorno y vida en la zona (verano e invierno)|Demografía y composición social|Movilidad y conexiones|Servicios y vida diaria|Clima y entorno natural|Planificación urbanística oficial prevista|Fuentes citadas y nota de vigencia','en'=>'Your brief and scope|Summary dashboard and detected patterns|Safety and community|Education and schools|Healthcare: centres, distances and times|Environment and life in the area (summer and winter)|Demographics and social composition|Mobility and connections|Services and daily life|Climate and natural environment|Official urban planning ahead|Cited sources and validity note','fr'=>'Votre commande et périmètre|Tableau de bord et tendances détectées|Sécurité et vie de quartier|Éducation et écoles|Santé : centres, distances et temps|Environnement et vie dans la zone (été et hiver)|Démographie et composition sociale|Mobilité et connexions|Services et vie quotidienne|Climat et environnement naturel|Urbanisme officiel prévu|Sources citées et note de validité','de'=>'Ihr Auftrag und Umfang|Übersichts-Dashboard und erkannte Muster|Sicherheit und Nachbarschaft|Bildung und Schulen|Gesundheit: Zentren, Entfernungen und Zeiten|Umfeld und Leben im Gebiet (Sommer und Winter)|Demografie und soziale Zusammensetzung|Mobilität und Verbindungen|Dienstleistungen und Alltag|Klima und Naturraum|Geplante offizielle Stadtplanung|Zitierte Quellen und Gültigkeitshinweis','ru'=>'Ваш заказ и объём|Сводная панель и выявленные закономерности|Безопасность и соседство|Образование и школы|Медицина: центры, расстояния и время|Среда и жизнь в районе (лето и зима)|Демография и социальный состав|Транспорт и связи|Услуги и повседневная жизнь|Климат и природная среда|Официальное градостроительное планирование|Источники и срок действия' ],
        'mu.toc.pri' => [ 'es'=>'Prioridad','en'=>'Priority','fr'=>'Priorité','de'=>'Priorität','ru'=>'Приоритет' ],
        'mu.cap.sec'   => [ 'es'=>'03 · Prioridad 1 de su encargo','en'=>'03 · Priority 1 of your brief','fr'=>'03 · Priorité 1 de votre commande','de'=>'03 · Priorität 1 Ihres Auftrags','ru'=>'03 · Приоритет 1 вашего заказа' ],
        'mu.cap.title' => [ 'es'=>'Seguridad y convivencia','en'=>'Safety and community','fr'=>'Sécurité et vie de quartier','de'=>'Sicherheit und Nachbarschaft','ru'=>'Безопасность и соседство' ],
        'mu.cap.sintesis' => [ 'es'=>'Síntesis: la zona presenta un contexto de convivencia estable según los registros oficiales del último trienio, con la estacionalidad propia de la costa.','en'=>'Summary: the area shows a stable community context according to official records for the last three years, with the seasonality typical of the coast.','fr'=>'Synthèse : la zone présente un contexte de vie stable selon les registres officiels des trois dernières années, avec la saisonnalité propre à la côte.','de'=>'Zusammenfassung: Das Gebiet zeigt laut offiziellen Registern der letzten drei Jahre ein stabiles Zusammenleben, mit der küstentypischen Saisonalität.','ru'=>'Резюме: по официальным данным за последние три года район демонстрирует стабильную среду проживания с типичной для побережья сезонностью.' ],
        'mu.cap.th' => [ 'es'=>'Indicador|Zona|Media provincial|Fuente','en'=>'Indicator|Area|Provincial average|Source','fr'=>'Indicateur|Zone|Moyenne provinciale|Source','de'=>'Indikator|Gebiet|Provinzdurchschnitt|Quelle','ru'=>'Показатель|Район|Среднее по провинции|Источник' ],
