        'mu.cap.r4' => [ 'es'=>'Variación estacional observada','en'=>'Observed seasonal variation','fr'=>'Variation saisonnière observée','de'=>'Beobachtete saisonale Schwankung','ru'=>'Наблюдаемая сезонная вариация' ],
