        'mu.cap.f3' => [ 'es'=>'Prensa local contrastada','en'=>'Cross-checked local press','fr'=>'Presse locale recoupée','de'=>'Geprüfte Lokalpresse','ru'=>'Проверенная местная пресса' ],
        'mu.cap.src' => [ 'es'=>'[1] Ministerio del Interior — Balance de criminalidad · [4] Ayuntamiento, memoria anual · [6] Dos medios locales, cruzados. Cifras ocultas por ser una muestra; en su informe aparecen completas y con enlace a la fuente.','en'=>'[1] Ministry of the Interior — Crime statistics · [4] Town hall, annual report · [6] Two local outlets, cross-checked. Figures hidden because this is a sample; in your report they appear in full with a link to the source.','fr'=>'[1] Ministère de l\'Intérieur — Bilan de la criminalité · [4] Mairie, rapport annuel · [6] Deux médias locaux, recoupés. Chiffres masqués car il s\'agit d\'un exemple ; dans votre rapport ils figurent en entier avec lien vers la source.','de'=>'[1] Innenministerium — Kriminalitätsbilanz · [4] Rathaus, Jahresbericht · [6] Zwei Lokalmedien, abgeglichen. Zahlen verdeckt, da dies ein Muster ist; in Ihrem Bericht erscheinen sie vollständig mit Quellenlink.','ru'=>'[1] МВД — статистика преступности · [4] Мэрия, годовой отчёт · [6] Два местных СМИ, перекрёстно. Цифры скрыты, поскольку это образец; в вашем отчёте они приводятся полностью со ссылкой на источник.' ],
        'mu.cap.fyk' => [ 'es'=>'Qué significa para usted','en'=>'What this means for you','fr'=>'Ce que cela signifie pour vous','de'=>'Was das für Sie bedeutet','ru'=>'Что это значит для вас' ],
        'mu.cap.fy' => [ 'es'=>'Con dos hijos y su prioridad de tranquilidad, lo relevante de estos datos es <b>cómo se comporta la zona fuera de temporada</b>: los registros describen un entorno de actividad estable en invierno, con los picos habituales de población flotante en verano. <b>Los datos describen; la valoración final es suya.</b>','en'=>'With two children and your priority of peace, what matters in these figures is <b>how the area behaves off-season</b>: the records describe a stable environment in winter, with the usual summer peaks of floating population. <b>The data describes; the final judgement is yours.</b>','fr'=>'Avec deux enfants et votre priorité de tranquillité, l\'essentiel de ces données est <b>le comportement de la zone hors saison</b> : les registres décrivent un environnement stable en hiver, avec les pics habituels de population flottante en été. <b>Les données décrivent ; l\'appréciation finale vous appartient.</b>','de'=>'Mit zwei Kindern und Ihrer Priorität Ruhe ist das Relevante an diesen Daten, <b>wie sich das Gebiet außerhalb der Saison verhält</b>: Die Register beschreiben ein stabiles Umfeld im Winter, mit den üblichen Sommerspitzen der wechselnden Bevölkerung. <b>Die Daten beschreiben; das endgültige Urteil liegt bei Ihnen.</b>','ru'=>'С двумя детьми и вашим приоритетом спокойствия главное в этих данных — <b>как район ведёт себя вне сезона</b>: записи описывают стабильную среду зимой с обычными летними пиками приезжих. <b>Данные описывают; окончательная оценка за вами.</b>' ],
        'mu.mid.cta' => [ 'es'=>'Quiero esto para mi zona','en'=>'I want this for my area','fr'=>'Je veux ceci pour ma zone','de'=>'Das möchte ich für mein Gebiet','ru'=>'Хочу такой отчёт по своему району' ],
        'mu.pat.sec'   => [ 'es'=>'02 · Lo que solo se ve cruzando dimensiones','en'=>'02 · What you only see by cross-referencing dimensions','fr'=>'02 · Ce qui ne se voit qu\'en croisant les dimensions','de'=>'02 · Was man nur durch Verknüpfen der Dimensionen sieht','ru'=>'02 · Что видно только при пересечении измерений' ],
        'mu.pat.title' => [ 'es'=>'Tres patrones que un dato suelto no muestra','en'=>'Three patterns a single figure will not show','fr'=>'Trois tendances qu\'une donnée isolée ne montre pas','de'=>'Drei Muster, die eine einzelne Zahl nicht zeigt','ru'=>'Три закономерности, которых не видно по одной цифре' ],
        'mu.pat.1' => [ 'es'=>'<b>La zona funciona todo el año, no solo en verano.</b> El padrón, la actividad comercial y los horarios de servicios coinciden en describir población estable fuera de temporada.','en'=>'<b>The area works all year round, not only in summer.</b> The census, commercial activity and service hours all describe a stable population off-season.','fr'=>'<b>La zone vit toute l\'année, pas seulement en été.</b> Le recensement, l\'activité commerciale et les horaires des services décrivent une population stable hors saison.','de'=>'<b>Das Gebiet funktioniert das ganze Jahr, nicht nur im Sommer.</b> Melderegister, Geschäftstätigkeit und Öffnungszeiten beschreiben übereinstimmend eine stabile Bevölkerung außerhalb der Saison.','ru'=>'<b>Район живёт круглый год, а не только летом.</b> Реестр жителей, коммерческая активность и график услуг согласованно описывают стабильное население вне сезона.' ],
        'mu.pat.1f' => [ 'es'=>'Cruce: Demografía + Servicios + Entorno','en'=>'Cross: Demographics + Services + Environment','fr'=>'Croisement : Démographie + Services + Environnement','de'=>'Verknüpfung: Demografie + Dienstleistungen + Umfeld','ru'=>'Пересечение: Демография + Услуги + Среда' ],
        'mu.pat.2' => [ 'es'=>'<b>Los tiempos reales a sanidad dependen del acceso este.</b> La distancia en mapa es corta, pero el acceso principal concentra el tráfico estacional; el informe detalla los tiempos por franja.','en'=>'<b>Real travel times to healthcare depend on the eastern access.</b> The map distance is short, but the main access concentrates seasonal traffic; the report details times by time slot.','fr'=>'<b>Les temps réels vers la santé dépendent de l\'accès est.</b> La distance sur carte est courte, mais l\'accès principal concentre le trafic saisonnier ; le rapport détaille les temps par tranche.','de'=>'<b>Die realen Wege zur Gesundheitsversorgung hängen vom Ostzugang ab.</b> Die Kartenentfernung ist kurz, aber der Hauptzugang bündelt den Saisonverkehr; der Bericht schlüsselt die Zeiten nach Zeitfenstern auf.','ru'=>'<b>Реальное время до медицины зависит от восточного въезда.</b> Расстояние по карте небольшое, но главный въезд концентрирует сезонный трафик; отчёт детализирует время по интервалам.' ],
        'mu.pat.2f' => [ 'es'=>'Cruce: Sanidad + Movilidad','en'=>'Cross: Healthcare + Mobility','fr'=>'Croisement : Santé + Mobilité','de'=>'Verknüpfung: Gesundheit + Mobilität','ru'=>'Пересечение: Медицина + Транспорт' ],
        'mu.pat.3' => [ 'es'=>'<b>Hay dos obras públicas previstas que cambiarán el día a día.</b> Recogidas en el planeamiento oficial, afectan a un acceso y a un equipamiento escolar. Se describen sin especular con su efecto en precios.','en'=>'<b>Two planned public works will change daily life.</b> Set out in official planning, they affect one access road and one school facility. They are described without speculating on their effect on prices.','fr'=>'<b>Deux travaux publics prévus changeront le quotidien.</b> Inscrits dans l\'urbanisme officiel, ils concernent un accès et un équipement scolaire. Décrits sans spéculer sur leur effet sur les prix.','de'=>'<b>Zwei geplante öffentliche Bauvorhaben werden den Alltag verändern.</b> In der offiziellen Planung verankert, betreffen sie eine Zufahrt und eine Schuleinrichtung. Beschrieben ohne Spekulation über Preiseffekte.','ru'=>'<b>Две запланированные общественные стройки изменят повседневность.</b> Заложены в официальном планировании и затрагивают один въезд и школьный объект. Описаны без спекуляций о влиянии на цены.' ],
        'mu.pat.3f' => [ 'es'=>'Cruce: Planificación + Educación + Movilidad','en'=>'Cross: Planning + Education + Mobility','fr'=>'Croisement : Urbanisme + Éducation + Mobilité','de'=>'Verknüpfung: Planung + Bildung + Mobilität','ru'=>'Пересечение: Планирование + Образование + Транспорт' ],
        'mu.pat.callout' => [ 'es'=>'<b>Por qué importa.</b> Cualquiera puede buscar un dato. El valor está en cruzarlos: los patrones le cuentan cómo funciona la zona de verdad, que es lo que no se ve en una visita de una tarde.','en'=>'<b>Why it matters.</b> Anyone can look up a figure. The value lies in cross-referencing them: the patterns tell you how the area really works — what you cannot see in a one-afternoon visit.','fr'=>'<b>Pourquoi c\'est important.</b> N\'importe qui peut chercher une donnée. La valeur est dans le croisement : les tendances racontent comment la zone fonctionne vraiment, ce qu\'on ne voit pas en une visite d\'un après-midi.','de'=>'<b>Warum es zählt.</b> Eine Zahl kann jeder nachschlagen. Der Wert liegt im Verknüpfen: Die Muster erzählen, wie das Gebiet wirklich funktioniert — was man bei einem Nachmittagsbesuch nicht sieht.','ru'=>'<b>Почему это важно.</b> Найти цифру может каждый. Ценность — в пересечении: закономерности показывают, как район работает на самом деле, чего не увидеть за один вечерний визит.' ],
        'mu.fu.sec'   => [ 'es'=>'12 · Cada dato, comprobable','en'=>'12 · Every figure, verifiable','fr'=>'12 · Chaque donnée, vérifiable','de'=>'12 · Jede Angabe überprüfbar','ru'=>'12 · Каждый факт проверяем' ],
        'mu.fu.title' => [ 'es'=>'De dónde sale lo que le contamos','en'=>'Where what we tell you comes from','fr'=>'D\'où vient ce que nous vous disons','de'=>'Woher das stammt, was wir Ihnen sagen','ru'=>'Откуда берётся то, что мы вам сообщаем' ],
        'mu.fu.1t' => [ 'es'=>'Fuentes oficiales y registros públicos','en'=>'Official sources and public records','fr'=>'Sources officielles et registres publics','de'=>'Offizielle Quellen und öffentliche Register','ru'=>'Официальные источники и публичные реестры' ],
        'mu.fu.1d' => [ 'es'=>'Ministerio del Interior, INE, Catastro, planeamiento municipal, carteras de sanidad y educación','en'=>'Ministry of the Interior, INE, Cadastre, municipal planning, healthcare and education registers','fr'=>'Ministère de l\'Intérieur, INE, Cadastre, urbanisme municipal, offres de santé et d\'éducation','de'=>'Innenministerium, INE, Kataster, Gemeindeplanung, Gesundheits- und Bildungsverzeichnisse','ru'=>'МВД, INE, кадастр, муниципальное планирование, реестры здравоохранения и образования' ],
        'mu.fu.2t' => [ 'es'=>'Fuentes locales contrastadas','en'=>'Cross-checked local sources','fr'=>'Sources locales recoupées','de'=>'Abgeglichene lokale Quellen','ru'=>'Перепроверенные местные источники' ],
        'mu.fu.2d' => [ 'es'=>'Prensa local, actas y anuncios municipales — solo lo verificado en más de una fuente','en'=>'Local press, minutes and municipal announcements — only what is verified in more than one source','fr'=>'Presse locale, procès-verbaux et annonces municipales — seulement ce qui est vérifié dans plus d\'une source','de'=>'Lokalpresse, Protokolle und Gemeindebekanntmachungen — nur das in mehr als einer Quelle Bestätigte','ru'=>'Местная пресса, протоколы и муниципальные объявления — только подтверждённое более чем одним источником' ],
        'mu.fu.3t' => [ 'es'=>'Método ROMVILL de cruce y verificación','en'=>'ROMVILL cross-checking and verification method','fr'=>'Méthode ROMVILL de croisement et vérification','de'=>'ROMVILL-Methode für Abgleich und Verifizierung','ru'=>'Метод ROMVILL: сверка и проверка' ],
        'mu.fu.3d' => [ 'es'=>'Cada dato citado a su fuente y contrastado; lo no verificable, se descarta','en'=>'Every figure cited to its source and cross-checked; what cannot be verified is discarded','fr'=>'Chaque donnée citée à sa source et recoupée ; le non vérifiable est écarté','de'=>'Jede Angabe mit Quellenangabe und abgeglichen; nicht Verifizierbares wird verworfen','ru'=>'Каждый факт со ссылкой на источник и перепроверен; непроверяемое отбрасывается' ],
        'mu.fu.vig' => [ 'es'=>'<b>Nota de vigencia.</b> Este informe se elabora con datos vigentes en el momento del encargo y refleja la situación a su fecha de emisión. No reutilizamos estudios antiguos.','en'=>'<b>Validity note.</b> This report is built with data current at the time of the order and reflects the situation at its issue date. We do not reuse old studies.','fr'=>'<b>Note de validité.</b> Ce rapport est élaboré avec des données à jour au moment de la commande et reflète la situation à sa date d\'émission. Nous ne réutilisons pas d\'anciennes études.','de'=>'<b>Gültigkeitshinweis.</b> Dieser Bericht entsteht mit zum Auftragszeitpunkt aktuellen Daten und spiegelt die Lage zum Ausstellungsdatum wider. Wir verwenden keine alten Studien wieder.','ru'=>'<b>О сроке действия.</b> Отчёт составляется по данным, актуальным на момент заказа, и отражает ситуацию на дату выпуска. Мы не переиспользуем старые исследования.' ],
        'mu.fu.indep' => [ 'es'=>'<b>Declaración de independencia.</b> Este informe no ha sido encargado ni financiado por agencias, promotores o propietarios de la zona. ROMVILL no percibe comisión alguna vinculada a la decisión del cliente.','en'=>'<b>Declaration of independence.</b> This report has not been commissioned or funded by agencies, developers or property owners in the area. ROMVILL receives no commission linked to the client\'s decision.','fr'=>'<b>Déclaration d\'indépendance.</b> Ce rapport n\'a été ni commandé ni financé par des agences, promoteurs ou propriétaires de la zone. ROMVILL ne perçoit aucune commission liée à la décision du client.','de'=>'<b>Unabhängigkeitserklärung.</b> Dieser Bericht wurde weder von Agenturen, Bauträgern noch Eigentümern des Gebiets beauftragt oder finanziert. ROMVILL erhält keine an die Kundenentscheidung geknüpfte Provision.','ru'=>'<b>Декларация независимости.</b> Этот отчёт не заказан и не оплачен агентствами, застройщиками или собственниками района. ROMVILL не получает комиссий, связанных с решением клиента.' ],
        'mu.ent.pdf.t' => [ 'es'=>'Informe en PDF sellado','en'=>'Sealed PDF report','fr'=>'Rapport PDF scellé','de'=>'Versiegelter PDF-Bericht','ru'=>'Запечатанный PDF-отчёт' ],
        'mu.ent.pdf.d' => [ 'es'=>'El documento final, <b>protegido contra edición</b> y con la referencia de expediente en cada página. Lo que le entregamos queda tal cual, <b>firmado por ROMVILL</b>: nadie puede alterarlo.','en'=>'The final document, <b>protected against editing</b> and with the file reference on every page. What we deliver stays as is, <b>signed by ROMVILL</b>: no one can alter it.','fr'=>'Le document final, <b>protégé contre l\'édition</b> et avec la référence du dossier sur chaque page. Ce que nous livrons reste tel quel, <b>signé par ROMVILL</b> : personne ne peut l\'altérer.','de'=>'Das endgültige Dokument, <b>gegen Bearbeitung geschützt</b> und mit der Aktenreferenz auf jeder Seite. Was wir liefern, bleibt unverändert, <b>von ROMVILL signiert</b>: niemand kann es verändern.','ru'=>'Итоговый документ, <b>защищённый от редактирования</b>, с референсом дела на каждой странице. Что мы передали — остаётся как есть, <b>подписано ROMVILL</b>: никто не может его изменить.' ],
        'mu.ent.web.t' => [ 'es'=>'Informe web interactivo','en'=>'Interactive web report','fr'=>'Rapport web interactif','de'=>'Interaktiver Web-Bericht','ru'=>'Интерактивный веб-отчёт' ],
        'mu.ent.web.d' => [ 'es'=>'La versión online privada: cómoda de leer en cualquier dispositivo, con indicadores visuales. <b>Acceso solo mediante su enlace personal</b> — nadie más puede verla.','en'=>'The private online version: easy to read on any device, with visual indicators. <b>Access only via your personal link</b> — no one else can see it.','fr'=>'La version en ligne privée : facile à lire sur tout appareil, avec des indicateurs visuels. <b>Accès uniquement via votre lien personnel</b> — personne d\'autre ne peut la voir.','de'=>'Die private Online-Version: bequem auf jedem Gerät zu lesen, mit visuellen Indikatoren. <b>Zugang nur über Ihren persönlichen Link</b> — niemand sonst kann sie sehen.','ru'=>'Приватная онлайн-версия: удобно читать на любом устройстве, с визуальными индикаторами. <b>Доступ только по вашей личной ссылке</b> — никто другой её не увидит.' ],
        'mu.ent.lock' => [ 'es'=>'Protegido','en'=>'Protected','fr'=>'Protégé','de'=>'Geschützt','ru'=>'Защищено' ],
        'mu.ent.note' => [ 'es'=>'Ambos formatos contienen el mismo informe y se acuerdan al hacer el encargo, según el nivel elegido. Sin archivos editables: lo que ROMVILL firma, no se puede modificar.','en'=>'Both formats contain the same report and are agreed when placing the order, depending on the chosen level. No editable files: what ROMVILL signs cannot be modified.','fr'=>'Les deux formats contiennent le même rapport et sont convenus à la commande, selon le niveau choisi. Pas de fichiers modifiables : ce que ROMVILL signe ne peut pas être modifié.','de'=>'Beide Formate enthalten denselben Bericht und werden bei der Beauftragung je nach gewählter Stufe vereinbart. Keine bearbeitbaren Dateien: Was ROMVILL signiert, kann nicht verändert werden.','ru'=>'Оба формата содержат один и тот же отчёт и согласуются при заказе в зависимости от уровня. Без редактируемых файлов: то, что подписывает ROMVILL, изменить нельзя.' ],
        'mu.cta.title' => [ 'es'=>'Su zona, con este mismo rigor','en'=>'Your area, with this same rigour','fr'=>'Votre zone, avec la même rigueur','de'=>'Ihr Gebiet, mit derselben Sorgfalt','ru'=>'Ваш район — с той же строгостью' ],
        'mu.cta.p' => [ 'es'=>'Esto es una muestra con datos ficticios y cifras ocultas. Su informe se elabora desde cero sobre la zona exacta que le interesa, enfocado a sus prioridades y con todos los datos completos.','en'=>'This is a sample with fictitious data and hidden figures. Your report is built from scratch on the exact area you care about, focused on your priorities and with all figures in full.','fr'=>'Ceci est un exemple avec des données fictives et des chiffres masqués. Votre rapport est élaboré à partir de zéro sur la zone exacte qui vous intéresse, centré sur vos priorités et avec toutes les données complètes.','de'=>'Dies ist ein Muster mit fiktiven Daten und verdeckten Zahlen. Ihr Bericht entsteht von Grund auf für genau das Gebiet, das Sie interessiert, ausgerichtet auf Ihre Prioritäten und mit allen vollständigen Daten.','ru'=>'Это образец с вымышленными данными и скрытыми цифрами. Ваш отчёт создаётся с нуля по интересующему вас району, с фокусом на ваши приоритеты и с полными данными.' ],
        'mu.link.ver' => [ 'es'=>'Ver una muestra del informe','en'=>'See a sample report','fr'=>'Voir un exemple de rapport','de'=>'Einen Musterbericht ansehen','ru'=>'Посмотреть образец отчёта' ],
        'zona.marbella.h1'          => [ 'es'=>'Análisis de zona en Marbella','en'=>'Area analysis in Marbella','fr'=>'Analyse de zone à Marbella','de'=>'Gebietsanalyse in Marbella','ru'=>'Анализ района в Марбелье' ],
        'zona.marbella.sub'         => [ 'es'=>'Antes de comprar o instalarte en Marbella, conoce la zona de verdad — no la del folleto, la real.','en'=>'Before buying or settling in Marbella, get to know the area as it really is — not the brochure version.','fr'=>'Avant d\'acheter ou de vous installer à Marbella, découvrez la zone telle qu\'elle est réellement — pas celle de la brochure.','de'=>'Bevor Sie in Marbella kaufen oder sich niederlassen, lernen Sie die Gegend wirklich kennen — nicht die aus dem Prospekt, die echte.','ru'=>'Прежде чем покупать или обосноваться в Марбелье, узнайте район по-настоящему — не из буклета, а реальный.' ],
        'zona.marbella.intro.title' => [ 'es'=>'Marbella no es una sola zona','en'=>'Marbella is not a single area','fr'=>'Marbella n\'est pas une seule zone','de'=>'Marbella ist kein einheitliches Gebiet','ru'=>'Марбелья — это не один район' ],
        'zona.marbella.intro.p1'    => [ 'es'=>'Entre la <b>Milla de Oro</b>, <b>Nueva Andalucía</b>, <b>San Pedro de Alcántara</b>, el casco antiguo o las urbanizaciones de la sierra hay diferencias enormes en seguridad, ambiente, servicios y futuro. Dos calles pueden ser dos mundos.','en'=>'Between the <b>Golden Mile</b>, <b>Nueva Andalucía</b>, <b>San Pedro de Alcántara</b>, the old town or the hillside urbanisations there are huge differences in safety, atmosphere, services and future. Two streets can be two worlds.','fr'=>'Entre la <b>Milla de Oro</b>, <b>Nueva Andalucía</b>, <b>San Pedro de Alcántara</b>, la vieille ville ou les résidences de la sierra, les différences de sécurité, d\'ambiance, de services et d\'avenir sont énormes. Deux rues peuvent être deux mondes.','de'=>'Zwischen der <b>Goldenen Meile</b>, <b>Nueva Andalucía</b>, <b>San Pedro de Alcántara</b>, der Altstadt oder den Hangsiedlungen gibt es riesige Unterschiede bei Sicherheit, Atmosphäre, Dienstleistungen und Zukunft. Zwei Straßen können zwei Welten sein.','ru'=>'Между <b>Золотой милей</b>, <b>Нуэва-Андалусией</b>, <b>Сан-Педро-де-Алькантара</b>, старым городом и посёлками в горах — огромная разница в безопасности, атмосфере, услугах и будущем. Две улицы могут быть двумя мирами.' ],
        'zona.marbella.intro.p2'    => [ 'es'=>'Tomar una decisión de este calibre por lo que se ve en una visita —o por lo que te cuenta quien te vende— es jugársela. <b>ROMVILL estudia la zona exacta que te interesa con criterio de inteligencia, no de inmobiliaria.</b>','en'=>'Making a decision of this magnitude based on a single visit —or on what the seller tells you— is a gamble. <b>ROMVILL studies the exact area you care about with an intelligence approach, not an estate-agent one.</b>','fr'=>'Prendre une décision de cette ampleur d\'après une simple visite —ou d\'après ce que dit le vendeur— c\'est jouer gros. <b>ROMVILL étudie la zone exacte qui vous intéresse avec une approche de renseignement, pas d\'agence.</b>','de'=>'Eine Entscheidung dieser Größenordnung nach einem einzigen Besuch —oder nach dem, was der Verkäufer sagt— zu treffen, ist ein Risiko. <b>ROMVILL untersucht das genaue Gebiet, das Sie interessiert, mit dem Blick eines Analysten, nicht mit dem eines Maklers.</b>','ru'=>'Принимать решение такого масштаба по одному визиту —или по словам продавца— значит рисковать. <b>ROMVILL изучает именно интересующий вас район методом разведки, а не агентства недвижимости.</b>' ],
        'seo.title.analisis-marbella' => [ 'es'=>'Análisis de zona en Marbella — Seguridad, servicios y entorno | ROMVILL','en'=>'Area analysis in Marbella — Safety, services and surroundings | ROMVILL','fr'=>'Analyse de zone à Marbella — Sécurité, services et environnement | ROMVILL','de'=>'Gebietsanalyse in Marbella — Sicherheit, Dienste und Umfeld | ROMVILL','ru'=>'Анализ района в Марбелье — безопасность, услуги и окружение | ROMVILL' ],
        'seo.desc.analisis-marbella'  => [ 'es'=>'Estudio independiente de zonas de Marbella antes de comprar o mudarte: seguridad, quién vive, sanidad, movilidad, servicios y desarrollo. Datos oficiales, sin intereses inmobiliarios.','en'=>'Independent study of Marbella areas before you buy or move: safety, who lives there, healthcare, mobility, services and development. Official data, no real-estate interests.','fr'=>'Étude indépendante des zones de Marbella avant d\'acheter ou de déménager : sécurité, qui y vit, santé, mobilité, services et développement. Données officielles, sans intérêts immobiliers.','de'=>'Unabhängige Studie von Gebieten in Marbella vor Kauf oder Umzug: Sicherheit, wer dort lebt, Gesundheit, Mobilität, Dienste und Entwicklung. Amtliche Daten, ohne Immobilieninteressen.','ru'=>'Независимое исследование районов Марбельи перед покупкой или переездом: безопасность, кто живёт, здравоохранение, мобильность, услуги и развитие. Официальные данные, без риелторских интересов.' ],
        'zona.malaga.h1'          => [ 'es'=>'Análisis de zona en Málaga','en'=>'Area analysis in Málaga','fr'=>'Analyse de zone à Málaga','de'=>'Gebietsanalyse in Málaga','ru'=>'Анализ района в Малаге' ],
        'zona.malaga.sub'         => [ 'es'=>'Antes de comprar o instalarte en Málaga, conoce la zona de verdad — no la del folleto, la real.','en'=>'Before buying or settling in Málaga, get to know the area as it really is — not the brochure version.','fr'=>'Avant d\'acheter ou de vous installer à Málaga, découvrez la zone telle qu\'elle est réellement — pas celle de la brochure.','de'=>'Bevor Sie in Málaga kaufen oder sich niederlassen, lernen Sie die Gegend wirklich kennen — nicht die aus dem Prospekt, die echte.','ru'=>'Прежде чем покупать или обосноваться в Малаге, узнайте район по-настоящему — не из буклета, а реальный.' ],
        'zona.malaga.intro.title' => [ 'es'=>'Málaga no es una sola zona','en'=>'Málaga is not a single area','fr'=>'Málaga n\'est pas une seule zone','de'=>'Málaga ist kein einheitliches Gebiet','ru'=>'Малага — это не один район' ],
        'zona.malaga.intro.p1'    => [ 'es'=>'No es lo mismo el <b>Centro histórico</b>, <b>El Limonar</b>, <b>Teatinos</b>, <b>Pedregalejo</b> o la zona oeste: entre unos barrios y otros cambian la seguridad, el ambiente, los servicios y el futuro. Dos barrios pueden ser dos ciudades.','en'=>'The <b>historic centre</b>, <b>El Limonar</b>, <b>Teatinos</b>, <b>Pedregalejo</b> or the western side are not the same: safety, atmosphere, services and future change from one neighbourhood to the next. Two neighbourhoods can be two cities.','fr'=>'Le <b>centre historique</b>, <b>El Limonar</b>, <b>Teatinos</b>, <b>Pedregalejo</b> ou l\'ouest ne se valent pas : sécurité, ambiance, services et avenir changent d\'un quartier à l\'autre. Deux quartiers peuvent être deux villes.','de'=>'Die <b>historische Altstadt</b>, <b>El Limonar</b>, <b>Teatinos</b>, <b>Pedregalejo</b> oder der Westen sind nicht dasselbe: Sicherheit, Atmosphäre, Dienste und Zukunft ändern sich von Viertel zu Viertel. Zwei Viertel können zwei Städte sein.','ru'=>'Исторический <b>центр</b>, <b>Эль-Лимонар</b>, <b>Театинос</b>, <b>Педрегалехо</b> или западная часть — это не одно и то же: безопасность, атмосфера, услуги и будущее меняются от района к району. Два района могут быть двумя городами.' ],
        'zona.malaga.intro.p2'    => [ 'es'=>'Tomar una decisión de este calibre por lo que se ve en una visita —o por lo que te cuenta quien te vende— es jugársela. <b>ROMVILL estudia la zona exacta que te interesa con criterio de inteligencia, no de inmobiliaria.</b>','en'=>'Making a decision of this magnitude based on a single visit —or on what the seller tells you— is a gamble. <b>ROMVILL studies the exact area you care about with an intelligence approach, not an estate-agent one.</b>','fr'=>'Prendre une décision de cette ampleur d\'après une simple visite —ou d\'après ce que dit le vendeur— c\'est jouer gros. <b>ROMVILL étudie la zone exacte qui vous intéresse avec une approche de renseignement, pas d\'agence.</b>','de'=>'Eine Entscheidung dieser Größenordnung nach einem einzigen Besuch —oder nach dem, was der Verkäufer sagt— zu treffen, ist ein Risiko. <b>ROMVILL untersucht das genaue Gebiet, das Sie interessiert, mit dem Blick eines Analysten, nicht mit dem eines Maklers.</b>','ru'=>'Принимать решение такого масштаба по одному визиту —или по словам продавца— значит рисковать. <b>ROMVILL изучает именно интересующий вас район методом разведки, а не агентства недвижимости.</b>' ],
