        'zona.alicante.h1'          => [ 'es'=>'Análisis de zona en Alicante','en'=>'Area analysis in Alicante','fr'=>'Analyse de zone à Alicante','de'=>'Gebietsanalyse in Alicante','ru'=>'Анализ района в Аликанте' ],
        'zona.alicante.sub'         => [ 'es'=>'Antes de comprar o instalarte en Alicante o la Costa Blanca, conoce la zona de verdad — no la del folleto, la real.','en'=>'Before buying or settling in Alicante or the Costa Blanca, get to know the area as it really is — not the brochure version.','fr'=>'Avant d\'acheter ou de vous installer à Alicante ou sur la Costa Blanca, découvrez la zone telle qu\'elle est réellement — pas celle de la brochure.','de'=>'Bevor Sie in Alicante oder an der Costa Blanca kaufen oder sich niederlassen, lernen Sie die Gegend wirklich kennen — nicht die aus dem Prospekt, die echte.','ru'=>'Прежде чем покупать или обосноваться в Аликанте или на Коста-Бланке, узнайте район по-настоящему — не из буклета, а реальный.' ],
        'zona.alicante.intro.title' => [ 'es'=>'Alicante no es una sola zona','en'=>'Alicante is not a single area','fr'=>'Alicante n\'est pas une seule zone','de'=>'Alicante ist kein einheitliches Gebiet','ru'=>'Аликанте — это не один район' ],
        'zona.alicante.intro.p1'    => [ 'es'=>'No es lo mismo el <b>centro</b>, la <b>Playa de San Juan</b>, la <b>Albufereta</b>, <b>Vistahermosa</b> o los pueblos de la <b>Costa Blanca</b> como Jávea o Altea: cambian la seguridad, el ambiente, los servicios y el futuro.','en'=>'The <b>centre</b>, <b>San Juan beach</b>, the <b>Albufereta</b>, <b>Vistahermosa</b> or the <b>Costa Blanca</b> towns like Jávea or Altea are not the same: safety, atmosphere, services and future all change.','fr'=>'Le <b>centre</b>, la <b>plage de San Juan</b>, l\'<b>Albufereta</b>, <b>Vistahermosa</b> ou les villages de la <b>Costa Blanca</b> comme Jávea ou Altea ne se valent pas : sécurité, ambiance, services et avenir changent.','de'=>'Das <b>Zentrum</b>, der <b>Strand von San Juan</b>, die <b>Albufereta</b>, <b>Vistahermosa</b> oder die <b>Costa-Blanca</b>-Orte wie Jávea oder Altea sind nicht dasselbe: Sicherheit, Atmosphäre, Dienste und Zukunft ändern sich.','ru'=>'<b>Центр</b>, <b>пляж Сан-Хуан</b>, <b>Альбуферета</b>, <b>Вистаэрмоса</b> или городки <b>Коста-Бланки</b> вроде Хавеи или Альтеи — это не одно и то же: меняются безопасность, атмосфера, услуги и будущее.' ],
        'zona.alicante.intro.p2'    => [ 'es'=>'Tomar una decisión de este calibre por lo que se ve en una visita —o por lo que te cuenta quien te vende— es jugársela. <b>ROMVILL estudia la zona exacta que te interesa con criterio de inteligencia, no de inmobiliaria.</b>','en'=>'Making a decision of this magnitude based on a single visit —or on what the seller tells you— is a gamble. <b>ROMVILL studies the exact area you care about with an intelligence approach, not an estate-agent one.</b>','fr'=>'Prendre une décision de cette ampleur d\'après une simple visite —ou d\'après ce que dit le vendeur— c\'est jouer gros. <b>ROMVILL étudie la zone exacte qui vous intéresse avec une approche de renseignement, pas d\'agence.</b>','de'=>'Eine Entscheidung dieser Größenordnung nach einem einzigen Besuch —oder nach dem, was der Verkäufer sagt— zu treffen, ist ein Risiko. <b>ROMVILL untersucht das genaue Gebiet, das Sie interessiert, mit dem Blick eines Analysten, nicht mit dem eines Maklers.</b>','ru'=>'Принимать решение такого масштаба по одному визиту —или по словам продавца— значит рисковать. <b>ROMVILL изучает именно интересующий вас район методом разведки, а не агентства недвижимости.</b>' ],
        'seo.title.analisis-alicante' => [ 'es'=>'Análisis de zona en Alicante — Seguridad, servicios y entorno | ROMVILL','en'=>'Area analysis in Alicante — Safety, services and surroundings | ROMVILL','fr'=>'Analyse de zone à Alicante — Sécurité, services et environnement | ROMVILL','de'=>'Gebietsanalyse in Alicante — Sicherheit, Dienste und Umfeld | ROMVILL','ru'=>'Анализ района в Аликанте — безопасность, услуги и окружение | ROMVILL' ],
        'seo.desc.analisis-alicante'  => [ 'es'=>'Estudio independiente de zonas de Alicante y la Costa Blanca antes de comprar o mudarte: seguridad, quién vive, sanidad, movilidad, servicios y desarrollo. Datos oficiales, sin intereses inmobiliarios.','en'=>'Independent study of Alicante and Costa Blanca areas before you buy or move: safety, who lives there, healthcare, mobility, services and development. Official data, no real-estate interests.','fr'=>'Étude indépendante des zones d\'Alicante et de la Costa Blanca avant d\'acheter ou de déménager : sécurité, qui y vit, santé, mobilité, services et développement. Données officielles, sans intérêts immobiliers.','de'=>'Unabhängige Studie von Gebieten in Alicante und an der Costa Blanca vor Kauf oder Umzug: Sicherheit, wer dort lebt, Gesundheit, Mobilität, Dienste und Entwicklung. Amtliche Daten, ohne Immobilieninteressen.','ru'=>'Независимое исследование районов Аликанте и Коста-Бланки перед покупкой или переездом: безопасность, кто живёт, здравоохранение, мобильность, услуги и развитие. Официальные данные, без риелторских интересов.' ],
        'modal.alicante.badge'=> [ 'es'=>'Comunidad Valenciana · Costa Mediterránea','en'=>'Valencian Community · Mediterranean Coast','fr'=>'Communauté Valencienne · Côte Méditerranéenne','de'=>'Valencianische Gemeinschaft · Mittelmeerküste','ru'=>'Валенсийское Сообщество · Средиземноморское Побережье' ],
        'modal.alicante.h3'   => [ 'es'=>'Una costa que no para de crecer','en'=>'A coast that keeps on growing','fr'=>'Une côte qui ne cesse de croître','de'=>'Eine Küste, die unaufhörlich wächst','ru'=>'Побережье, которое не перестаёт расти' ],
        'modal.alicante.p1'   => [ 'es'=>'Alicante y sus municipios vive un momento de fuerte demanda inmobiliaria, y eso está transformando muchas de sus zonas. Algunas áreas se consolidan como entornos muy cotizados, mientras otras crecen tan rápido que conviene conocer bien cómo está cada lugar antes de decidir.','en'=>'Alicante and its municipalities are experiencing a moment of strong property demand, and that is transforming many of its areas. Some areas are consolidating as highly sought-after environments, while others are growing so fast that it is worth knowing well how each place stands before deciding.','fr'=>'Alicante et ses communes connaissent un moment de forte demande immobilière, et cela transforme bon nombre de ses zones. Certaines zones se consolident comme des environnements très prisés, tandis que d\'autres croissent si vite qu\'il convient de bien connaître l\'état de chaque endroit avant de décider.','de'=>'Alicante und seine Gemeinden erleben derzeit eine starke Immobiliennachfrage, die viele Gebiete verändert. Manche festigen sich als sehr begehrte Lagen, während andere so schnell wachsen, dass man vor einer Entscheidung genau wissen sollte, wie es um jeden Ort steht.','ru'=>'Аликанте и его муниципалитеты переживают момент высокого спроса на недвижимость, и это преображает многие их зоны. Одни районы укрепляются как очень востребованные среды, тогда как другие растут так быстро, что стоит хорошо узнать положение каждого места перед принятием решения.' ],
        'modal.alicante.p2'   => [ 'es'=>'Por eso vamos más allá de los portales inmobiliarios: estudiamos sobre el terreno cómo es realmente cada zona, su ambiente, su entorno y su día a día, para darle una visión clara y honesta antes de que dé el paso.','en'=>'That is why we go beyond property portals: we study on the ground what each area is really like, its atmosphere, its surroundings and its daily life, to give you a clear and honest picture before you take the step.','fr'=>'C\'est pourquoi nous allons au-delà des portails immobiliers : nous étudions sur le terrain comment est vraiment chaque zone, son ambiance, son environnement et son quotidien, pour vous donner une vision claire et honnête avant que vous ne franchissiez le pas.','de'=>'Deshalb gehen wir über Immobilienportale hinaus: Wir untersuchen vor Ort, wie jedes Gebiet wirklich ist, seine Atmosphäre, sein Umfeld und seinen Alltag, um Ihnen ein klares und ehrliches Bild zu geben, bevor Sie den Schritt wagen.','ru'=>'Поэтому мы выходим за рамки порталов недвижимости: мы изучаем на месте, какова на самом деле каждая зона, её атмосфера, окружение и повседневная жизнь, чтобы дать вам ясную и честную картину, прежде чем вы сделаете шаг.' ],
        'modal.alicante.cov'  => [ 'es'=>'Zona de cobertura: Alicante ciudad, El Campello, San Juan, San Vicente del Raspeig y municipios limítrofes.','en'=>'Coverage area: Alicante city, El Campello, San Juan, San Vicente del Raspeig and bordering municipalities.','fr'=>'Zone de couverture : Ville d\'Alicante, El Campello, San Juan, San Vicente del Raspeig et communes limitrophes.','de'=>'Abdeckungsgebiet: Stadt Alicante, El Campello, San Juan, San Vicente del Raspeig und angrenzende Gemeinden.','ru'=>'Зона охвата: город Аликанте, Эль-Кампельо, Сан-Хуан, Сан-Висенте-дель-Распейг и прилегающие муниципалитеты.' ],
        'modal.malaga.badge'  => [ 'es'=>'Andalucía · Costa del Sol Oriental','en'=>'Andalusia · Eastern Costa del Sol','fr'=>'Andalousie · Costa del Sol Est','de'=>'Andalusien · Östliche Costa del Sol','ru'=>'Андалусия · Восточная Коста-дель-Соль' ],
        'modal.malaga.h3'     => [ 'es'=>'Una ciudad en plena transformación','en'=>'A city in full transformation','fr'=>'Une ville en pleine transformation','de'=>'Eine Stadt im vollen Wandel','ru'=>'Город в разгаре преображения' ],
        'modal.malaga.p1'     => [ 'es'=>'Málaga se ha convertido en uno de los grandes polos de innovación de Europa. Ese auge ha disparado el interés por la ciudad y ha hecho que muchos barrios cambien rápidamente, tanto en precios como en ambiente y servicios.','en'=>'Málaga has become one of Europe\'s major innovation hubs. That boom has driven up interest in the city and made many neighbourhoods change rapidly, both in prices and in atmosphere and services.','fr'=>'Málaga est devenue l\'un des grands pôles d\'innovation d\'Europe. Cet essor a fait grimper l\'intérêt pour la ville et a fait évoluer rapidement de nombreux quartiers, tant en prix qu\'en ambiance et en services.','de'=>'Málaga ist zu einem der großen Innovationszentren Europas geworden. Dieser Aufschwung hat das Interesse an der Stadt steigen lassen und viele Stadtteile schnell verändert, sowohl bei den Preisen als auch in Atmosphäre und Dienstleistungen.','ru'=>'Малага стала одним из крупнейших центров инноваций Европы. Этот подъём резко повысил интерес к городу и заставил многие районы быстро меняться — как в ценах, так и в атмосфере и услугах.' ],
        'modal.malaga.p2'     => [ 'es'=>'Por eso analizamos sobre el terreno cómo está hoy cada zona del área metropolitana: su entorno, sus servicios, su evolución y su día a día, para que tenga una visión clara y fiable antes de tomar cualquier decisión.','en'=>'That is why we study on the ground how each area of the metropolitan region stands today: its surroundings, its services, its evolution and its daily life, so you have a clear and reliable picture before making any decision.','fr'=>'C\'est pourquoi nous analysons sur le terrain l\'état actuel de chaque zone de l\'aire métropolitaine : son environnement, ses services, son évolution et son quotidien, pour que vous ayez une vision claire et fiable avant de prendre toute décision.','de'=>'Deshalb analysieren wir vor Ort, wie jedes Gebiet des Ballungsraums heute dasteht: sein Umfeld, seine Dienstleistungen, seine Entwicklung und seinen Alltag, damit Sie vor jeder Entscheidung ein klares und verlässliches Bild haben.','ru'=>'Поэтому мы анализируем на месте, в каком состоянии сегодня находится каждая зона агломерации: её окружение, услуги, развитие и повседневную жизнь, чтобы у вас была ясная и надёжная картина перед принятием любого решения.' ],
        'modal.malaga.cov'    => [ 'es'=>'Zona de cobertura: Málaga capital, Torremolinos, Benalmádena, Fuengirola y el corredor de la A-7.','en'=>'Coverage area: Málaga capital, Torremolinos, Benalmádena, Fuengirola and the A-7 corridor.','fr'=>'Zone de couverture : Málaga capitale, Torremolinos, Benalmádena, Fuengirola et le corridor de l\'A-7.','de'=>'Abdeckungsgebiet: Málaga Hauptstadt, Torremolinos, Benalmádena, Fuengirola und der A-7-Korridor.','ru'=>'Зона охвата: город Малага, Торремолинос, Беналмадена, Фуэнхирола и коридор трассы A-7.' ],
        'modal.marbella.badge'=> [ 'es'=>'Andalucía · Costa del Sol Occidental','en'=>'Andalusia · Western Costa del Sol','fr'=>'Andalousie · Costa del Sol Ouest','de'=>'Andalusien · Westliche Costa del Sol','ru'=>'Андалусия · Западная Коста-дель-Соль' ],
        'modal.marbella.h3'   => [ 'es'=>'Calidad de vida y exclusividad','en'=>'Quality of life and exclusivity','fr'=>'Qualité de vie et exclusivité','de'=>'Lebensqualität und Exklusivität','ru'=>'Качество жизни и эксклюзивность' ],
        'modal.marbella.p1'   => [ 'es'=>'Marbella y su entorno de alto valor (Benahavís, Sierra Blanca) concentran buena parte de la inversión más exclusiva de España. Es un mercado muy particular, donde la calidad real de cada urbanización no siempre es fácil de conocer desde fuera.','en'=>'Marbella and its high-value surroundings (Benahavís, Sierra Blanca) concentrate much of the most exclusive investment in Spain. It is a very particular market, where the real quality of each development is not always easy to know from the outside.','fr'=>'Marbella et son environnement de haute valeur (Benahavís, Sierra Blanca) concentrent une bonne partie de l\'investissement le plus exclusif d\'Espagne. C\'est un marché très particulier, où la qualité réelle de chaque urbanisation n\'est pas toujours facile à connaître de l\'extérieur.','de'=>'Marbella und sein hochwertiges Umfeld (Benahavís, Sierra Blanca) konzentrieren einen Großteil der exklusivsten Investitionen Spaniens. Es ist ein sehr besonderer Markt, in dem die tatsächliche Qualität jeder Wohnanlage von außen nicht immer leicht zu erkennen ist.','ru'=>'Марбелья и её высококлассное окружение (Бенахавис, Сьерра-Бланка) концентрируют значительную часть самых эксклюзивных инвестиций Испании. Это очень особенный рынок, где реальное качество каждого жилого комплекса не всегда легко узнать со стороны.' ],
        'modal.marbella.p2'   => [ 'es'=>'Por eso analizamos cada comunidad sobre el terreno: su nivel de ocupación a lo largo del año, el estado y la conservación de las urbanizaciones y el ambiente general del entorno, para que conozca de verdad la zona antes de invertir o establecerse.','en'=>'That is why we study each community on the ground: its occupancy level throughout the year, the condition and upkeep of the developments and the general atmosphere of the surroundings, so you truly know the area before investing or settling.','fr'=>'C\'est pourquoi nous analysons chaque communauté sur le terrain : son niveau d\'occupation tout au long de l\'année, l\'état et l\'entretien des urbanisations et l\'ambiance générale de l\'environnement, pour que vous connaissiez vraiment la zone avant d\'investir ou de vous installer.','de'=>'Deshalb analysieren wir jede Gemeinschaft vor Ort: ihren Belegungsstand im Jahresverlauf, den Zustand und die Instandhaltung der Wohnanlagen und die allgemeine Atmosphäre des Umfelds, damit Sie das Gebiet wirklich kennen, bevor Sie investieren oder sich niederlassen.','ru'=>'Поэтому мы анализируем каждый комплекс на месте: уровень заселённости в течение года, состояние и содержание жилых комплексов и общую атмосферу окружения, чтобы вы по-настоящему узнали зону перед тем, как инвестировать или поселиться.' ],
        'modal.marbella.cov'  => [ 'es'=>'Zona de cobertura: Marbella, Benahavís, Estepona, San Pedro Alcántara y la Sierra Blanca.','en'=>'Coverage area: Marbella, Benahavís, Estepona, San Pedro Alcántara and Sierra Blanca.','fr'=>'Zone de couverture : Marbella, Benahavís, Estepona, San Pedro Alcántara et la Sierra Blanca.','de'=>'Abdeckungsgebiet: Marbella, Benahavís, Estepona, San Pedro Alcántara und die Sierra Blanca.','ru'=>'Зона охвата: Марбелья, Бенахавис, Эстепона, Сан-Педро-де-Алькантара и Сьерра-Бланка.' ],

        // CTA section
        'cta.title'           => [ 'es'=>'¿Va a dar el paso?<br/>Primero, conózcalo todo.','en'=>'Ready to take the step?<br/>First, know everything.','fr'=>'Vous allez franchir le pas ?<br/>Sachez d\'abord tout ce qu\'il faut savoir.','de'=>'Bereit für den Schritt?<br/>Erst alles wissen.','ru'=>'Готовы сделать шаг?<br/>Сначала узнайте всё.' ],
        'cta.desc'            => [ 'es'=>'Cuéntenos qué zona le interesa y le explicamos cómo podemos ayudarle. Sin compromiso, sin tecnicismos.','en'=>'Tell us which area interests you and we will explain how we can help. No commitment, no jargon.','fr'=>'Dites-nous quelle zone vous intéresse et nous vous expliquerons comment nous pouvons vous aider. Sans engagement, sans jargon.','de'=>'Sagen Sie uns, welches Gebiet Sie interessiert, und wir erklären Ihnen, wie wir helfen können. Ohne Verpflichtung, ohne Fachjargon.','ru'=>'Расскажите, какой район вас интересует, и мы объясним, как можем помочь. Без обязательств, без жаргона.' ],
