        'contact.form.recommend'      => ['es'=>'Para recibir un presupuesto personalizado basado en su perfil, le recomendamos','en'=>'For a personalised quote based on your profile, we recommend','fr'=>'Pour un devis personnalisé basé sur votre profil, nous vous recommandons','de'=>'Für ein personalisiertes Angebot basierend auf Ihrem Profil empfehlen wir','ru'=>'Для получения персонализированной сметы на основе вашего профиля рекомендуем'],
        'contact.form.recommend.link' => ['es'=>'completar el cuestionario especializado','en'=>'completing the specialised questionnaire','fr'=>'de compléter le questionnaire spécialisé','de'=>'den spezialisierten Fragebogen auszufüllen','ru'=>'заполнить специализированную анкету'],
        'contact.noinmo'       => ['es'=>'No somos una inmobiliaria. Analizamos zonas, sin intereses de por medio.','en'=>'We are not a real estate agency. We analyse areas, with no conflicts of interest.','fr'=>'Nous ne sommes pas une agence immobilière. Nous analysons les zones, sans conflit d\'intérêts.','de'=>'Wir sind keine Immobilienagentur. Wir analysieren Gebiete, ohne Interessenkonflikte.','ru'=>'Мы не агентство недвижимости. Мы анализируем зоны, без конфликта интересов.'],
        'contact.why.title'   => [ 'es'=>'Por qué elegir Romvill','en'=>'Why choose Romvill','fr'=>'Pourquoi choisir Romvill','de'=>'Warum Romvill wählen','ru'=>'Почему выбирают Romvill' ],
        'contact.why.quote'   => [ 'es'=>'"Saber primero es siempre mejor. Romvill le da esa ventaja."','en'=>'"Knowing first is always better. Romvill gives you that advantage."','fr'=>'"Mieux vaut savoir avant de décider. Romvill vous donne cet avantage."','de'=>'"Zuerst zu wissen ist immer besser. Romvill gibt Ihnen diesen Vorteil."','ru'=>'«Знать первым — всегда лучше. Romvill даёт вам это преимущество».' ],
        'contact.why.r1t'     => [ 'es'=>'Informe claro y completo','en'=>'Clear and complete report','fr'=>'Rapport clair et complet','de'=>'Klarer und vollständiger Bericht','ru'=>'Чёткий и полный отчёт' ],
        'contact.why.r1d'     => [ 'es'=>'Recibirá un informe ordenado y comprensible con todo lo que necesita saber sobre la zona que le interesa.','en'=>'You will receive an ordered, comprehensible report with everything you need to know about the area of interest.','fr'=>'Vous recevrez un rapport ordonné et compréhensible avec tout ce que vous devez savoir sur la zone qui vous intéresse.','de'=>'Sie erhalten einen geordneten, verständlichen Bericht mit allem, was Sie über das betreffende Gebiet wissen müssen.','ru'=>'Вы получите упорядоченный и понятный отчёт со всем, что нужно знать об интересующем вас районе.' ],
        'contact.why.r2t'     => [ 'es'=>'Solo analizamos, sin intereses','en'=>'We only analyse, no vested interests','fr'=>'Nous analysons uniquement, sans intérêts','de'=>'Wir analysieren nur, ohne Eigeninteressen','ru'=>'Мы только анализируем, без личных интересов' ],
        'contact.why.r2d'     => [ 'es'=>'No vendemos propiedades ni tenemos vínculos con promotores. Nuestra única función es informarle bien.','en'=>'We do not sell properties nor have ties to developers. Our sole role is to keep you properly informed.','fr'=>'Nous ne vendons pas de propriétés et n\'avons aucun lien avec des promoteurs. Notre seule fonction est de bien vous informer.','de'=>'Wir verkaufen keine Immobilien und haben keine Verbindungen zu Entwicklern. Unsere einzige Funktion ist es, Sie gut zu informieren.','ru'=>'Мы не продаём недвижимость и не связаны с застройщиками. Наша единственная функция — хорошо вас информировать.' ],
        'contact.why.r3t'     => [ 'es'=>'Datos verificados y fiables','en'=>'Verified and reliable data','fr'=>'Données vérifiées et fiables','de'=>'Verifizierte und zuverlässige Daten','ru'=>'Проверенные и надёжные данные' ],
        'contact.why.r3d'     => [ 'es'=>'Contrastamos varias fuentes para que cada dato que le damos sea real y comprobable.','en'=>'We cross-reference multiple sources so every piece of data we give you is real and verifiable.','fr'=>'Nous croisons plusieurs sources pour que chaque donnée que nous vous donnons soit réelle et vérifiable.','de'=>'Wir gleichen mehrere Quellen miteinander ab, damit jede Information, die wir Ihnen geben, real und überprüfbar ist.','ru'=>'Мы перекрёстно проверяем несколько источников, чтобы каждый предоставляемый факт был реальным и проверяемым.' ],
        'contact.why.r4t'     => [ 'es'=>'Ahorro de tiempo y capital','en'=>'Time and capital savings','fr'=>'Économie de temps et de capital','de'=>'Zeit- und Kapitalersparnis','ru'=>'Экономия времени и капитала' ],
        'contact.why.r4d'     => [ 'es'=>'Evite desplazamientos innecesarios y decisiones equivocadas. Nosotros hacemos el trabajo de campo por usted.','en'=>'Avoid unnecessary travel and wrong decisions. We do the fieldwork for you.','fr'=>'Évitez les déplacements inutiles et les mauvaises décisions. Nous faisons le travail de terrain pour vous.','de'=>'Vermeiden Sie unnötige Reisen und falsche Entscheidungen. Wir erledigen die Feldarbeit für Sie.','ru'=>'Избегайте ненужных поездок и ошибочных решений. Мы выполняем полевую работу за вас.' ],
        'contact.why.r5t'     => [ 'es'=>'Confidencialidad absoluta','en'=>'Absolute confidentiality','fr'=>'Confidentialité absolue','de'=>'Absolute Vertraulichkeit','ru'=>'Абсолютная конфиденциальность' ],
        'contact.why.r5d'     => [ 'es'=>'Manejamos cada solicitud con la máxima discreción y profesionalidad.','en'=>'We handle every request with the utmost discretion and professionalism.','fr'=>'Nous traitons chaque demande avec la plus grande discrétion et le plus grand professionnalisme.','de'=>'Wir bearbeiten jede Anfrage mit höchster Diskretion und Professionalität.','ru'=>'Мы обрабатываем каждый запрос с максимальной деликатностью и профессионализмом.' ],
        'contact.why.r6t'     => [ 'es'=>'Estándar profesional','en'=>'Professional Standard','fr'=>'Standard professionnel','de'=>'Professioneller Standard','ru'=>'Профессиональный Стандарт' ],
        'contact.why.r6d'     => [ 'es'=>'Un mismo estándar de rigor sostiene cada informe; su alcance y profundidad se definen según la exigencia de cada cliente.','en'=>'The same standard of rigour underpins every report; its scope and depth are defined according to each client\'s requirements.','fr'=>'Un même standard de rigueur sous-tend chaque rapport ; sa portée et sa profondeur sont définies selon les exigences de chaque client.','de'=>'Derselbe Maßstab an Strenge liegt jedem Bericht zugrunde; sein Umfang und seine Tiefe richten sich nach den Anforderungen jedes Kunden.','ru'=>'Один и тот же стандарт строгости лежит в основе каждого отчёта; его объём и глубина определяются в соответствии с требованиями каждого клиента.' ],
        'contact.why.r7t'     => [ 'es'=>'Alcance Internacional','en'=>'International Reach','fr'=>'Portée Internationale','de'=>'Internationale Reichweite','ru'=>'Международный Охват' ],
        'contact.why.r7d'     => [ 'es'=>'Capacidad operativa para analizar plazas en el extranjero bajo demanda.','en'=>'Operational capacity to analyse locations abroad on demand.','fr'=>'Capacité opérationnelle pour analyser des lieux à l\'étranger sur demande.','de'=>'Betriebskapazität zur Analyse von Standorten im Ausland auf Anfrage.','ru'=>'Операционный потенциал для анализа зарубежных объектов по запросу.' ],
        'contact.why.r8t'     => [ 'es'=>'Inteligencia Estratégica','en'=>'Strategic Intelligence','fr'=>'Intelligence Stratégique','de'=>'Strategische Intelligenz','ru'=>'Стратегическая Аналитика' ],
        'contact.why.r8d'     => [ 'es'=>'Convertimos los datos dispersos en decisiones claras. Minimizamos el riesgo de su inversión o traslado.','en'=>'We turn scattered data into clear decisions. We minimise the risk of your investment or relocation.','fr'=>'Nous transformons les données dispersées en décisions claires. Nous minimisons le risque de votre investissement ou déménagement.','de'=>'Wir verwandeln verstreute Daten in klare Entscheidungen. Wir minimieren das Risiko Ihrer Investition oder Ihres Umzugs.','ru'=>'Мы превращаем разрозненные данные в чёткие решения. Минимизируем риск ваших инвестиций или переезда.' ],

        // ── METODOLOGÍA PAGE ──────────────────────────────────────
        'met.badge'           => [ 'es'=>'Nuestro Proceso','en'=>'Our Process','fr'=>'Notre Processus','de'=>'Unser Prozess','ru'=>'Наш Процесс' ],
        'met.title'           => [ 'es'=>'Metodología','en'=>'Methodology','fr'=>'Méthodologie','de'=>'Methodik','ru'=>'Методология' ],
        'met.subtitle'        => [ 'es'=>'Cómo trabajamos para que usted reciba información real','en'=>'How we work so you receive real information','fr'=>'Comment nous travaillons pour que vous receviez de vraies informations','de'=>'Wie wir arbeiten, damit Sie echte Informationen erhalten','ru'=>'Как мы работаем, чтобы вы получали реальную информацию' ],
        'met.intro'           => [ 'es'=>'Así trabajamos para que usted reciba información fiable y útil: sin atajos, sin datos genéricos y con verificación directa sobre el terreno. Tres pasos claros que garantizan la calidad de cada informe que entregamos.','en'=>'This is how we work to give you reliable and useful information: no shortcuts, no generic data, and direct on-the-ground verification. Three clear steps that guarantee the quality of every report we deliver.','fr'=>'Voici comment nous travaillons pour vous fournir des informations fiables et utiles : sans raccourcis, sans données génériques et avec une vérification directe sur le terrain. Trois étapes claires qui garantissent la qualité de chaque rapport que nous livrons.','de'=>'So arbeiten wir, damit Sie zuverlässige und nützliche Informationen erhalten: ohne Abkürzungen, ohne generische Daten und mit direkter Vor-Ort-Überprüfung. Drei klare Schritte, die die Qualität jedes Berichts garantieren.','ru'=>'Вот как мы работаем, чтобы вы получали надёжную и полезную информацию: без коротких путей, без общих данных и с прямой проверкой на месте. Три чётких шага, гарантирующих качество каждого отчёта.' ],
        'met.level'           => [ 'es'=>'Nivel','en'=>'Level','fr'=>'Niveau','de'=>'Ebene','ru'=>'Уровень' ],
        'met.l1.title'        => [ 'es'=>'Recolección OSINT + Campo','en'=>'OSINT + Field Collection','fr'=>'Collecte OSINT + Terrain','de'=>'OSINT + Felderhebung','ru'=>'Сбор данных: OSINT + полевая работа' ],
        'met.l1.desc'         => [ 'es'=>'Recopilamos información de <strong class="text-slate-700 dark:text-slate-200">fuentes oficiales y registros públicos</strong>, y la contrastamos con visitas presenciales sobre el terreno.','en'=>'We gather information from <strong class="text-slate-700 dark:text-slate-200">official sources and public records</strong>, cross-referencing it with on-site visits in the field.','fr'=>'Nous collectons des informations auprès de <strong class="text-slate-700 dark:text-slate-200">sources officielles et de registres publics</strong>, et les confrontons avec des visites sur le terrain.','de'=>'Wir sammeln Informationen aus <strong class="text-slate-700 dark:text-slate-200">offiziellen Quellen und öffentlichen Registern</strong> und gleichen sie mit Vor-Ort-Besuchen ab.','ru'=>'Мы собираем информацию из <strong class="text-slate-700 dark:text-slate-200">официальных источников и публичных реестров</strong> и перекрёстно проверяем её с выездными визитами.' ],
        'met.l1.i1'           => [ 'es'=>'Datos de fuentes oficiales y registros públicos','en'=>'Data from official sources and public records','fr'=>'Données de sources officielles et registres publics','de'=>'Daten aus offiziellen Quellen und öffentlichen Registern','ru'=>'Данные из официальных источников и публичных реестров' ],
        'met.l1.i2'           => [ 'es'=>'Contraste de información entre distintas fuentes','en'=>'Cross-referencing information between different sources','fr'=>'Recoupement d\'informations entre différentes sources','de'=>'Informationsabgleich zwischen verschiedenen Quellen','ru'=>'Перекрёстная проверка информации из разных источников' ],
        'met.l1.i3'           => [ 'es'=>'Equipo especializado en análisis territorial','en'=>'Team specialised in territorial analysis','fr'=>'Équipe spécialisée en analyse territoriale','de'=>'Auf Gebietsanalyse spezialisiertes Team','ru'=>'Команда, специализирующаяся на территориальном анализе' ],
        'met.l1.i4'           => [ 'es'=>'Visita presencial para confirmar lo que dicen los datos','en'=>'On-site visit to confirm what the data says','fr'=>'Visite sur site pour confirmer ce que disent les données','de'=>'Vor-Ort-Besuch zur Bestätigung der Datenlage','ru'=>'Выездной визит для подтверждения того, что говорят данные' ],
        'met.l2.title'        => [ 'es'=>'Contextualización','en'=>'Contextualisation','fr'=>'Contextualisation','de'=>'Kontextualisierung','ru'=>'Контекстуализация' ],
        'met.l2.desc'         => [ 'es'=>'Convertimos los números en algo comprensible y útil. No basta con los datos: hay que entender qué significan en la vida real de cada zona.','en'=>'We turn numbers into something comprehensible and useful. Data alone is not enough: you have to understand what it means in the real life of each area.','fr'=>'Nous transformons les chiffres en quelque chose de compréhensible et d\'utile. Les données ne suffisent pas : il faut comprendre ce qu\'elles signifient dans la vie réelle de chaque zone.','de'=>'Wir verwandeln Zahlen in etwas Verständliches und Nützliches. Daten allein reichen nicht aus: Man muss verstehen, was sie im realen Leben jedes Gebiets bedeuten.','ru'=>'Мы превращаем цифры во что-то понятное и полезное. Данных недостаточно: нужно понять, что они означают в реальной жизни каждой зоны.' ],
        'met.l2.i1'           => [ 'es'=>'Cómo es la comunidad y el ambiente de la zona','en'=>'What the community and atmosphere of the area are like','fr'=>'Comment sont la communauté et l\'ambiance de la zone','de'=>'Wie die Gemeinschaft und die Atmosphäre des Gebiets sind','ru'=>'Сообщество и атмосфера района' ],
        'met.l2.i2'           => [ 'es'=>'El carácter y la vida social del entorno','en'=>'The character and social life of the environment','fr'=>'Le caractère et la vie sociale de l\'environnement','de'=>'Der Charakter und das soziale Leben des Umfelds','ru'=>'Характер и социальная жизнь окружения' ],
        'met.l2.i3'           => [ 'es'=>'Calidad de vida y percepción del entorno','en'=>'Quality of life and perception of the environment','fr'=>'Qualité de vie et perception de l\'environnement','de'=>'Lebensqualität und Wahrnehmung der Umgebung','ru'=>'Качество жизни и восприятие окружающей среды' ],
        'met.l2.i4'           => [ 'es'=>'Contexto regional y comparativa con zonas similares','en'=>'Regional context and comparison with similar areas','fr'=>'Contexte régional et comparaison avec des zones similaires','de'=>'Regionaler Kontext und Vergleich mit ähnlichen Gebieten','ru'=>'Региональный контекст и сравнение с аналогичными зонами' ],
        'met.l2.i5'           => [ 'es'=>'Seguridad percibida y ambiente real del área','en'=>'Perceived security and real atmosphere of the area','fr'=>'Sécurité perçue et atmosphère réelle de la zone','de'=>'Wahrgenommene Sicherheit und echte Atmosphäre des Bereichs','ru'=>'Воспринимаемая безопасность и реальная атмосфера района' ],
        'met.l3.title'        => [ 'es'=>'Presentación','en'=>'Presentation','fr'=>'Présentation','de'=>'Präsentation','ru'=>'Презентация' ],
        'met.l3.desc'         => [ 'es'=>'Todo lo analizado se resume en un informe claro y ordenado, entregado en el plazo acordado. Sin tecnicismos innecesarios.','en'=>'Everything analysed is summarised in a clear and ordered report, delivered within the agreed timeframe. No unnecessary jargon.','fr'=>'Tout ce qui a été analysé est résumé dans un rapport clair et ordonné, livré dans le délai convenu. Sans jargon inutile.','de'=>'Alles Analysierte wird in einem klaren und geordneten Bericht zusammengefasst, der innerhalb der vereinbarten Frist geliefert wird. Ohne unnötigen Fachjargon.','ru'=>'Всё проанализированное резюмируется в чётком и упорядоченном отчёте, доставляемом в согласованные сроки. Без лишнего жаргона.' ],
        'met.l3.i1'           => [ 'es'=>'Informe estructurado y fácil de entender','en'=>'Structured and easy-to-understand report','fr'=>'Rapport structuré et facile à comprendre','de'=>'Strukturierter und leicht verständlicher Bericht','ru'=>'Структурированный и понятный отчёт' ],
        'met.l3.i2'           => [ 'es'=>'Resumen ejecutivo con los puntos clave','en'=>'Executive summary with key points','fr'=>'Résumé exécutif avec les points clés','de'=>'Kompakte Zusammenfassung mit den wichtigsten Punkten','ru'=>'Резюме для руководства с ключевыми пунктами' ],
        'met.l3.i3'           => [ 'es'=>'Comparativa entre zonas si fuera necesario','en'=>'Area comparison if required','fr'=>'Comparaison entre zones si nécessaire','de'=>'Gebietsvergleich, falls erforderlich','ru'=>'Сравнение зон при необходимости' ],
        'met.l3.i4'           => [ 'es'=>'Conclusiones claras y directas','en'=>'Clear and direct conclusions','fr'=>'Conclusions claires et directes','de'=>'Klare und direkte Schlussfolgerungen','ru'=>'Чёткие и прямые выводы' ],
        'met.l3.i5'           => [ 'es'=>'Dossier completo entregado en el plazo acordado','en'=>'Complete dossier delivered within the agreed timeframe','fr'=>'Dossier complet livré dans le délai convenu','de'=>'Vollständiges Dossier innerhalb der vereinbarten Frist','ru'=>'Полное досье, переданное в согласованный срок' ],
        'met.filter.badge'    => [ 'es'=>'Filtro Romvill','en'=>'Romvill Filter','fr'=>'Filtre Romvill','de'=>'Romvill-Filter','ru'=>'Фильтр Romvill' ],
        'met.filter.title'    => [ 'es'=>'Convertimos datos dispersos en <span class="italic text-slate-400">criterio estratégico</span>','en'=>'We turn scattered data into <span class="italic text-slate-400">strategic insight</span>','fr'=>'Nous transformons les données dispersées en <span class="italic text-slate-400">discernement stratégique</span>','de'=>'Wir verwandeln verstreute Daten in <span class="italic text-slate-400">strategisches Urteil</span>','ru'=>'Мы превращаем разрозненные данные в <span class="italic text-slate-400">стратегическое понимание</span>' ],
        'met.filter.desc'     => [ 'es'=>'En el mercado actual, el problema no es la falta de información, sino el exceso de datos irrelevantes o sesgados. Nuestro trabajo es actuar como su analista experto.','en'=>'In today\'s market, the problem is not a lack of information, but an excess of irrelevant or biased data. Our job is to act as your expert analyst.','fr'=>'Sur le marché actuel, le problème n\'est pas le manque d\'information, mais l\'excès de données non pertinentes ou biaisées. Notre travail est d\'agir comme votre analyste expert.','de'=>'Im heutigen Markt ist das Problem nicht der Mangel an Informationen, sondern der Überschuss an irrelevanten oder voreingenommenen Daten. Unsere Aufgabe ist es, als Ihr Expertenanalyst zu fungieren.','ru'=>'На сегодняшнем рынке проблема не в нехватке информации, а в избытке нерелевантных или предвзятых данных. Наша задача — выступать вашим экспертным аналитиком.' ],
        'met.b1.title'        => [ 'es'=>'Cero Especulación','en'=>'Zero Speculation','fr'=>'Zéro Spéculation','de'=>'Null Spekulation','ru'=>'Ноль Спекуляций' ],
        'met.b1.desc'         => [ 'es'=>'Eliminamos el "me han dicho" y el "parece que". Todo lo que incluimos en el informe ha sido validado.','en'=>'We eliminate "I heard" and "it seems". Everything included in the report has been validated.','fr'=>'Nous éliminons le "on m\'a dit" et le "il semble que". Tout ce qui est inclus dans le rapport a été validé.','de'=>'Wir eliminieren das "Man hat mir gesagt" und das "Es scheint". Alles im Bericht ist validiert.','ru'=>'Мы устраняем «мне говорили» и «кажется». Всё, что включено в отчёт, прошло проверку.' ],
        'met.b2.title'        => [ 'es'=>'Trabajo de Campo Real','en'=>'Real Fieldwork','fr'=>'Travail de Terrain Réel','de'=>'Echte Feldarbeit','ru'=>'Реальная Полевая Работа' ],
        'met.b2.desc'         => [ 'es'=>'Los satélites no cuentan toda la historia. Pisamos el terreno, medimos los tiempos de acceso.','en'=>'Satellites do not tell the whole story. We walk the ground, we measure access times.','fr'=>'Les satellites ne racontent pas toute l\'histoire. Nous foulons le terrain, mesurons les temps d\'accès.','de'=>'Satelliten erzählen nicht die ganze Geschichte. Wir betreten das Gelände und messen die Zugangszeiten.','ru'=>'Спутники не рассказывают всей истории. Мы ходим по земле, измеряем время в пути.' ],
        'met.b3.title'        => [ 'es'=>'Perspectiva Independiente','en'=>'Independent Perspective','fr'=>'Perspective Indépendante','de'=>'Unabhängige Perspektive','ru'=>'Независимая Перспектива' ],
        'met.b3.desc'         => [ 'es'=>'No intermediamos en operaciones ni promocionamos zonas. Nuestro único objetivo es la radiografía exacta del lugar.','en'=>'We do not broker deals or promote areas. Our only objective is an accurate, unvarnished picture of the location.','fr'=>'Nous ne servons d\'intermédiaire dans aucune opération et ne faisons la promotion d\'aucune zone. Notre seul objectif est la radiographie exacte du lieu.','de'=>'Wir vermitteln keine Geschäfte und fördern keine Gebiete. Unser einziges Ziel ist das genaue Röntgenbild des Ortes.','ru'=>'Мы не посредничаем в сделках и не продвигаем зоны. Наша единственная цель — точный «рентгеновский снимок» места.' ],
        'met.card1.title'     => [ 'es'=>'Validación Múltiple','en'=>'Multiple Validation','fr'=>'Validation Multiple','de'=>'Mehrfachvalidierung','ru'=>'Многократная Валидация' ],
        'met.card1.desc'      => [ 'es'=>'Cruzamos hasta 5 fuentes de datos por dimensión analizada.','en'=>'We cross up to 5 data sources per analysed dimension.','fr'=>'Nous croisons jusqu\'à 5 sources de données par dimension analysée.','de'=>'Wir gleichen bis zu 5 Datenquellen pro analysierter Dimension miteinander ab.','ru'=>'Мы перекрёстно проверяем до 5 источников данных на каждое анализируемое измерение.' ],
        'met.card2.title'     => [ 'es'=>'Lo que no se ve a simple vista','en'=>'What is not visible at first sight','fr'=>'Ce qui ne se voit pas au premier coup d\'œil','de'=>'Was auf den ersten Blick nicht sichtbar ist','ru'=>'То, что не видно с первого взгляда' ],
        'met.card2.desc'      => [ 'es'=>'Detectamos los detalles del entorno que no aparecen en un anuncio pero que conviene conocer antes de decidir.','en'=>'We detect details of the environment that do not appear in a listing but are worth knowing before deciding.','fr'=>'Nous détectons les détails de l\'environnement qui n\'apparaissent pas dans une annonce mais qu\'il convient de connaître avant de décider.','de'=>'Wir erkennen Details des Umfelds, die nicht in einer Anzeige stehen, aber vor der Entscheidung wichtig sind.','ru'=>'Мы выявляем детали окружения, которые не указываются в объявлении, но которые важно знать перед принятием решения.' ],
        'met.card3.title'     => [ 'es'=>'Proyectos de futuro','en'=>'Future Projects','fr'=>'Projets d\'avenir','de'=>'Zukunftsprojekte','ru'=>'Проекты будущего' ],
        'met.card3.desc'      => [ 'es'=>'Identificamos los proyectos e infraestructuras recogidos en la planificación urbanística oficial de la zona.','en'=>'We identify the projects and infrastructure included in the official urban planning of the area.','fr'=>'Nous identifions les projets et infrastructures inscrits dans la planification urbanistique officielle de la zone.','de'=>'Wir identifizieren die Projekte und Infrastrukturen, die in der offiziellen Stadtplanung des Gebiets vorgesehen sind.','ru'=>'Мы выявляем проекты и инфраструктуру, предусмотренные в официальной градостроительной документации зоны.' ],
        'met.obj_badge'       => [ 'es'=>'Objetividad','en'=>'Objectivity','fr'=>'Objectivité','de'=>'Objektivität','ru'=>'Объективность' ],
        'met.cta.title'       => [ 'es'=>'¿Tiene preguntas sobre cómo trabajamos?','en'=>'Do you have questions about how we work?','fr'=>'Avez-vous des questions sur notre façon de travailler ?','de'=>'Haben Sie Fragen zu unserer Arbeitsweise?','ru'=>'Есть ли у вас вопросы о том, как мы работаем?' ],
        'met.cta.desc'        => [ 'es'=>'Si quiere saber más sobre cómo elaboramos los informes o tiene preguntas concretas sobre su caso, estamos para ayudarle.','en'=>'If you want to know more about how we prepare the reports or have specific questions about your case, we are here to help.','fr'=>'Si vous souhaitez en savoir plus sur la façon dont nous élaborons les rapports ou si vous avez des questions précises sur votre cas, nous sommes là pour vous aider.','de'=>'Wenn Sie mehr darüber erfahren möchten, wie wir die Berichte erstellen, oder konkrete Fragen zu Ihrem Fall haben, sind wir hier, um zu helfen.','ru'=>'Если вы хотите узнать больше о том, как мы готовим отчёты, или у вас есть конкретные вопросы о вашем случае — мы здесь, чтобы помочь.' ],
        'met.cta.btn'         => [ 'es'=>'Hablar con nosotros','en'=>'Talk to us','fr'=>'Parler avec nous','de'=>'Mit uns sprechen','ru'=>'Поговорить с нами' ],

