        // ── ANÁLISIS PAGE ─────────────────────────────────────────
        'ana.badge'           => [ 'es'=>'Inteligencia Territorial','en'=>'Territorial Intelligence','fr'=>'Intelligence Territoriale','de'=>'Territoriale Standortanalyse','ru'=>'Территориальная Аналитика' ],
        'ana.title'           => [ 'es'=>'Lo que analizamos <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-secondary to-[#9A7529]">para que usted decida con seguridad</span>','en'=>'What we analyse <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-secondary to-[#9A7529]">so you decide with confidence</span>','fr'=>'Ce que nous analysons <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-secondary to-[#9A7529]">pour que vous décidiez en toute sécurité</span>','de'=>'Was wir analysieren <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-secondary to-[#9A7529]">damit Sie sicher entscheiden</span>','ru'=>'Что мы анализируем <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-secondary to-[#9A7529]">чтобы вы решали уверенно</span>' ],
        'ana.desc'            => [ 'es'=>'Antes de mudarse o dar cualquier paso importante, Romvill estudia a fondo la zona que le interesa: seguridad real, quién vive allí, qué servicios tiene y cómo es moverse por esa área.','en'=>'Before moving or taking any important step, Romvill thoroughly studies the area that interests you: real security, who lives there, what services it has and what it is like to get around that area.','fr'=>'Avant de déménager ou de prendre toute décision importante, Romvill étudie en profondeur la zone qui vous intéresse : sécurité réelle, qui y vit, quels services elle offre et comment on s\'y déplace.','de'=>'Bevor Sie umziehen oder einen wichtigen Schritt unternehmen, untersucht Romvill gründlich das Gebiet, das Sie interessiert: echte Sicherheit, wer dort lebt, welche Dienstleistungen es gibt und wie man sich dort im Alltag bewegt.','ru'=>'Прежде чем переехать или сделать важный шаг, Romvill тщательно изучает интересующую вас зону: реальная безопасность, кто там живёт, какие есть услуги и как передвигаться по этому району.' ],
        'ana.d1.title'        => [ 'es'=>'Seguridad de la Zona','en'=>'Security of the Area','fr'=>'Sécurité de la Zone','de'=>'Sicherheit des Gebiets','ru'=>'Безопасность Зоны' ],
        'ana.d1.desc'         => [ 'es'=>'No nos basamos en rumores ni en apariencias. Analizamos la seguridad de la zona combinando información contrastada con la comprobación directa del ambiente sobre el terreno.','en'=>'We do not rely on rumours or appearances. We analyse the security of the area by combining verified information with direct verification of the atmosphere on the ground.','fr'=>'Nous ne nous basons pas sur des rumeurs ou des apparences. Nous analysons la sécurité de la zone en combinant des informations recoupées avec la vérification directe de l\'ambiance sur le terrain.','de'=>'Wir verlassen uns nicht auf Gerüchte oder den äußeren Anschein. Wir analysieren die Sicherheit des Gebiets, indem wir gegengeprüfte Informationen mit der direkten Überprüfung der Atmosphäre vor Ort verbinden.','ru'=>'Мы не полагаемся на слухи или внешний вид. Мы анализируем безопасность зоны, сочетая проверенную информацию с непосредственной проверкой атмосферы на месте.' ],
        'ana.d1.i1'           => [ 'es'=>'Análisis documental de fuentes solventes','en'=>'Documentary analysis of reliable sources','fr'=>'Analyse documentaire de sources fiables','de'=>'Dokumentenanalyse verlässlicher Quellen','ru'=>'Документальный анализ надёжных источников' ],
        'ana.d1.i2'           => [ 'es'=>'Reconocimiento presencial del entorno','en'=>'On-site assessment of the environment','fr'=>'Reconnaissance sur place de l\'environnement','de'=>'Begehung des Umfelds vor Ort','ru'=>'Личное обследование окружения' ],
        'ana.d1.link'         => [ 'es'=>'Ver Perfil de Seguridad','en'=>'See Security Profile','fr'=>'Voir Profil de Sécurité','de'=>'Sicherheitsprofil ansehen','ru'=>'Просмотреть Профиль Безопасности' ],
        'ana.d2.title'        => [ 'es'=>'Perfil Demográfico','en'=>'Demographic Profile','fr'=>'Profil Démographique','de'=>'Demografisches Profil','ru'=>'Демографический Профиль' ],
        'ana.d2.desc'         => [ 'es'=>'Conocer el entorno humano de la zona es esencial. Elaboramos un perfil preciso de cómo es la comunidad que la habita.','en'=>'Knowing the human environment of the area is essential. We draw up a precise profile of what the community that inhabits it is like.','fr'=>'Connaître l\'environnement humain de la zone est essentiel. Nous établissons un profil précis de ce qu\'est la communauté qui l\'habite.','de'=>'Das menschliche Umfeld des Gebiets zu kennen ist wesentlich. Wir erstellen ein genaues Profil davon, wie die Gemeinschaft ist, die es bewohnt.','ru'=>'Понимать, кто живёт в районе, крайне важно. Мы составляем точный портрет местного сообщества.' ],
        'ana.d2.i1'           => [ 'es'=>'Composición familiar y edad media','en'=>'Family composition and average age','fr'=>'Composition familiale et âge moyen','de'=>'Familienzusammensetzung und Durchschnittsalter','ru'=>'Состав семей и средний возраст' ],
        'ana.d2.i2'           => [ 'es'=>'Evolución de la población local','en'=>'Evolution of the local population','fr'=>'Évolution de la population locale','de'=>'Entwicklung der lokalen Bevölkerung','ru'=>'Динамика местного населения' ],
        'ana.d2.link'         => [ 'es'=>'Ver Perfil Demográfico','en'=>'See Demographic Profile','fr'=>'Voir Profil Démographique','de'=>'Demografisches Profil ansehen','ru'=>'Просмотреть Демографический Профиль' ],
        'ana.d3.title'        => [ 'es'=>'Cobertura Sanitaria','en'=>'Healthcare Coverage','fr'=>'Couverture Sanitaire','de'=>'Gesundheitsversorgung','ru'=>'Охват Здравоохранения' ],
        'ana.d3.desc'         => [ 'es'=>'La salud y las emergencias no pueden depender del azar. Mapeamos la disponibilidad y calidad de los servicios médicos cercanos.','en'=>'Health and emergencies cannot depend on chance. We map the availability and quality of nearby medical services.','fr'=>'La santé et les urgences ne peuvent pas dépendre du hasard. Nous cartographions la disponibilité et la qualité des services médicaux proches.','de'=>'Gesundheit und Notfälle können nicht vom Zufall abhängen. Wir kartieren die Verfügbarkeit und Qualität nahegelegener medizinischer Dienste.','ru'=>'Здоровье и экстренные ситуации не могут зависеть от случая. Мы составляем карту доступности и качества ближайших медицинских услуг.' ],
        'ana.d3.i1'           => [ 'es'=>'Infraestructura pública y privada','en'=>'Public and private infrastructure','fr'=>'Infrastructure publique et privée','de'=>'Öffentliche und private Infrastruktur','ru'=>'Государственная и частная инфраструктура' ],
        'ana.d3.i2'           => [ 'es'=>'Distancias clínicas y accesibilidad','en'=>'Distances to medical centres and accessibility','fr'=>'Distances aux centres médicaux et accessibilité','de'=>'Entfernungen zu Kliniken und Erreichbarkeit','ru'=>'Расстояния до клиник и доступность' ],
        'ana.d3.link'         => [ 'es'=>'Ver Perfil de Sanidad','en'=>'See Healthcare Profile','fr'=>'Voir Profil de Santé','de'=>'Gesundheitsprofil ansehen','ru'=>'Просмотреть Профиль Здравоохранения' ],
        'ana.d4.title'        => [ 'es'=>'Conectividad y Movilidad','en'=>'Connectivity and Mobility','fr'=>'Connectivité et Mobilité','de'=>'Konnektivität und Mobilität','ru'=>'Связность и Мобильность' ],
        'ana.d4.desc'         => [ 'es'=>'El tiempo es oro. Estudiamos las arterias de la zona: accesos por carretera, tráfico real en horas punta, opciones de transporte público.','en'=>'Your time matters. We study the area\'s arteries: road access, real peak-hour traffic and public transport options.','fr'=>'Votre temps est précieux. Nous étudions les artères de la zone : accès routiers, trafic réel aux heures de pointe, options de transport en commun.','de'=>'Zeit ist kostbar. Wir untersuchen die Verkehrsadern des Gebiets: Straßenanbindung, realen Verkehr zu Stoßzeiten und die Angebote des öffentlichen Nahverkehrs.','ru'=>'Время — золото. Мы изучаем артерии зоны: дорожные подъезды, реальный трафик в час пик, варианты общественного транспорта.' ],
        'ana.d4.i1'           => [ 'es'=>'Nudos de transporte y aparcamiento','en'=>'Transport hubs and parking','fr'=>'Noeuds de transport et stationnement','de'=>'Verkehrsknotenpunkte und Parken','ru'=>'Транспортные узлы и парковка' ],
        'ana.d4.i2'           => [ 'es'=>'Nivel de congestión residencial','en'=>'Residential congestion level','fr'=>'Niveau de congestion résidentielle','de'=>'Verkehrsaufkommen im Wohnumfeld','ru'=>'Уровень жилой загруженности' ],
        'ana.d4.link'         => [ 'es'=>'Ver Perfil de Movilidad','en'=>'See Mobility Profile','fr'=>'Voir Profil de Mobilité','de'=>'Mobilitätsprofil ansehen','ru'=>'Просмотреть Профиль Мобильности' ],
        'ana.dim'             => [ 'es'=>'Dimensión','en'=>'Dimension','fr'=>'Dimension','de'=>'Dimension','ru'=>'Измерение' ],
        'ana.cta.title'       => [ 'es'=>'Un informe hecho para usted','en'=>'A report made for you','fr'=>'Un rapport fait pour vous','de'=>'Ein Bericht für Sie gemacht','ru'=>'Отчёт, сделанный для вас' ],
        'ana.cta.desc'        => [ 'es'=>'No entregamos datos sueltos ni informes genéricos. Reunimos todo lo anterior —seguridad, vecindario, servicios y movilidad— en un único informe claro y a su medida, para que entienda de verdad cómo es la zona antes de dar el paso.','en'=>'We don\'t hand you scattered data or generic reports. We bring everything above —safety, neighbourhood, services and mobility— together into a single clear report, tailored to you, so you truly understand what the area is like before taking the step.','fr'=>'Nous ne livrons pas de données éparses ni de rapports génériques. Nous réunissons tout ce qui précède —sécurité, voisinage, services et mobilité— dans un seul rapport clair et sur mesure, pour que vous compreniez vraiment comment est la zone avant de franchir le pas.','de'=>'Wir liefern keine losen Daten oder generischen Berichte. Wir führen alles Vorherige —Sicherheit, Nachbarschaft, Dienstleistungen und Mobilität— in einem einzigen klaren Bericht zusammen, auf Sie zugeschnitten, damit Sie wirklich verstehen, wie das Gebiet ist, bevor Sie den Schritt wagen.','ru'=>'Мы не выдаём разрозненные данные или шаблонные отчёты. Мы объединяем всё перечисленное —безопасность, окружение, услуги и мобильность— в один понятный отчёт, созданный лично для вас, чтобы вы действительно понимали, какая это зона, прежде чем сделать шаг.' ],
        'ana.cta.btn'         => [ 'es'=>'Solicitar Informe','en'=>'Request Report','fr'=>'Demander le Rapport','de'=>'Bericht anfordern','ru'=>'Запросить Отчёт' ],

        // ── PERFILES DE DIMENSIÓN (común) ─────────────────────────
        'perfil.volver'       => [ 'es'=>'Volver a Análisis','en'=>'Back to Analysis','fr'=>'Retour à l\'Analyse','de'=>'Zurück zur Analyse','ru'=>'Назад к Анализу' ],

        // ── PERFIL DE SEGURIDAD PAGE ──────────────────────────────
        'perfil.seg.h1'       => [ 'es'=>'Perfil de Seguridad','en'=>'Security Profile','fr'=>'Profil de Sécurité','de'=>'Sicherheitsprofil','ru'=>'Профиль Безопасности' ],
        'perfil.seg.cta'      => [ 'es'=>'Solicitar Análisis de Seguridad','en'=>'Request Security Analysis','fr'=>'Demander l\'Analyse de Sécurité','de'=>'Sicherheitsanalyse anfordern','ru'=>'Запросить Анализ Безопасности' ],
        'perfil.seg.intro'    => [ 'es'=>'La seguridad de una zona no se mide por su apariencia. La estudiamos combinando información contrastada con observación directa sobre el terreno.','en'=>'The security of an area is not measured by its appearance. We study it by combining verified information with direct observation on the ground.','fr'=>'La sécurité d\'une zone ne se mesure pas à son apparence. Nous l\'étudions en combinant des informations recoupées avec l\'observation directe sur le terrain.','de'=>'Die Sicherheit eines Gebiets wird nicht an seinem Erscheinungsbild gemessen. Wir untersuchen sie, indem wir gegengeprüfte Informationen mit direkter Beobachtung vor Ort verbinden.','ru'=>'Безопасность зоны не измеряется её внешним видом. Мы изучаем её, сочетая проверенную информацию с непосредственным наблюдением на месте.' ],
        'perfil.seg.c1.title' => [ 'es'=>'Seguridad del entorno','en'=>'Security of the environment','fr'=>'Sécurité de l\'environnement','de'=>'Sicherheit des Umfelds','ru'=>'Безопасность окружения' ],
        'perfil.seg.c1.desc'  => [ 'es'=>'Estudiamos el contexto de seguridad de cada barrio o urbanización a partir de información contrastada y del trabajo sobre el terreno.','en'=>'We study the security context of each neighbourhood or development based on verified information and on-the-ground work.','fr'=>'Nous étudions le contexte de sécurité de chaque quartier ou résidence à partir d\'informations recoupées et du travail sur le terrain.','de'=>'Wir untersuchen den Sicherheitskontext jedes Viertels oder jeder Wohnanlage anhand gegengeprüfter Informationen und der Arbeit vor Ort.','ru'=>'Мы изучаем контекст безопасности каждого района или жилого комплекса на основе проверенной информации и работы на месте.' ],
        'perfil.seg.c2.title' => [ 'es'=>'Ambiente y convivencia','en'=>'Atmosphere and coexistence','fr'=>'Ambiance et cohabitation','de'=>'Atmosphäre und Zusammenleben','ru'=>'Атмосфера и добрососедство' ],
        'perfil.seg.c2.desc'  => [ 'es'=>'Recogemos cómo perciben el entorno quienes ya viven en la zona: el ambiente cotidiano, la convivencia y la tranquilidad del día a día.','en'=>'We gather how those who already live in the area perceive their environment: the everyday atmosphere, coexistence and the calm of daily life.','fr'=>'Nous recueillons la façon dont perçoivent leur environnement ceux qui vivent déjà dans la zone : l\'ambiance quotidienne, la cohabitation et la tranquillité au jour le jour.','de'=>'Wir erfassen, wie diejenigen, die bereits in dem Gebiet leben, ihr Umfeld wahrnehmen: die alltägliche Atmosphäre, das Zusammenleben und die Ruhe des Alltags.','ru'=>'Мы собираем, как воспринимают окружение те, кто уже живёт в зоне: повседневную атмосферу, добрососедство и спокойствие будней.' ],
        'perfil.seg.c3.title' => [ 'es'=>'Entorno y servicios de proximidad','en'=>'Surroundings and local services','fr'=>'Environnement et services de proximité','de'=>'Umgebung und Nahdienste','ru'=>'Окружение и услуги поблизости' ],
        'perfil.seg.c3.desc'  => [ 'es'=>'Observamos elementos del entorno que influyen en la tranquilidad: iluminación, mantenimiento de las calles y servicios cercanos.','en'=>'We observe elements of the surroundings that affect peace of mind: lighting, street maintenance and nearby services.','fr'=>'Nous observons des éléments de l\'environnement qui influent sur la tranquillité : éclairage, entretien des rues et services à proximité.','de'=>'Wir beobachten Elemente der Umgebung, die die Ruhe beeinflussen: Beleuchtung, Instandhaltung der Straßen und nahegelegene Dienste.','ru'=>'Мы наблюдаем элементы окружения, влияющие на спокойствие: освещение, содержание улиц и близлежащие услуги.' ],
        'perfil.seg.c4.title' => [ 'es'=>'Aspectos a tener en cuenta','en'=>'Aspects to bear in mind','fr'=>'Aspects à prendre en compte','de'=>'Zu berücksichtigende Aspekte','ru'=>'Аспекты, которые стоит учесть' ],
        'perfil.seg.c4.desc'  => [ 'es'=>'Señalamos aspectos del entorno cercano que conviene conocer y que pueden influir en su tranquilidad y en su decisión.','en'=>'We point out aspects of the nearby environment worth knowing that may affect your peace of mind and your decision.','fr'=>'Nous signalons des aspects de l\'environnement proche qu\'il convient de connaître et qui peuvent influer sur votre tranquillité et votre décision.','de'=>'Wir weisen auf Aspekte des näheren Umfelds hin, die man kennen sollte und die Ihre Ruhe und Ihre Entscheidung beeinflussen können.','ru'=>'Мы указываем на аспекты ближайшего окружения, которые стоит знать и которые могут повлиять на ваше спокойствие и ваше решение.' ],

        // ── PERFIL DEMOGRÁFICO PAGE ───────────────────────────────
        'perfil.dem.h1'       => [ 'es'=>'Perfil Demográfico','en'=>'Demographic Profile','fr'=>'Profil Démographique','de'=>'Demografisches Profil','ru'=>'Демографический Профиль' ],
        'perfil.dem.cta'      => [ 'es'=>'Solicitar Análisis Demográfico','en'=>'Request Demographic Analysis','fr'=>'Demander l\'Analyse Démographique','de'=>'Demografische Analyse anfordern','ru'=>'Запросить Демографический Анализ' ],
        'perfil.dem.intro'    => [ 'es'=>'Le mostramos cómo es la comunidad de la zona: familias, profesionales, jubilados y población de temporada. El carácter humano del entorno donde va a vivir.','en'=>'We show you what the community of the area is like: families, professionals, retirees and seasonal population. The human character of the environment where you are going to live.','fr'=>'Nous vous montrons comment est la communauté de la zone : familles, professionnels, retraités et population saisonnière. Le caractère humain de l\'environnement où vous allez vivre.','de'=>'Wir zeigen Ihnen, wie die Gemeinschaft des Gebiets ist: Familien, Berufstätige, Rentner und Saisonbevölkerung. Der menschliche Charakter des Umfelds, in dem Sie leben werden.','ru'=>'Мы показываем, каково сообщество района: семьи, специалисты, пенсионеры и сезонные жители. Человеческий облик места, где вам предстоит жить.' ],
        'perfil.dem.c1.title' => [ 'es'=>'Composición de la comunidad','en'=>'Composition of the community','fr'=>'Composition de la communauté','de'=>'Zusammensetzung der Gemeinschaft','ru'=>'Состав сообщества' ],
        'perfil.dem.c1.desc'  => [ 'es'=>'La edad media de la zona, la presencia de familias y la proporción entre quienes residen todo el año y la población de temporada.','en'=>'The average age of the area, the presence of families and the proportion between year-round residents and the seasonal population.','fr'=>'L\'âge moyen de la zone, la présence de familles et la proportion entre les résidents à l\'année et la population saisonnière.','de'=>'Das Durchschnittsalter des Gebiets, die Präsenz von Familien und das Verhältnis zwischen ganzjährigen Bewohnern und der Saisonbevölkerung.','ru'=>'Средний возраст зоны, наличие семей и соотношение между круглогодичными жителями и сезонным населением.' ],
        'perfil.dem.c2.title' => [ 'es'=>'Perfil económico de la zona','en'=>'Economic profile of the area','fr'=>'Profil économique de la zone','de'=>'Wirtschaftliches Profil des Gebiets','ru'=>'Экономический профиль зоны' ],
        'perfil.dem.c2.desc'  => [ 'es'=>'El nivel de renta general del área y el tipo de actividad económica que predomina, para que entienda el perfil del entorno y su evolución.','en'=>'The general income level of the area and the type of economic activity that predominates, so you understand the profile of the environment and its evolution.','fr'=>'Le niveau de revenu général de la zone et le type d\'activité économique qui prédomine, afin que vous compreniez le profil de l\'environnement et son évolution.','de'=>'Das allgemeine Einkommensniveau des Gebiets und die vorherrschende Art wirtschaftlicher Aktivität, damit Sie das Profil des Umfelds und seine Entwicklung verstehen.','ru'=>'Общий уровень доходов района и преобладающий тип экономической деятельности, чтобы вы поняли профиль окружения и его развитие.' ],
        'perfil.dem.c3.title' => [ 'es'=>'Evolución de la zona','en'=>'Evolution of the area','fr'=>'Évolution de la zone','de'=>'Entwicklung des Gebiets','ru'=>'Развитие зоны' ],
        'perfil.dem.c3.desc'  => [ 'es'=>'Cómo ha evolucionado el entorno en los últimos años: si la población crece o disminuye, si se renueva con gente nueva o si tiende a envejecer, y hacia dónde apunta esa tendencia.','en'=>'How the environment has evolved in recent years: whether the population grows or shrinks, whether it is renewed with new people or tends to age, and where that trend is heading.','fr'=>'Comment l\'environnement a évolué ces dernières années : si la population augmente ou diminue, si elle se renouvelle avec de nouvelles personnes ou tend à vieillir, et vers où se dirige cette tendance.','de'=>'Wie sich das Umfeld in den letzten Jahren entwickelt hat: ob die Bevölkerung wächst oder schrumpft, ob sie sich mit neuen Menschen erneuert oder zur Alterung neigt, und wohin dieser Trend zeigt.','ru'=>'Как окружение развивалось в последние годы: растёт ли население или сокращается, обновляется ли новыми людьми или склонно стареть, и куда движется эта тенденция.' ],
        'perfil.dem.c4.title' => [ 'es'=>'Comunidad internacional','en'=>'International community','fr'=>'Communauté internationale','de'=>'Internationale Gemeinschaft','ru'=>'Международное сообщество' ],
        'perfil.dem.c4.desc'  => [ 'es'=>'La presencia de residentes extranjeros en la zona, las nacionalidades con mayor arraigo y las comunidades ya establecidas, útil si busca un entorno con personas de su mismo origen o idioma.','en'=>'The presence of foreign residents in the area, the most established nationalities and the communities already settled, useful if you are looking for an environment with people of your own origin or language.','fr'=>'La présence de résidents étrangers dans la zone, les nationalités les plus enracinées et les communautés déjà établies, utile si vous recherchez un environnement avec des personnes de votre origine ou de votre langue.','de'=>'Die Präsenz ausländischer Bewohner in dem Gebiet, die am stärksten verwurzelten Nationalitäten und die bereits etablierten Gemeinschaften, nützlich, wenn Sie ein Umfeld mit Menschen Ihrer eigenen Herkunft oder Sprache suchen.','ru'=>'Присутствие иностранных жителей в зоне, наиболее укоренившиеся национальности и уже сложившиеся сообщества — полезно, если вы ищете окружение с людьми вашего же происхождения или языка.' ],

        // ── PERFIL DE SANIDAD PAGE ────────────────────────────────
        'perfil.san.h1'       => [ 'es'=>'Perfil de Sanidad','en'=>'Healthcare Profile','fr'=>'Profil de Santé','de'=>'Gesundheitsprofil','ru'=>'Профиль Здравоохранения' ],
        'perfil.san.cta'      => [ 'es'=>'Solicitar Análisis Sanitario','en'=>'Request Healthcare Analysis','fr'=>'Demander l\'Analyse Sanitaire','de'=>'Gesundheitsanalyse anfordern','ru'=>'Запросить Анализ Здравоохранения' ],
        'perfil.san.intro'    => [ 'es'=>'Analizamos la infraestructura sanitaria accesible desde la zona: hospitales, centros de salud, farmacias y tiempos de acceso a urgencias.','en'=>'We analyse the healthcare infrastructure accessible from the area: hospitals, health centres, pharmacies and emergency access times.','fr'=>'Nous analysons l\'infrastructure sanitaire accessible depuis la zone : hôpitaux, centres de santé, pharmacies et temps d\'accès aux urgences.','de'=>'Wir analysieren die vom Gebiet aus zugängliche Gesundheitsinfrastruktur: Krankenhäuser, Gesundheitszentren, Apotheken und Zugangszeiten zur Notaufnahme.','ru'=>'Мы анализируем доступную из зоны медицинскую инфраструктуру: больницы, медицинские центры, аптеки и время доступа к неотложной помощи.' ],
        'perfil.san.c1.title' => [ 'es'=>'Red hospitalaria','en'=>'Hospital network','fr'=>'Réseau hospitalier','de'=>'Krankenhausnetz','ru'=>'Сеть больниц' ],
        'perfil.san.c1.desc'  => [ 'es'=>'Distancia y tiempo de acceso a los hospitales más cercanos (públicos y privados), especialidades disponibles y nivel de saturación.','en'=>'Distance and access time to the nearest hospitals (public and private), available specialities and level of saturation.','fr'=>'Distance et temps d\'accès aux hôpitaux les plus proches (publics et privés), spécialités disponibles et niveau de saturation.','de'=>'Entfernung und Zugangszeit zu den nächstgelegenen Krankenhäusern (öffentlich und privat), verfügbare Fachrichtungen und Auslastungsgrad.','ru'=>'Расстояние и время в пути до ближайших больниц (государственных и частных), доступные специализации и уровень загруженности.' ],
        'perfil.san.c2.title' => [ 'es'=>'Atención primaria','en'=>'Primary care','fr'=>'Soins de proximité','de'=>'Hausärztliche Versorgung','ru'=>'Первичная медицинская помощь' ],
        'perfil.san.c2.desc'  => [ 'es'=>'Centros de salud asignados, disponibilidad de citas, ratio médico-paciente y valoración de los profesionales.','en'=>'Assigned health centres, appointment availability, doctor-to-patient ratio and how the professionals are rated.','fr'=>'Centres de santé de rattachement, disponibilité des rendez-vous, ratio médecin-patient et évaluation des professionnels.','de'=>'Zugewiesene Gesundheitszentren, Terminverfügbarkeit, Arzt-Patienten-Verhältnis und Bewertung der Fachkräfte.','ru'=>'Закреплённые медицинские центры, доступность записи, соотношение врачей и пациентов и оценки специалистов.' ],
        'perfil.san.c3.title' => [ 'es'=>'Farmacias y urgencias','en'=>'Pharmacies and emergencies','fr'=>'Pharmacies et urgences','de'=>'Apotheken und Notdienste','ru'=>'Аптеки и неотложная помощь' ],
        'perfil.san.c3.desc'  => [ 'es'=>'Farmacias de guardia, servicios de urgencias 24h cercanos y tiempo estimado de respuesta de emergencias.','en'=>'On-duty pharmacies, nearby 24-hour emergency services and estimated emergency response times.','fr'=>'Pharmacies de garde, services d\'urgence 24h/24 à proximité et temps de réponse estimé des secours.','de'=>'Notdienst-Apotheken, nahegelegene 24-Stunden-Notaufnahmen und geschätzte Reaktionszeit der Rettungsdienste.','ru'=>'Дежурные аптеки, круглосуточные службы неотложной помощи поблизости и расчётное время реагирования экстренных служб.' ],
        'perfil.san.c4.title' => [ 'es'=>'Servicios especializados','en'=>'Specialised services','fr'=>'Services spécialisés','de'=>'Spezialisierte Leistungen','ru'=>'Специализированные услуги' ],
        'perfil.san.c4.desc'  => [ 'es'=>'Centros geriátricos, rehabilitación, pediatría especializada y otros servicios médicos relevantes para el perfil del residente.','en'=>'Geriatric centres, rehabilitation, specialised paediatrics and other medical services relevant to the resident\'s profile.','fr'=>'Centres gériatriques, rééducation, pédiatrie spécialisée et autres services médicaux pertinents selon le profil du résident.','de'=>'Geriatrische Zentren, Rehabilitation, spezialisierte Pädiatrie und weitere medizinische Leistungen, die für das Profil des Bewohners relevant sind.','ru'=>'Гериатрические центры, реабилитация, специализированная педиатрия и другие медицинские услуги, значимые для профиля резидента.' ],

        // ── PERFIL DE MOVILIDAD PAGE ──────────────────────────────
        'perfil.mov.h1'       => [ 'es'=>'Perfil de Movilidad','en'=>'Mobility Profile','fr'=>'Profil de Mobilité','de'=>'Mobilitätsprofil','ru'=>'Профиль Мобильности' ],
        'perfil.mov.cta'      => [ 'es'=>'Solicitar Análisis de Movilidad','en'=>'Request Mobility Analysis','fr'=>'Demander l\'Analyse de Mobilité','de'=>'Mobilitätsanalyse anfordern','ru'=>'Запросить Анализ Мобильности' ],
        'perfil.mov.intro'    => [ 'es'=>'Estudiamos cómo se mueve la zona: accesos por carretera, transporte público, aparcamiento y tiempos reales de desplazamiento.','en'=>'We study how the area moves: road access, public transport, parking and real travel times.','fr'=>'Nous étudions comment la zone se déplace : accès routiers, transports en commun, stationnement et temps de trajet réels.','de'=>'Wir untersuchen, wie sich das Gebiet bewegt: Straßenanbindung, öffentlicher Nahverkehr, Parken und reale Fahrzeiten.','ru'=>'Мы изучаем, как устроено передвижение по зоне: дорожные подъезды, общественный транспорт, парковка и реальное время в пути.' ],
        'perfil.mov.c1.title' => [ 'es'=>'Accesos por carretera','en'=>'Road access','fr'=>'Accès routiers','de'=>'Straßenanbindung','ru'=>'Дорожные подъезды' ],
        'perfil.mov.c1.desc'  => [ 'es'=>'Autopistas, autovías y carreteras principales conectadas con la zona. Tiempos de acceso al aeropuerto y a las ciudades cercanas.','en'=>'Motorways, dual carriageways and main roads connected to the area. Access times to the airport and nearby cities.','fr'=>'Autoroutes, voies rapides et routes principales reliées à la zone. Temps d\'accès à l\'aéroport et aux villes proches.','de'=>'Autobahnen, Schnellstraßen und Hauptstraßen mit Anschluss an das Gebiet. Fahrzeiten zum Flughafen und zu den nahegelegenen Städten.','ru'=>'Автомагистрали, скоростные и основные дороги, связанные с зоной. Время в пути до аэропорта и ближайших городов.' ],
        'perfil.mov.c2.title' => [ 'es'=>'Transporte público','en'=>'Public transport','fr'=>'Transports en commun','de'=>'Öffentlicher Nahverkehr','ru'=>'Общественный транспорт' ],
        'perfil.mov.c2.desc'  => [ 'es'=>'Paradas de autobús, estaciones de tren, metro o tranvía cercanas, frecuencias de paso, calidad del servicio, etc.','en'=>'Nearby bus stops, train, metro or tram stations, service frequencies, quality of service, etc.','fr'=>'Arrêts de bus, gares de train, métro ou tramway à proximité, fréquences de passage, qualité du service, etc.','de'=>'Nahe Bushaltestellen, Bahn-, U-Bahn- oder Straßenbahnstationen, Taktfrequenzen, Servicequalität usw.','ru'=>'Близлежащие автобусные остановки, станции поездов, метро или трамвая, частота движения, качество обслуживания и т. д.' ],
        'perfil.mov.c3.title' => [ 'es'=>'Aparcamiento','en'=>'Parking','fr'=>'Stationnement','de'=>'Parken','ru'=>'Парковка' ],
        'perfil.mov.c3.desc'  => [ 'es'=>'Disponibilidad de aparcamiento público y privado, coste medio, facilidad para encontrar sitio y opciones de estacionamiento en el entorno, entre otros aspectos.','en'=>'Availability of public and private parking, average cost, ease of finding a spot and parking options in the surroundings, among other aspects.','fr'=>'Disponibilité de stationnement public et privé, coût moyen, facilité à trouver une place et options de stationnement dans les environs, entre autres aspects.','de'=>'Verfügbarkeit öffentlicher und privater Parkplätze, Durchschnittskosten, einfaches Finden eines Platzes und Parkmöglichkeiten in der Umgebung, unter anderem.','ru'=>'Наличие общественной и частной парковки, средняя стоимость, лёгкость найти место и варианты стоянки поблизости, среди прочих аспектов.' ],
        'perfil.mov.c4.title' => [ 'es'=>'Tiempos de desplazamiento','en'=>'Travel times','fr'=>'Temps de trajet','de'=>'Reisezeiten','ru'=>'Время в пути' ],
        'perfil.mov.c4.desc'  => [ 'es'=>'Medimos cuánto se tarda hasta los puntos clave de la zona: trabajo, colegios, hospitales, playa, etc.','en'=>'We measure how long it takes to reach the key points of the area: work, schools, hospitals, beach, etc.','fr'=>'Nous mesurons le temps nécessaire pour atteindre les points clés de la zone : travail, écoles, hôpitaux, plage, etc.','de'=>'Wir messen, wie lange man bis zu den wichtigsten Punkten des Gebiets braucht: Arbeit, Schulen, Krankenhäuser, Strand usw.','ru'=>'Мы измеряем, сколько времени нужно, чтобы добраться до ключевых точек зоны: работа, школы, больницы, пляж и т. д.' ],

        // ── PERFIL DE PROYECCIÓN PAGE ─────────────────────────────
        'perfil.pro.h1'       => [ 'es'=>'Perfil de Proyección','en'=>'Projection Profile','fr'=>'Profil de Projection','de'=>'Zukunftsprognose-Profil','ru'=>'Профиль Будущего Развития' ],
        'perfil.pro.cta'      => [ 'es'=>'Solicitar Análisis de Proyección','en'=>'Request Projection Analysis','fr'=>'Demander l\'Analyse de Projection','de'=>'Zukunftsanalyse anfordern','ru'=>'Запросить Анализ Будущего Развития' ],
        'perfil.pro.intro'    => [ 'es'=>'Analizamos hacia dónde va la zona: obras previstas, inversión pública y planes urbanísticos aprobados que cambiarán su entorno — hechos documentados, sin especular con precios.','en'=>'We analyse where the area is heading: planned works, public investment and approved urban plans that will change its surroundings — documented facts, with no price speculation.','fr'=>'Nous analysons où va la zone : travaux prévus, investissement public et plans d\'urbanisme approuvés qui transformeront son environnement — des faits documentés, sans spéculer sur les prix.','de'=>'Wir analysieren, wohin sich das Gebiet entwickelt: geplante Bauvorhaben, öffentliche Investitionen und genehmigte Bebauungspläne, die das Umfeld verändern werden — dokumentierte Fakten, ohne Preisspekulation.','ru'=>'Мы анализируем, куда движется зона: запланированные работы, государственные инвестиции и утверждённые градостроительные планы, которые изменят её облик, — документированные факты, без спекуляций о ценах.' ],
        'perfil.pro.c1.title' => [ 'es'=>'Evolución del mercado','en'=>'Market evolution','fr'=>'Évolution du marché','de'=>'Marktentwicklung','ru'=>'Динамика рынка' ],
        'perfil.pro.c1.desc'  => [ 'es'=>'Evolución histórica de precios y tendencia actual del mercado, descrita con datos oficiales — sin proyecciones ni promesas de revalorización.','en'=>'Historical price evolution and the current market trend, described with official data — no forecasts, no promises of appreciation.','fr'=>'Évolution historique des prix et tendance actuelle du marché, décrites à partir de données officielles — sans projections ni promesses de plus-value.','de'=>'Historische Preisentwicklung und aktueller Markttrend, beschrieben anhand offizieller Daten — ohne Prognosen und ohne Wertsteigerungsversprechen.','ru'=>'Историческая динамика цен и текущая тенденция рынка — по официальным данным, без прогнозов и обещаний роста стоимости.' ],
        'perfil.pro.c2.title' => [ 'es'=>'Proyectos urbanísticos','en'=>'Urban development projects','fr'=>'Projets d\'urbanisme','de'=>'Städtebauprojekte','ru'=>'Градостроительные проекты' ],
        'perfil.pro.c2.desc'  => [ 'es'=>'Obras previstas, nuevas infraestructuras, cambios en el PGOU y desarrollos que afectarán la zona a medio plazo.','en'=>'Planned works, new infrastructure, changes to the municipal master plan (PGOU) and developments that will affect the area in the medium term.','fr'=>'Travaux prévus, nouvelles infrastructures, modifications du plan d\'urbanisme municipal (PGOU) et développements qui affecteront la zone à moyen terme.','de'=>'Geplante Bauarbeiten, neue Infrastrukturen, Änderungen am kommunalen Flächennutzungsplan (PGOU) und Entwicklungen, die das Gebiet mittelfristig betreffen werden.','ru'=>'Запланированные работы, новая инфраструктура, изменения в муниципальном генеральном плане (PGOU) и проекты, которые повлияют на зону в среднесрочной перспективе.' ],
        'perfil.pro.c3.title' => [ 'es'=>'Inversión pública','en'=>'Public investment','fr'=>'Investissement public','de'=>'Öffentliche Investitionen','ru'=>'Государственные инвестиции' ],
        'perfil.pro.c3.desc'  => [ 'es'=>'Presupuestos municipales asignados a la zona, mejoras previstas en servicios públicos y planes de rehabilitación urbana.','en'=>'Municipal budgets allocated to the area, planned improvements to public services and urban regeneration plans.','fr'=>'Budgets municipaux affectés à la zone, améliorations prévues des services publics et plans de réhabilitation urbaine.','de'=>'Dem Gebiet zugewiesene kommunale Haushaltsmittel, geplante Verbesserungen der öffentlichen Dienste und Pläne zur Stadterneuerung.','ru'=>'Муниципальные бюджеты, выделенные зоне, запланированные улучшения общественных услуг и планы городской реновации.' ],
        'perfil.pro.c4.title' => [ 'es'=>'Señales de transformación','en'=>'Signs of transformation','fr'=>'Signes de transformation','de'=>'Anzeichen des Wandels','ru'=>'Признаки перемен' ],
        'perfil.pro.c4.desc'  => [ 'es'=>'Cambios observables en la zona: nuevos negocios, evolución del perfil de residentes y transformación del tejido comercial — descritos, no interpretados como consejo.','en'=>'Observable changes in the area: new businesses, the evolving resident profile and the transformation of the commercial fabric — described, never framed as advice.','fr'=>'Changements observables dans la zone : nouveaux commerces, évolution du profil des résidents et transformation du tissu commercial — décrits, jamais présentés comme un conseil.','de'=>'Beobachtbare Veränderungen im Gebiet: neue Geschäfte, ein sich wandelndes Bewohnerprofil und der Wandel des Gewerbegefüges — beschrieben, nie als Empfehlung formuliert.','ru'=>'Наблюдаемые изменения в зоне: новые бизнесы, меняющийся профиль жителей и трансформация коммерческой среды — описанные факты, а не советы.' ],

        // ── SECTORES PAGE ─────────────────────────────────────────
        'sec.b2c.title'       => [ 'es'=>'Para Particulares <br />y Familias','en'=>'For Individuals <br />and Families','fr'=>'Pour les Particuliers <br />et les Familles','de'=>'Für Privatpersonen <br />und Familien','ru'=>'Для Физических Лиц <br />и Семей' ],
        'sec.b2c.desc'        => [ 'es'=>'Le damos información clara sobre la zona donde va a vivir: seguridad, servicios, entorno y calidad de vida.','en'=>'We give you clear information about the area where you are going to live: security, services, environment and quality of life.','fr'=>'Nous vous donnons des informations claires sur la zone où vous allez vivre : sécurité, services, environnement et qualité de vie.','de'=>'Wir geben Ihnen klare Informationen über das Gebiet, in dem Sie leben werden: Sicherheit, Dienstleistungen, Umgebung und Lebensqualität.','ru'=>'Мы предоставляем понятную информацию о районе, где вы будете жить: безопасность, услуги, окружение и качество жизни.' ],
        'sec.b2c.btn'         => [ 'es'=>'Estudio Residencial','en'=>'Residential Study','fr'=>'Étude Résidentielle','de'=>'Wohnstudie','ru'=>'Жилищное Исследование' ],
        'sec.b2b.title'       => [ 'es'=>'Para Inversores <br />y Empresas','en'=>'For Investors <br />and Companies','fr'=>'Pour les Investisseurs <br />et les Entreprises','de'=>'Für Investoren <br />und Unternehmen','ru'=>'Для Инвесторов <br />и Компаний' ],
        'sec.b2b.desc'        => [ 'es'=>'Información territorial detallada y análisis de zona para que tome decisiones fundamentadas.','en'=>'Detailed territorial information and area analysis so you make informed decisions.','fr'=>'Informations territoriales détaillées et analyse de zone pour que vous preniez des décisions éclairées.','de'=>'Detaillierte territoriale Informationen und Gebietsanalyse für fundierte Entscheidungen.','ru'=>'Подробная территориальная информация и анализ зоны для принятия обоснованных решений.' ],
        'sec.cover.badge'     => [ 'es'=>'Áreas de Cobertura','en'=>'Coverage Areas','fr'=>'Zones de Couverture','de'=>'Abdeckungsgebiete','ru'=>'Зоны Охвата' ],
        'sec.cover.title'     => [ 'es'=>'Dónde Operamos','en'=>'Where We Operate','fr'=>'Où Nous Opérons','de'=>'Wo Wir Tätig Sind','ru'=>'Где Мы Работаем' ],
        'sec.cover.desc'      => [ 'es'=>'Nuestra actividad se concentra en tres de las áreas más valoradas y demandadas de la costa mediterránea.','en'=>'Our activity is concentrated in three of the most valued and sought-after areas on the Mediterranean coast.','fr'=>'Notre activité se concentre dans trois des zones les plus prisées et les plus demandées de la côte méditerranéenne.','de'=>'Unsere Aktivität konzentriert sich auf drei der angesehensten und begehrtesten Gebiete der Mittelmeerküste.','ru'=>'Наша деятельность сосредоточена в трёх из наиболее ценимых и востребованных районов средиземноморского побережья.' ],
        'sec.alicante.sub'    => [ 'es'=>'Costa Blanca','en'=>'Costa Blanca','fr'=>'Costa Blanca','de'=>'Costa Blanca','ru'=>'Коста-Бланка' ],
        'sec.marbella.sub'    => [ 'es'=>'Costa del Sol','en'=>'Costa del Sol','fr'=>'Costa del Sol','de'=>'Costa del Sol','ru'=>'Коста-дель-Соль' ],
        'sec.malaga.sub'      => [ 'es'=>'Capital de la Costa','en'=>'Capital of the Costa del Sol','fr'=>'Capitale de la Côte','de'=>'Hauptstadt der Küste','ru'=>'Столица Побережья' ],
        'sec.intl.title'      => [ 'es'=>'Servicios Internacionales y Otras Ciudades','en'=>'International Services and Other Cities','fr'=>'Services Internationaux et Autres Villes','de'=>'Internationale Dienste und Andere Städte','ru'=>'Международные Услуги и Другие Города' ],
        'sec.intl.desc'       => [ 'es'=>'De forma excepcional, realizamos informes territoriales en <strong>el extranjero y en otras ciudades</strong> bajo demanda. Los costes requerirán un presupuesto personalizado.','en'=>'On an exceptional basis, we carry out territorial reports <strong>abroad and in other cities</strong> on demand. Costs will require a personalised quote.','fr'=>'À titre exceptionnel, nous réalisons des rapports territoriaux <strong>à l\'étranger et dans d\'autres villes</strong> sur demande. Les coûts nécessiteront un devis personnalisé.','de'=>'Auf außerordentlicher Basis führen wir territoriale Berichte <strong>im Ausland und in anderen Städten</strong> auf Anfrage durch. Die Kosten erfordern ein individuelles Angebot.','ru'=>'В исключительных случаях мы проводим территориальные исследования <strong>за рубежом и в других городах</strong> по запросу. Стоимость потребует индивидуального предложения.' ],
        'sec.intl.link'       => [ 'es'=>'Consultar disponibilidad','en'=>'Check availability','fr'=>'Vérifier la disponibilité','de'=>'Verfügbarkeit prüfen','ru'=>'Проверить доступность' ],
        'sec.spec.badge'      => [ 'es'=>'Servicios Especializados','en'=>'Specialised Services','fr'=>'Services Spécialisés','de'=>'Spezialisierte Dienste','ru'=>'Специализированные Услуги' ],
        'sec.spec.title'      => [ 'es'=>'Análisis para cada caso','en'=>'Analysis for every case','fr'=>'Analyse pour chaque cas','de'=>'Analyse für jeden Fall','ru'=>'Анализ для каждого случая' ],
        'sec.spec.desc'       => [ 'es'=>'Trabajamos tanto con personas y familias que van a vivir en la zona, como con inversores que necesitan conocerla antes de actuar.','en'=>'We work with both individuals and families who are going to live in the area, and investors who need to know it before acting.','fr'=>'Nous travaillons avec des personnes et des familles qui vont vivre dans la zone, ainsi qu\'avec des investisseurs qui ont besoin de la connaître avant d\'agir.','de'=>'Wir arbeiten sowohl mit Personen und Familien, die in dem Gebiet leben werden, als auch mit Investoren, die es kennen müssen, bevor sie handeln.','ru'=>'Мы работаем как с физическими лицами и семьями, которые собираются жить в этом районе, так и с инвесторами, которым необходимо знать его перед принятием решения.' ],
        'sec.res.badge'       => [ 'es'=>'Seguridad Residencial','en'=>'Residential Security','fr'=>'Sécurité Résidentielle','de'=>'Wohnsicherheit','ru'=>'Жилая Безопасность' ],
        'sec.res.title'       => [ 'es'=>'Particulares y Familias','en'=>'Individuals and Families','fr'=>'Particuliers et Familles','de'=>'Privatpersonen und Familien','ru'=>'Физические Лица и Семьи' ],
        'sec.res.desc'        => [ 'es'=>'Le decimos si la zona donde quiere vivir es <strong class="text-slate-900 dark:text-white">segura, bien equipada y rentable</strong> a largo plazo.','en'=>'We tell you whether the area where you want to live is <strong class="text-slate-900 dark:text-white">safe, well-equipped and worthwhile</strong> in the long term.','fr'=>'Nous vous disons si la zone où vous souhaitez vivre est <strong class="text-slate-900 dark:text-white">sûre, bien équipée et rentable</strong> à long terme.','de'=>'Wir sagen Ihnen, ob das Gebiet, in dem Sie leben möchten, <strong class="text-slate-900 dark:text-white">sicher, gut ausgestattet und lohnend</strong> ist.','ru'=>'Мы скажем вам, является ли район, в котором вы хотите жить, <strong class="text-slate-900 dark:text-white">безопасным, хорошо оснащённым и перспективным</strong> в долгосрочной перспективе.' ],
        'sec.r1t'             => [ 'es'=>'Seguridad real del barrio','en'=>'Real neighbourhood security','fr'=>'Sécurité réelle du quartier','de'=>'Echte Sicherheit des Viertels','ru'=>'Реальная безопасность района' ],
        'sec.r1d'             => [ 'es'=>'Incidentes, tendencias y comparativa con zonas similares.','en'=>'Incidents, trends and comparison with similar areas.','fr'=>'Incidents, tendances et comparaison avec des zones similaires.','de'=>'Vorfälle, Trends und Vergleich mit ähnlichen Gebieten.','ru'=>'Инциденты, тенденции и сравнение с аналогичными зонами.' ],
        'sec.r2t'             => [ 'es'=>'Servicios esenciales cercanos','en'=>'Nearby essential services','fr'=>'Services essentiels proches','de'=>'Nahe wesentliche Dienstleistungen','ru'=>'Ближайшие основные услуги' ],
        'sec.r2d'             => [ 'es'=>'Colegios, centros de salud, comercios y ocio.','en'=>'Schools, health centres, shops and leisure.','fr'=>'Écoles, centres de santé, commerces et loisirs.','de'=>'Schulen, Gesundheitszentren, Geschäfte und Freizeit.','ru'=>'Школы, медицинские центры, магазины и досуг.' ],
        'sec.r3t'             => [ 'es'=>'Entorno y calidad de vida','en'=>'Environment and quality of life','fr'=>'Environnement et qualité de vie','de'=>'Umgebung und Lebensqualität','ru'=>'Окружение и качество жизни' ],
        'sec.r3d'             => [ 'es'=>'Cómo es el día a día: tranquilidad, ambiente, ruido.','en'=>'What daily life is like: calm, atmosphere, noise.','fr'=>'À quoi ressemble le quotidien : tranquillité, ambiance, bruit.','de'=>'Wie der Alltag ist: Ruhe, Atmosphäre, Lärm.','ru'=>'Каков повседневный уклад: спокойствие, атмосфера, шум.' ],
        'sec.r4t'             => [ 'es'=>'Perfil del vecindario','en'=>'Neighbourhood profile','fr'=>'Profil du voisinage','de'=>'Nachbarschaftsprofil','ru'=>'Профиль района' ],
        'sec.r4d'             => [ 'es'=>'Quiénes viven allí, nivel de vida y dinámica social.','en'=>'Who lives there, standard of living and social dynamics.','fr'=>'Qui y vit, niveau de vie et dynamique sociale.','de'=>'Wer dort lebt, Lebensstandard und soziale Dynamik.','ru'=>'Кто там живёт, уровень жизни и социальная динамика.' ],
        'sec.res.link'        => [ 'es'=>'Solicitar informe residencial','en'=>'Request residential report','fr'=>'Demander un rapport résidentiel','de'=>'Wohnbericht anfordern','ru'=>'Запросить жилищный отчёт' ],
        'sec.inv.badge'       => [ 'es'=>'Inteligencia Territorial','en'=>'Territorial Intelligence','fr'=>'Intelligence Territoriale','de'=>'Territoriale Standortanalyse','ru'=>'Территориальная Аналитика' ],
        'sec.inv.title'       => [ 'es'=>'Inversores y Empresas','en'=>'Investors and Companies','fr'=>'Investisseurs et Entreprises','de'=>'Investoren und Unternehmen','ru'=>'Инвесторы и Компании' ],
        'sec.inv.desc'        => [ 'es'=>'Antes de comprometerse, conozca a fondo la zona: <strong class="text-white">quién la habita, qué infraestructura tiene y qué dice la normativa</strong>.','en'=>'Before committing, know the area thoroughly: <strong class="text-white">who inhabits it, what infrastructure it has and what the regulations say</strong>.','fr'=>'Avant de vous engager, connaissez la zone en profondeur : <strong class="text-white">qui l\'habite, quelle infrastructure elle possède et ce que dit la réglementation</strong>.','de'=>'Bevor Sie sich festlegen, sollten Sie das Gebiet gründlich kennen: <strong class="text-white">wer dort lebt, welche Infrastruktur es gibt und was die Vorschriften besagen</strong>.','ru'=>'Прежде чем брать обязательства, досконально изучите район: <strong class="text-white">кто его населяет, какова инфраструктура и что говорит законодательство</strong>.' ],
        'sec.i1t'             => [ 'es'=>'Comparativa objetiva de zonas','en'=>'Objective area comparison','fr'=>'Comparaison objective des zones','de'=>'Objektiver Gebietsvergleich','ru'=>'Объективное сравнение зон' ],
        'sec.i1d'             => [ 'es'=>'Evaluamos distintas áreas con los mismos criterios.','en'=>'We evaluate different areas using the same criteria.','fr'=>'Nous évaluons différentes zones selon les mêmes critères.','de'=>'Wir bewerten verschiedene Gebiete nach denselben Kriterien.','ru'=>'Мы оцениваем разные зоны по одинаковым критериям.' ],
        'sec.i2t'             => [ 'es'=>'Análisis urbanístico','en'=>'Urban planning analysis','fr'=>'Analyse urbanistique','de'=>'Stadtplanerische Analyse','ru'=>'Анализ градостроительства' ],
        'sec.i2d'             => [ 'es'=>'Normativa local, uso del suelo y características urbanas.','en'=>'Local regulations, land use and urban characteristics.','fr'=>'Réglementation locale, usage des sols et caractéristiques urbaines.','de'=>'Lokale Vorschriften, Landnutzung und städtische Merkmale.','ru'=>'Местные нормативы, землепользование и городские характеристики.' ],
        'sec.i3t'             => [ 'es'=>'Entorno e infraestructura','en'=>'Environment and infrastructure','fr'=>'Environnement et infrastructure','de'=>'Umgebung und Infrastruktur','ru'=>'Окружение и инфраструктура' ],
        'sec.i3d'             => [ 'es'=>'Conectividad, servicios y calidad del entorno.','en'=>'Connectivity, services and environmental quality.','fr'=>'Connectivité, services et qualité de l\'environnement.','de'=>'Konnektivität, Dienstleistungen und Umgebungsqualität.','ru'=>'Связность, услуги и качество окружающей среды.' ],
        'sec.i4t'             => [ 'es'=>'Perfil de la demanda local','en'=>'Local demand profile','fr'=>'Profil de la demande locale','de'=>'Lokales Nachfrageprofil','ru'=>'Профиль местного спроса' ],
        'sec.i4d'             => [ 'es'=>'Quién habita y quién busca en cada zona.','en'=>'Who lives in each area — and who is looking to move there.','fr'=>'Qui habite et qui cherche dans chaque zone.','de'=>'Wer in jedem Gebiet lebt und wer dort sucht.','ru'=>'Кто населяет и кто ищет в каждой зоне.' ],
        'sec.inv.link'        => [ 'es'=>'Solicitar informe de zona','en'=>'Request area report','fr'=>'Demander un rapport de zone','de'=>'Gebietsbericht anfordern','ru'=>'Запросить отчёт по зоне' ],
        'sec.final.title'     => [ 'es'=>'Conocer antes de decidir es siempre la mejor estrategia.','en'=>'Knowing before deciding is always the best strategy.','fr'=>'Savoir avant de décider est toujours la meilleure stratégie.','de'=>'Zu wissen, bevor man entscheidet, ist immer die beste Strategie.','ru'=>'Знать перед принятием решения — всегда лучшая стратегия.' ],
