        // ── META DESCRIPTIONS ─────────────────────────────────────
        'meta.home.desc'      => [ 'es'=>'Romvill ofrece inteligencia territorial en la Costa Mediterránea: informes expertos sobre seguridad, demografía, sanidad y movilidad para compra, inversión o traslado.','en'=>'Romvill provides territorial intelligence on the Mediterranean Coast: expert reports on security, demographics, health and mobility for purchase, investment or relocation.','fr'=>'Romvill offre une intelligence territoriale sur la Côte Méditerranéenne : rapports d\'experts sur la sécurité, la démographie, la santé et la mobilité pour achat, investissement ou déménagement.','de'=>'Romvill bietet territoriale Standortanalyse an der Mittelmeerküste: Expertenberichte über Sicherheit, Demografie, Gesundheit und Mobilität für Kauf, Investition oder Umzug.','ru'=>'Romvill предоставляет территориальную аналитику на Средиземноморском побережье: экспертные отчёты о безопасности, демографии, здравоохранении и мобильности для покупки, инвестиций или переезда.' ],
        'meta.met.desc'       => [ 'es'=>'Descubra cómo Romvill elabora sus informes: recolección OSINT, análisis de campo y presentación estructurada para que tome decisiones con criterio.','en'=>'Discover how Romvill prepares its reports: OSINT collection, field analysis and structured presentation so you make informed decisions.','fr'=>'Découvrez comment Romvill prépare ses rapports : collecte OSINT, analyse de terrain et présentation structurée pour décider en connaissance de cause.','de'=>'Erfahren Sie, wie Romvill seine Berichte erstellt: OSINT-Sammlung, Feldanalyse und strukturierte Darstellung für fundierte Entscheidungen.','ru'=>'Узнайте, как Romvill составляет свои отчёты: сбор OSINT, полевой анализ и структурированная презентация для обоснованных решений.' ],
        'meta.ana.desc'       => [ 'es'=>'Romvill analiza cuatro dimensiones clave: seguridad real, perfil demográfico, cobertura sanitaria y movilidad. Conozca la zona antes de decidir.','en'=>'Romvill analyses four key dimensions: real security, demographic profile, healthcare coverage and mobility. Know the area before you decide.','fr'=>'Romvill analyse quatre dimensions clés : sécurité réelle, profil démographique, couverture sanitaire et mobilité. Connaissez la zone avant de décider.','de'=>'Romvill analysiert vier Schlüsseldimensionen: echte Sicherheit, demografisches Profil, Gesundheitsversorgung und Mobilität. Lernen Sie das Gebiet kennen, bevor Sie entscheiden.','ru'=>'Romvill анализирует четыре ключевых измерения: реальная безопасность, демографический профиль, охват здравоохранения и мобильность. Узнайте район перед принятием решения.' ],
        'meta.sec.desc'       => [ 'es'=>'Romvill trabaja con particulares, familias e inversores en Alicante, Marbella y Málaga. Estudios residenciales y análisis territorial especializado.','en'=>'Romvill works with individuals, families and investors in Alicante, Marbella and Málaga. Residential studies and specialised territorial analysis.','fr'=>'Romvill travaille avec des particuliers, des familles et des investisseurs à Alicante, Marbella et Málaga. Études résidentielles et analyses territoriales spécialisées.','de'=>'Romvill arbeitet mit Privatpersonen, Familien und Investoren in Alicante, Marbella und Málaga. Wohnstudien und spezialisierte territoriale Analysen.','ru'=>'Romvill работает с физическими лицами, семьями и инвесторами в Аликанте, Марбелье и Малаге. Жилищные исследования и специализированный территориальный анализ.' ],
        'meta.cont.desc'      => [ 'es'=>'Solicite su informe territorial personalizado. Contacte con Romvill para conocer la zona que le interesa antes de comprar, invertir o trasladarse.','en'=>'Request your personalised territorial report. Contact Romvill to learn about the area that interests you before buying, investing or relocating.','fr'=>'Demandez votre rapport territorial personnalisé. Contactez Romvill pour en savoir plus sur la zone qui vous intéresse avant d\'acheter, d\'investir ou de déménager.','de'=>'Fordern Sie Ihren personalisierten Gebietsbericht an. Kontaktieren Sie Romvill, um das Gebiet kennenzulernen, das Sie interessiert — vor Kauf, Investition oder Umzug.','ru'=>'Запросите персонализированный территориальный отчёт. Свяжитесь с Romvill, чтобы узнать об интересующем вас районе.' ],
        'meta.priv.desc'      => [ 'es'=>'Política de privacidad de Romvill. Cómo recopilamos, usamos y protegemos su información personal de acuerdo con el RGPD.','en'=>'Romvill privacy policy. How we collect, use and protect your personal information in accordance with the GDPR.','fr'=>'Politique de confidentialité de Romvill. Comment nous collectons, utilisons et protégeons vos informations personnelles conformément au RGPD.','de'=>'Datenschutzrichtlinie von Romvill. Wie wir Ihre persönlichen Daten gemäß der DSGVO erheben, verwenden und schützen.','ru'=>'Политика конфиденциальности Romvill. Как мы собираем, используем и защищаем ваши персональные данные в соответствии с GDPR.' ],
        'meta.terms.desc'     => [ 'es'=>'Términos y condiciones de uso de Romvill. Conozca las condiciones que rigen la prestación de nuestros servicios de análisis territorial.','en'=>'Romvill terms and conditions of use. Learn about the conditions governing the provision of our territorial analysis services.','fr'=>'Conditions générales d\'utilisation de Romvill. Découvrez les conditions régissant nos services d\'analyse territoriale.','de'=>'Nutzungsbedingungen von Romvill. Erfahren Sie mehr über die Bedingungen für unsere territorialen Analysedienste.','ru'=>'Условия использования Romvill. Ознакомьтесь с условиями предоставления наших услуг территориального анализа.' ],

