        // Descriptions (per page)
        'seo.desc.home'       => [ 'es'=>'Análisis territorial independiente en Alicante, Málaga y Marbella. Informes sobre seguridad, entorno y servicios antes de comprar, invertir o establecerse.','en'=>'Independent territorial analysis in Alicante, Málaga and Marbella. Reports on security, environment and services before buying, investing or settling.','fr'=>'Analyse territoriale indépendante à Alicante, Málaga et Marbella. Rapports sur la sécurité, l\'environnement et les services avant d\'acheter, d\'investir ou de s\'installer.','de'=>'Unabhängige Gebietsanalyse in Alicante, Málaga und Marbella. Berichte über Sicherheit, Umfeld und Dienstleistungen vor Kauf, Investition oder Niederlassung.','ru'=>'Независимый территориальный анализ в Аликанте, Малаге и Марбелье. Отчёты о безопасности, окружении и услугах перед покупкой, инвестициями или переездом.' ],
        'seo.desc.metodologia' => [ 'es'=>'Cómo trabajamos en ROMVILL: combinamos fuentes contrastadas y análisis sobre el terreno para ofrecerle información fiable sobre la zona.','en'=>'How we work at ROMVILL: we combine cross-checked sources and on-the-ground analysis to give you reliable information about the area.','fr'=>'Comment nous travaillons chez ROMVILL : nous combinons des sources recoupées et une analyse sur le terrain pour vous offrir des informations fiables sur la zone.','de'=>'Wie wir bei ROMVILL arbeiten: Wir kombinieren gegengeprüfte Quellen und Analysen vor Ort, um Ihnen verlässliche Informationen über das Gebiet zu bieten.','ru'=>'Как мы работаем в ROMVILL: мы сочетаем проверенные источники и анализ на месте, чтобы предоставить надёжную информацию о зоне.' ],
        'seo.desc.analisis'   => [ 'es'=>'Las dimensiones que analizamos de cada zona: seguridad, comunidad, sanidad y movilidad, con rigor profesional.','en'=>'The dimensions we analyse in each area: security, community, healthcare and mobility, with professional rigour.','fr'=>'Les dimensions que nous analysons dans chaque zone : sécurité, communauté, santé et mobilité, avec rigueur professionnelle.','de'=>'Die Dimensionen, die wir in jedem Gebiet analysieren: Sicherheit, Gemeinschaft, Gesundheit und Mobilität, mit professioneller Strenge.','ru'=>'Измерения, которые мы анализируем в каждой зоне: безопасность, сообщество, здравоохранение и мобильность, с профессиональной строгостью.' ],
        'seo.desc.sectores'   => [ 'es'=>'Análisis territorial para particulares, inversores, promotores y empresas que necesitan conocer una zona antes de decidir.','en'=>'Territorial analysis for individuals, investors, developers and businesses that need to know an area before deciding.','fr'=>'Analyse territoriale pour particuliers, investisseurs, promoteurs et entreprises qui ont besoin de connaître une zone avant de décider.','de'=>'Gebietsanalyse für Privatpersonen, Investoren, Projektentwickler und Unternehmen, die ein Gebiet vor der Entscheidung kennen müssen.','ru'=>'Территориальный анализ для частных лиц, инвесторов, девелоперов и компаний, которым нужно узнать зону перед принятием решения.' ],
        'seo.desc.contacto'   => [ 'es'=>'Solicite su informe de zona. Cuéntenos qué área le interesa y reciba un análisis independiente, sin compromiso.','en'=>'Request your area report. Tell us which area interests you and receive an independent analysis, with no obligation.','fr'=>'Demandez votre rapport de zone. Dites-nous quelle zone vous intéresse et recevez une analyse indépendante, sans engagement.','de'=>'Fordern Sie Ihren Gebietsbericht an. Sagen Sie uns, welches Gebiet Sie interessiert, und erhalten Sie eine unabhängige Analyse, unverbindlich.','ru'=>'Запросите отчёт по зоне. Расскажите, какая зона вас интересует, и получите независимый анализ без обязательств.' ],
        'seo.desc.perfil-seguridad'   => [ 'es'=>'Analizamos el contexto de seguridad de la zona combinando información contrastada y observación sobre el terreno.','en'=>'We analyse the security context of the area by combining cross-checked information and on-the-ground observation.','fr'=>'Nous analysons le contexte de sécurité de la zone en combinant des informations recoupées et l\'observation sur le terrain.','de'=>'Wir analysieren den Sicherheitskontext des Gebiets durch die Kombination gegengeprüfter Informationen und Beobachtung vor Ort.','ru'=>'Мы анализируем контекст безопасности зоны, сочетая проверенную информацию и наблюдение на месте.' ],
        'seo.desc.perfil-demografico' => [ 'es'=>'Le mostramos cómo es la comunidad de la zona: composición, ambiente y evolución del entorno.','en'=>'We show you what the community of the area is like: composition, atmosphere and evolution of the environment.','fr'=>'Nous vous montrons comment est la communauté de la zone : composition, ambiance et évolution de l\'environnement.','de'=>'Wir zeigen Ihnen, wie die Gemeinschaft des Gebiets ist: Zusammensetzung, Atmosphäre und Entwicklung des Umfelds.','ru'=>'Мы показываем, каково сообщество района: состав, атмосфера и развитие окружения.' ],
        'seo.desc.perfil-sanidad'     => [ 'es'=>'Analizamos la infraestructura sanitaria accesible desde la zona: hospitales, centros de salud, farmacias y urgencias.','en'=>'We analyse the healthcare infrastructure accessible from the area: hospitals, health centres, pharmacies and emergency services.','fr'=>'Nous analysons l\'infrastructure sanitaire accessible depuis la zone : hôpitaux, centres de santé, pharmacies et urgences.','de'=>'Wir analysieren die vom Gebiet aus zugängliche Gesundheitsinfrastruktur: Krankenhäuser, Gesundheitszentren, Apotheken und Notdienste.','ru'=>'Мы анализируем доступную из зоны медицинскую инфраструктуру: больницы, медицинские центры, аптеки и неотложную помощь.' ],
        'seo.desc.perfil-movilidad'   => [ 'es'=>'Estudiamos cómo se mueve la zona: accesos, transporte público, aparcamiento y tiempos de desplazamiento.','en'=>'We study how people get around the area: access roads, public transport, parking and travel times.','fr'=>'Nous étudions comment on se déplace dans la zone : accès, transports publics, stationnement et temps de trajet.','de'=>'Wir untersuchen die Mobilität des Gebiets: Zufahrten, öffentlicher Verkehr, Parken und Reisezeiten.','ru'=>'Мы изучаем, как устроено передвижение по району: подъезды, общественный транспорт, парковка и время в пути.' ],
        'seo.desc.perfil-proyeccion'  => [ 'es'=>'Planificación pública y proyección futura de la zona. Proyectos urbanísticos, infraestructuras y normativa del suelo.','en'=>'Public planning and the area\'s future outlook. Urban development projects, infrastructure and land-use regulations.','fr'=>'Planification publique et projection future de la zone. Projets d\'urbanisme, infrastructures et réglementation des sols.','de'=>'Öffentliche Planung und Zukunftsausblick des Gebiets. Städtebauprojekte, Infrastruktur und Bodennutzungsvorschriften.','ru'=>'Государственное планирование и перспективы развития зоны. Градостроительные проекты, инфраструктура и нормы землепользования.' ],
        // ── PÁGINA DE PRECIOS ──
        'nav.precios'        => [ 'es'=>'Precios','en'=>'Pricing','fr'=>'Tarifs','de'=>'Preise','ru'=>'Цены' ],
        'seo.title.precios'  => [ 'es'=>'Precios: Informes de Zona desde 149€ | ROMVILL','en'=>'Pricing: Area Reports from €149 | ROMVILL','fr'=>'Tarifs : Rapports de Zone à partir de 149€ | ROMVILL','de'=>'Preise: Gebietsberichte ab 149€ | ROMVILL','ru'=>'Цены: отчёты по зоне от 149€ | ROMVILL' ],
        'seo.desc.precios'   => [ 'es'=>'Tres niveles de informe de inteligencia territorial: Esencial, Superior y Premium. Precios claros desde 149€. Análisis independiente de la zona antes de comprar o invertir.','en'=>'Three levels of territorial intelligence report: Essential, Superior and Premium. Clear pricing from €149. Independent area analysis before buying or investing.','fr'=>'Trois niveaux de rapport d\'intelligence territoriale : Essentiel, Supérieur et Premium. Tarifs clairs à partir de 149€. Analyse indépendante de la zone avant d\'acheter ou d\'investir.','de'=>'Drei Stufen des Standort-Analyseberichts: Essential, Superior und Premium. Klare Preise ab 149€. Unabhängige Gebietsanalyse vor Kauf oder Investition.','ru'=>'Три уровня отчёта по территориальной аналитике: «Основной», «Супериор» и «Премиум». Понятные цены от 149€. Независимый анализ района перед покупкой или инвестицией.' ],
        'precios.kicker'     => [ 'es'=>'Precios','en'=>'Pricing','fr'=>'Tarifs','de'=>'Preise','ru'=>'Цены' ],
        'precios.title'      => [ 'es'=>'Un nivel de análisis para cada decisión','en'=>'A level of analysis for every decision','fr'=>'Un niveau d\'analyse pour chaque décision','de'=>'Eine Analysetiefe für jede Entscheidung','ru'=>'Уровень анализа для каждого решения' ],
        'precios.subtitle'   => [ 'es'=>'Elige la profundidad que necesitas. Y si luego quieres subir de nivel, no pagas dos veces: te descontamos lo que ya pagaste.','en'=>'Choose the depth you need. And if you later move up a level, you don\'t pay twice: we deduct what you already paid.','fr'=>'Choisissez la profondeur dont vous avez besoin. Et si vous montez de niveau plus tard, vous ne payez pas deux fois : nous déduisons ce que vous avez déjà payé.','de'=>'Wählen Sie die benötigte Tiefe. Und wenn Sie später eine Stufe höher gehen, zahlen Sie nicht doppelt: Wir rechnen das bereits Gezahlte an.','ru'=>'Выберите нужную глубину. И если позже вы перейдёте на уровень выше, вы не платите дважды: мы вычитаем уже оплаченное.' ],
        'precios.recommended'=> [ 'es'=>'Recomendado','en'=>'Recommended','fr'=>'Recommandé','de'=>'Empfohlen','ru'=>'Рекомендуется' ],
        'precios.launch.badge' => [ 'es'=>'Precio de lanzamiento','en'=>'Launch price','fr'=>'Prix de lancement','de'=>'Einführungspreis','ru'=>'Стартовая цена' ],
        'precios.launch.note'  => [ 'es'=>'Solo las primeras 5 plazas, a cambio de su reseña. Después, precio oficial.','en'=>'First 5 clients only, in exchange for your review. Official price afterwards.','fr'=>'Seulement les 5 premières places, en échange de votre avis. Ensuite, prix officiel.','de'=>'Nur die ersten 5 Plätze, im Tausch gegen Ihre Bewertung. Danach gilt der offizielle Preis.','ru'=>'Только первые 5 мест — в обмен на ваш отзыв. Далее действует официальная цена.' ],
        'precios.official'     => [ 'es'=>'Precio oficial','en'=>'Official price','fr'=>'Prix officiel','de'=>'Offizieller Preis','ru'=>'Официальная цена' ],
        'precios.sup.title'    => [ 'es'=>'Suplementos opcionales','en'=>'Optional add-ons','fr'=>'Suppléments optionnels','de'=>'Optionale Zusatzleistungen','ru'=>'Дополнительные опции' ],
        'precios.sup.items'    => [ 'es'=>'Dimensión adicional del catálogo — +69 € (máx. 2)|Comparativa con una segunda zona — +150 €|Versión del informe en otro idioma — +80 € (su idioma de entrega ya está incluido)|Análisis de una propiedad concreta — +180 € (desde nivel Superior)','en'=>'Additional dimension from the catalogue — +€69 (max. 2)|Comparison with a second area — +€150|Report version in another language — +€80 (your delivery language is already included)|Analysis of a specific property — +€180 (from Superior level)','fr'=>'Dimension supplémentaire du catalogue — +69 € (max. 2)|Comparaison avec une seconde zone — +150 €|Version du rapport dans une autre langue — +80 € (votre langue de livraison est déjà incluse)|Analyse d\'un bien précis — +180 € (dès le niveau Supérieur)','de'=>'Zusätzliche Dimension aus dem Katalog — +69 € (max. 2)|Vergleich mit einem zweiten Gebiet — +150 €|Berichtversion in einer weiteren Sprache — +80 € (Ihre Liefersprache ist bereits inklusive)|Analyse einer konkreten Immobilie — +180 € (ab Stufe Superior)','ru'=>'Дополнительное измерение из каталога — +69 € (макс. 2)|Сравнение со вторым районом — +150 €|Версия отчёта на ещё одном языке — +80 € (язык подачи уже включён)|Анализ конкретного объекта — +180 € (от уровня «Супериор»)' ],
        'precios.sup.note'     => [ 'es'=>'Los suplementos se acuerdan en su Resumen de Encargo. Los informes se amplían; nunca se recortan.','en'=>'Add-ons are agreed in your Order Summary. Reports are extended; never trimmed.','fr'=>'Les suppléments sont convenus dans votre Résumé de Commande. Un rapport peut être enrichi, jamais réduit.','de'=>'Zusatzleistungen werden in Ihrer Auftragsübersicht vereinbart. Berichte werden erweitert, nie gekürzt.','ru'=>'Опции согласуются в «Резюме заказа». Отчёты расширяются и никогда не урезаются.' ],
        'precios.from'       => [ 'es'=>'desde','en'=>'from','fr'=>'à partir de','de'=>'ab','ru'=>'от' ],
        'precios.delivery'   => [ 'es'=>'Entrega','en'=>'Delivery','fr'=>'Livraison','de'=>'Lieferung','ru'=>'Срок' ],
        'precios.cta'        => [ 'es'=>'Solicitar este informe','en'=>'Request this report','fr'=>'Demander ce rapport','de'=>'Diesen Bericht anfordern','ru'=>'Запросить этот отчёт' ],
        'precios.expres.name'=> [ 'es'=>'Esencial','en'=>'Essential','fr'=>'Essentiel','de'=>'Essential','ru'=>'Основной' ],
        'precios.expres.desc'=> [ 'es'=>'Una visión de conjunto fiable de la zona, con lo esencial.','en'=>'A reliable overview of the area, with the essentials.','fr'=>'Une vue d\'ensemble fiable de la zone, avec l\'essentiel.','de'=>'Ein verlässlicher Überblick über das Gebiet, mit dem Wesentlichen.','ru'=>'Надёжный обзор района с самым необходимым.' ],
        'precios.expres.feat'=> [ 'es'=>'Dashboard de la zona|6-7 dimensiones esenciales (seguridad, demografía, servicios…)|Datos oficiales verificables|Mapas y patrones detectados|Versión web interactiva','en'=>'Area dashboard|6-7 essential dimensions (safety, demographics, services…)|Verifiable official data|Maps and detected patterns|Interactive web version','fr'=>'Tableau de bord de la zone|6-7 dimensions essentielles (sécurité, démographie, services…)|Données officielles vérifiables|Cartes et tendances détectées|Version web interactive','de'=>'Gebiets-Dashboard|6-7 wesentliche Dimensionen (Sicherheit, Demografie, Dienstleistungen…)|Überprüfbare offizielle Daten|Karten und erkannte Muster|Interaktive Web-Version','ru'=>'Дашборд района|6-7 ключевых измерений (безопасность, демография, услуги…)|Проверяемые официальные данные|Карты и выявленные закономерности|Интерактивная веб-версия' ],
        'precios.expres.delivery'=> [ 'es'=>'3-4 días laborables','en'=>'3-4 working days','fr'=>'3-4 jours ouvrables','de'=>'3-4 Werktage','ru'=>'3-4 рабочих дня' ],
        'precios.analisis.name'=> [ 'es'=>'Superior','en'=>'Superior','fr'=>'Supérieur','de'=>'Superior','ru'=>'Супериор' ],
        'precios.analisis.desc'=> [ 'es'=>'El nivel que elige la mayoría: profundidad y verificación a fondo.','en'=>'The level most clients choose: depth and thorough verification.','fr'=>'Le niveau que choisit la majorité : profondeur et vérification approfondie.','de'=>'Die von den meisten gewählte Stufe: Tiefe und gründliche Prüfung.','ru'=>'Уровень, который выбирает большинство: глубина и тщательная проверка.' ],
        'precios.analisis.feat'=> [ 'es'=>'Todo lo del Esencial|11-12 dimensiones verificadas|Fiscalidad para no residentes y conectividad|Todas las fuentes citadas en cada dato','en'=>'Everything in Essential|11-12 verified dimensions|Tax for non-residents and connectivity|Every figure cited to its source','fr'=>'Tout l\'Essentiel|11-12 dimensions vérifiées|Fiscalité pour non-résidents et connectivité|Chaque donnée citée à sa source','de'=>'Alles aus Essential|11-12 geprüfte Dimensionen|Steuern für Nicht-Residenten und Konnektivität|Jede Angabe mit Quellenangabe','ru'=>'Всё из «Основной»|11-12 проверенных измерений|Налоги для нерезидентов и связность|Каждый факт со ссылкой на источник' ],
        'precios.analisis.delivery'=> [ 'es'=>'5-7 días laborables','en'=>'5-7 working days','fr'=>'5-7 jours ouvrables','de'=>'5-7 Werktage','ru'=>'5-7 рабочих дней' ],
        'precios.premium.name'=> [ 'es'=>'Premium','en'=>'Premium','fr'=>'Premium','de'=>'Premium','ru'=>'Премиум' ],
        'precios.premium.desc'=> [ 'es'=>'Máximo nivel: una propiedad concreta y acompañamiento dedicado.','en'=>'Top level: a specific property and dedicated support.','fr'=>'Niveau maximum : un bien précis et un accompagnement dédié.','de'=>'Höchste Stufe: eine konkrete Immobilie und persönliche Begleitung.','ru'=>'Максимальный уровень: конкретный объект и персональное сопровождение.' ],
        'precios.premium.feat'=> [ 'es'=>'Todo lo del Superior|14 dimensiones completas|Análisis de una propiedad concreta|Informe en 2 idiomas|Llamada con analista + WhatsApp directo','en'=>'Everything in Superior|14 full dimensions|Analysis of a specific property|Report in 2 languages|Call with an analyst + direct WhatsApp','fr'=>'Tout le Supérieur|14 dimensions complètes|Analyse d\'un bien précis|Rapport en 2 langues|Appel avec un analyste + WhatsApp direct','de'=>'Alles aus Superior|14 vollständige Dimensionen|Analyse einer konkreten Immobilie|Bericht in 2 Sprachen|Anruf mit Analyst + direktes WhatsApp','ru'=>'Всё из «Супериор»|14 полных измерений|Анализ конкретного объекта|Отчёт на 2 языках|Звонок с аналитиком + прямой WhatsApp' ],
        'precios.premium.delivery'=> [ 'es'=>'7-14 días laborables','en'=>'7-14 working days','fr'=>'7-14 jours ouvrables','de'=>'7-14 Werktage','ru'=>'7-14 рабочих дней' ],
        'precios.credit.title'=> [ 'es'=>'No pagas dos veces','en'=>'You don\'t pay twice','fr'=>'Vous ne payez pas deux fois','de'=>'Sie zahlen nicht doppelt','ru'=>'Вы не платите дважды' ],
        'precios.credit.desc'=> [ 'es'=>'¿Empiezas por un informe básico y luego quieres uno más completo? Te descontamos íntegramente lo que ya pagaste y solo abonas la diferencia. Tienes 60 días para subir de nivel.','en'=>'Start with a basic report and later want a more complete one? We deduct in full what you already paid, and you only pay the difference. You have 60 days to move up a level.','fr'=>'Vous commencez par un rapport de base et souhaitez ensuite un rapport plus complet ? Nous déduisons intégralement ce que vous avez déjà payé et vous ne réglez que la différence. Vous avez 60 jours pour passer à un niveau supérieur.','de'=>'Sie starten mit einem Basisbericht und möchten später einen umfassenderen? Wir rechnen den bereits gezahlten Betrag vollständig an, und Sie zahlen nur die Differenz. Sie haben 60 Tage, um eine Stufe höher zu gehen.','ru'=>'Начали с базового отчёта, а позже хотите более полный? Мы полностью вычитаем уже оплаченную сумму, и вы доплачиваете только разницу. У вас есть 60 дней, чтобы перейти на уровень выше.' ],
        'precios.faq.title'  => [ 'es'=>'Preguntas frecuentes','en'=>'Frequently asked questions','fr'=>'Questions fréquentes','de'=>'Häufige Fragen','ru'=>'Частые вопросы' ],
        'precios.faq.q1'     => [ 'es'=>'¿Es realmente independiente?','en'=>'Is it really independent?','fr'=>'Est-ce vraiment indépendant ?','de'=>'Ist es wirklich unabhängig?','ru'=>'Это действительно независимо?' ],
        'precios.faq.a1'     => [ 'es'=>'Sí. No vendemos inmuebles ni cobramos comisiones de agencias o promotores. Solo analizamos.','en'=>'Yes. We don\'t sell properties or take commissions from agencies or developers. We only analyse.','fr'=>'Oui. Nous ne vendons pas de biens et ne percevons aucune commission d\'agences ou de promoteurs. Nous analysons seulement.','de'=>'Ja. Wir verkaufen keine Immobilien und erhalten keine Provisionen von Agenturen oder Bauträgern. Wir analysieren nur.','ru'=>'Да. Мы не продаём недвижимость и не берём комиссий от агентств или застройщиков. Мы только анализируем.' ],
        'precios.faq.q2'     => [ 'es'=>'¿Y si necesito más profundidad después?','en'=>'What if I need more depth later?','fr'=>'Et si j\'ai besoin de plus de profondeur ensuite ?','de'=>'Was, wenn ich später mehr Tiefe brauche?','ru'=>'А если позже понадобится больше глубины?' ],
        'precios.faq.a2'     => [ 'es'=>'Durante los 60 días siguientes, te descontamos íntegramente lo que pagaste por tu informe si decides pasar a un nivel superior. Solo abonas la diferencia.','en'=>'For the next 60 days, we deduct in full what you paid for your report if you decide to move up to a higher level. You only pay the difference.','fr'=>'Pendant les 60 jours suivants, nous déduisons intégralement ce que vous avez payé pour votre rapport si vous décidez de passer à un niveau supérieur. Vous ne réglez que la différence.','de'=>'In den folgenden 60 Tagen rechnen wir den für Ihren Bericht gezahlten Betrag vollständig an, wenn Sie sich für eine höhere Stufe entscheiden. Sie zahlen nur die Differenz.','ru'=>'В течение следующих 60 дней мы полностью вычитаем сумму, уплаченную за ваш отчёт, если вы решите перейти на более высокий уровень. Вы доплачиваете только разницу.' ],
        'precios.faq.q3'     => [ 'es'=>'¿Sobre qué zonas trabajáis?','en'=>'Which areas do you cover?','fr'=>'Quelles zones couvrez-vous ?','de'=>'Welche Gebiete decken Sie ab?','ru'=>'С какими районами вы работаете?' ],
        'precios.faq.a3'     => [ 'es'=>'Costa Mediterránea: Alicante, Málaga y Marbella y su entorno. Otras zonas, a consultar.','en'=>'Mediterranean Coast: Alicante, Málaga and Marbella and their surroundings. Other areas on request.','fr'=>'Côte méditerranéenne : Alicante, Málaga et Marbella et leurs environs. Autres zones sur demande.','de'=>'Mittelmeerküste: Alicante, Málaga und Marbella und Umgebung. Andere Gebiete auf Anfrage.','ru'=>'Средиземноморское побережье: Аликанте, Малага и Марбелья и окрестности. Другие районы — по запросу.' ],

        'seo.desc.privacidad' => [ 'es'=>'Cómo ROMVILL recopila, usa y protege tus datos personales conforme al RGPD cuando solicitas un informe de zona. Confidenciales y sin cesión a terceros.','en'=>'How ROMVILL collects, uses and protects your personal data under the GDPR when you request an area report. Confidential and never shared with third parties.','fr'=>'Comment ROMVILL collecte, utilise et protège vos données personnelles conformément au RGPD lorsque vous demandez un rapport de zone. Confidentielles et jamais cédées à des tiers.','de'=>'Wie ROMVILL Ihre personenbezogenen Daten gemäß DSGVO erhebt, verwendet und schützt, wenn Sie einen Gebietsbericht anfordern. Vertraulich und ohne Weitergabe an Dritte.','ru'=>'Как ROMVILL собирает, использует и защищает ваши персональные данные согласно GDPR при запросе отчёта о зоне. Конфиденциально, без передачи третьим лицам.' ],
        'seo.desc.terminos'   => [ 'es'=>'Condiciones del servicio de análisis territorial de ROMVILL: alcance de los informes, uso del sitio web y derechos del cliente.','en'=>'Terms governing the ROMVILL territorial analysis service: scope of the reports, use of the website and client rights.','fr'=>'Conditions du service d\'analyse territoriale de ROMVILL : portée des rapports, utilisation du site web et droits du client.','de'=>'Bedingungen des Gebietsanalyse-Dienstes von ROMVILL: Umfang der Berichte, Nutzung der Website und Rechte des Kunden.','ru'=>'Условия услуги территориального анализа ROMVILL: объём отчётов, использование сайта и права клиента.' ],
        'seo.desc.presupuesto-bloque-1' => [ 'es'=>'Solicite su presupuesto de análisis territorial para particulares y familias: conozca la zona antes de mudarse o comprar su vivienda.','en'=>'Request your territorial analysis quote for individuals and families: know the area before moving or buying your home.','fr'=>'Demandez votre devis d\'analyse territoriale pour particuliers et familles : connaissez la zone avant de déménager ou d\'acheter votre logement.','de'=>'Fordern Sie Ihr Angebot für die Gebietsanalyse für Privatpersonen und Familien an: Lernen Sie das Gebiet kennen, bevor Sie umziehen oder Ihr Zuhause kaufen.','ru'=>'Запросите предложение по территориальному анализу для частных лиц и семей: узнайте зону перед переездом или покупкой жилья.' ],
        'seo.desc.presupuesto-bloque-2' => [ 'es'=>'Solicite su presupuesto de análisis territorial para inversores: evalúe la zona antes de invertir en una propiedad.','en'=>'Request your territorial analysis quote for investors: assess the area before investing in a property.','fr'=>'Demandez votre devis d\'analyse territoriale pour investisseurs : évaluez la zone avant d\'investir dans un bien.','de'=>'Fordern Sie Ihr Angebot für die Gebietsanalyse für Investoren an: Bewerten Sie das Gebiet, bevor Sie in eine Immobilie investieren.','ru'=>'Запросите предложение по территориальному анализу для инвесторов: оцените зону перед инвестированием в недвижимость.' ],
        'seo.desc.presupuesto-bloque-3' => [ 'es'=>'Solicite su presupuesto de análisis territorial para promotores: viabilidad y entorno de su proyecto antes de desarrollarlo.','en'=>'Request your territorial analysis quote for developers: viability and environment of your project before developing it.','fr'=>'Demandez votre devis d\'analyse territoriale pour promoteurs : viabilité et environnement de votre projet avant de le développer.','de'=>'Fordern Sie Ihr Angebot für die Gebietsanalyse für Projektentwickler an: Machbarkeit und Umfeld Ihres Projekts vor der Entwicklung.','ru'=>'Запросите предложение по территориальному анализу для девелоперов: жизнеспособность и окружение вашего проекта перед его реализацией.' ],
        'seo.desc.presupuesto-bloque-4' => [ 'es'=>'Solicite su presupuesto de análisis territorial para empresas: conozca el entorno antes de abrir, expandirse o reubicarse.','en'=>'Request your territorial analysis quote for businesses: know the environment before opening, expanding or relocating.','fr'=>'Demandez votre devis d\'analyse territoriale pour entreprises : connaissez l\'environnement avant d\'ouvrir, de vous développer ou de vous relocaliser.','de'=>'Fordern Sie Ihr Angebot für die Gebietsanalyse für Unternehmen an: Lernen Sie das Umfeld kennen, bevor Sie eröffnen, expandieren oder umziehen.','ru'=>'Запросите предложение по территориальному анализу для компаний: узнайте окружение перед открытием, расширением или переездом.' ],

        // ── PRIVACIDAD PAGE ───────────────────────────────────────
        'priv.title'          => [ 'es'=>'Política de Privacidad','en'=>'Privacy Policy','fr'=>'Politique de Confidentialité','de'=>'Datenschutzrichtlinie','ru'=>'Политика Конфиденциальности' ],
        'priv.badge'          => [ 'es'=>'Legal','en'=>'Legal','fr'=>'Légal','de'=>'Rechtlich','ru'=>'Правовой' ],
        'priv.updated'        => [ 'es'=>'Última actualización: junio 2026','en'=>'Last updated: June 2026','fr'=>'Dernière mise à jour : juin 2026','de'=>'Letzte Aktualisierung: Juni 2026','ru'=>'Последнее обновление: июнь 2026' ],
        'priv.intro'          => [ 'es'=>'En Romvill respetamos su privacidad y nos comprometemos a proteger sus datos personales. Esta política describe qué información recopilamos, cómo la usamos y cuáles son sus derechos conforme al Reglamento General de Protección de Datos (RGPD).','en'=>'At Romvill we respect your privacy and are committed to protecting your personal data. This policy describes what information we collect, how we use it and what your rights are under the General Data Protection Regulation (GDPR).','fr'=>'Chez Romvill, nous respectons votre vie privée et nous nous engageons à protéger vos données personnelles. Cette politique décrit les informations que nous collectons, comment nous les utilisons et quels sont vos droits en vertu du Règlement Général sur la Protection des Données (RGPD).','de'=>'Bei Romvill respektieren wir Ihre Privatsphäre und verpflichten uns, Ihre personenbezogenen Daten zu schützen. Diese Richtlinie beschreibt, welche Informationen wir erheben, wie wir sie verwenden und welche Rechte Sie gemäß der Datenschutz-Grundverordnung (DSGVO) haben.','ru'=>'В Romvill мы уважаем вашу конфиденциальность и обязуемся защищать ваши персональные данные. Эта политика описывает, какую информацию мы собираем, как её используем и каковы ваши права в соответствии с Общим регламентом о защите данных (GDPR).' ],
        'priv.s1.title'       => [ 'es'=>'Datos que recopilamos','en'=>'Data we collect','fr'=>'Données que nous collectons','de'=>'Daten, die wir erheben','ru'=>'Данные, которые мы собираем' ],
        'priv.s1.body'        => [ 'es'=>'Cuando utiliza nuestro formulario de contacto recopilamos: nombre, apellido, dirección de correo electrónico, teléfono (opcional), zona de interés y el mensaje que nos envía. No recopilamos datos de pago ni instalamos cookies de seguimiento de terceros.','en'=>'When you use our contact form we collect: first name, last name, email address, phone (optional), area of interest and the message you send us. We do not collect payment data or install third-party tracking cookies.','fr'=>'Lorsque vous utilisez notre formulaire de contact, nous collectons : prénom, nom de famille, adresse e-mail, téléphone (facultatif), zone d\'intérêt et le message que vous nous envoyez. Nous ne collectons pas de données de paiement ni n\'installons de cookies de suivi tiers.','de'=>'Wenn Sie unser Kontaktformular nutzen, erheben wir: Vorname, Nachname, E-Mail-Adresse, Telefon (optional), Interessengebiet und die Nachricht, die Sie uns senden. Wir erheben keine Zahlungsdaten und installieren keine Tracking-Cookies von Drittanbietern.','ru'=>'При использовании контактной формы мы собираем: имя, фамилию, адрес электронной почты, телефон (необязательно), зону интереса и ваше сообщение. Мы не собираем платёжные данные и не устанавливаем сторонние cookie для отслеживания.' ],
        'priv.s2.title'       => [ 'es'=>'Cómo usamos sus datos','en'=>'How we use your data','fr'=>'Comment nous utilisons vos données','de'=>'Wie wir Ihre Daten verwenden','ru'=>'Как мы используем ваши данные' ],
        'priv.s2.body'        => [ 'es'=>'Usamos sus datos exclusivamente para responder a su solicitud de informe y gestionar la relación comercial si así lo decide. No vendemos ni cedemos sus datos a terceros. Sus datos se tratan con base en su consentimiento (Art. 6.1.a RGPD) o en la ejecución de un contrato (Art. 6.1.b RGPD). Los datos se conservan durante el tiempo estrictamente necesario para la gestión del servicio solicitado.','en'=>'We use your data exclusively to respond to your report request and manage the commercial relationship should you choose to proceed. We do not sell or share your data with third parties. Your data is processed on the basis of your consent (Art. 6.1.a GDPR) or for the performance of a contract (Art. 6.1.b GDPR). Data is retained for the time strictly necessary to manage the requested service.','fr'=>'Nous utilisons vos données exclusivement pour répondre à votre demande de rapport et gérer la relation commerciale si vous le décidez. Nous ne vendons ni ne cédons vos données à des tiers. Vos données sont traitées sur la base de votre consentement (Art. 6.1.a RGPD) ou de l\'exécution d\'un contrat (Art. 6.1.b RGPD). Les données sont conservées pendant le temps strictement nécessaire à la gestion du service demandé.','de'=>'Wir verwenden Ihre Daten ausschließlich zur Beantwortung Ihrer Berichtsanfrage und zur Verwaltung der Geschäftsbeziehung, sofern Sie dies entscheiden. Wir verkaufen oder übermitteln Ihre Daten nicht an Dritte. Ihre Daten werden auf Grundlage Ihrer Einwilligung (Art. 6.1.a DSGVO) oder der Vertragserfüllung (Art. 6.1.b DSGVO) verarbeitet.','ru'=>'Мы используем ваши данные исключительно для ответа на запрос отчёта и управления деловыми отношениями. Мы не продаём и не передаём ваши данные третьим лицам. Обработка осуществляется на основании вашего согласия (ст. 6.1.a GDPR) или исполнения договора (ст. 6.1.b GDPR).' ],
        'priv.s3.title'       => [ 'es'=>'Sus derechos','en'=>'Your rights','fr'=>'Vos droits','de'=>'Ihre Rechte','ru'=>'Ваши права' ],
        'priv.s3.body'        => [ 'es'=>'Conforme al RGPD, tiene derecho a acceder, rectificar, suprimir, limitar el tratamiento, portabilidad y oponerse al tratamiento de sus datos. Para ejercer cualquiera de estos derechos, escríbanos a contacto@romvill.com con el asunto "Derechos RGPD". También puede presentar una reclamación ante la Agencia Española de Protección de Datos (aepd.es).','en'=>'Under the GDPR, you have the right to access, rectify, erase, restrict processing, data portability and to object to the processing of your data. To exercise any of these rights, write to us at contacto@romvill.com with the subject "GDPR Rights". You may also lodge a complaint with your national data protection authority.','fr'=>'Conformément au RGPD, vous avez le droit d\'accéder à vos données, de les rectifier, de les supprimer, d\'en limiter le traitement, à la portabilité et de vous opposer à leur traitement. Pour exercer l\'un de ces droits, écrivez-nous à contacto@romvill.com avec l\'objet "Droits RGPD". Vous pouvez également introduire une réclamation auprès de l\'Agence espagnole de protection des données (aepd.es).','de'=>'Gemäß DSGVO haben Sie das Recht auf Zugang, Berichtigung, Löschung, Einschränkung der Verarbeitung, Datenübertragbarkeit und Widerspruch. Um diese Rechte auszuüben, schreiben Sie uns an contacto@romvill.com mit dem Betreff "DSGVO-Rechte". Sie können außerdem eine Beschwerde bei der spanischen Datenschutzbehörde (aepd.es) einreichen.','ru'=>'В соответствии с GDPR вы имеете право на доступ, исправление, удаление, ограничение обработки, переносимость данных и возражение против обработки. Для реализации этих прав напишите на contacto@romvill.com с темой «Права GDPR». Вы также можете подать жалобу в Испанское агентство по защите данных (aepd.es).' ],
        'priv.s4.title'       => [ 'es'=>'Responsable del tratamiento','en'=>'Data controller','fr'=>'Responsable du traitement','de'=>'Verantwortlicher','ru'=>'Ответственный за обработку' ],
        'priv.s4.body'        => [ 'es'=>'Responsable: Romvill. Correo de contacto: contacto@romvill.com. Domicilio social: España. Si tiene cualquier duda sobre el tratamiento de sus datos, no dude en contactarnos.','en'=>'Controller: Romvill. Contact email: contacto@romvill.com. Registered address: Spain. If you have any questions about the processing of your data, please do not hesitate to contact us.','fr'=>'Responsable : Romvill. E-mail de contact : contacto@romvill.com. Siège social : Espagne. Si vous avez des questions sur le traitement de vos données, n\'hésitez pas à nous contacter.','de'=>'Verantwortlicher: Romvill. Kontakt-E-Mail: contacto@romvill.com. Sitz: Spanien. Wenn Sie Fragen zur Verarbeitung Ihrer Daten haben, zögern Sie nicht, uns zu kontaktieren.','ru'=>'Ответственный: Romvill. Email: contacto@romvill.com. Адрес: Испания. По любым вопросам обработки данных обращайтесь к нам.' ],

        // ── TÉRMINOS PAGE ─────────────────────────────────────────
        'terms.title'         => [ 'es'=>'Términos y Condiciones','en'=>'Terms and Conditions','fr'=>'Conditions Générales','de'=>'Nutzungsbedingungen','ru'=>'Условия Использования' ],
        'terms.badge'         => [ 'es'=>'Legal','en'=>'Legal','fr'=>'Légal','de'=>'Rechtlich','ru'=>'Правовой' ],
        'terms.updated'       => [ 'es'=>'Última actualización: junio 2026','en'=>'Last updated: June 2026','fr'=>'Dernière mise à jour : juin 2026','de'=>'Letzte Aktualisierung: Juni 2026','ru'=>'Последнее обновление: июнь 2026' ],
        'terms.intro'         => [ 'es'=>'Al acceder o utilizar el sitio web de Romvill y solicitar nuestros servicios, usted acepta los presentes términos y condiciones. Si no está de acuerdo con alguno de ellos, le rogamos que no utilice el servicio.','en'=>'By accessing or using the Romvill website and requesting our services, you accept these terms and conditions. If you do not agree with any of them, please do not use the service.','fr'=>'En accédant au site web de Romvill et en demandant nos services, vous acceptez les présentes conditions générales. Si vous n\'êtes pas d\'accord, nous vous prions de ne pas utiliser le service.','de'=>'Durch den Zugriff auf die Romvill-Website und die Inanspruchnahme unserer Dienste akzeptieren Sie diese Nutzungsbedingungen. Wenn Sie nicht einverstanden sind, bitten wir Sie, den Dienst nicht zu nutzen.','ru'=>'Получая доступ к сайту Romvill и запрашивая наши услуги, вы принимаете настоящие условия использования. Если вы не согласны — просим не пользоваться сервисом.' ],
        'terms.s1.title'      => [ 'es'=>'Descripción del servicio','en'=>'Service description','fr'=>'Description du service','de'=>'Dienstbeschreibung','ru'=>'Описание услуги' ],
        'terms.s1.body'       => [ 'es'=>'Romvill presta servicios de análisis e inteligencia territorial en la Costa Mediterránea española. Los informes son documentos informativos y no constituyen asesoramiento legal, financiero o inmobiliario vinculante. Cada informe se elabora de forma personalizada bajo los criterios profesionales del equipo Romvill y se entrega en el plazo acordado con el cliente.','en'=>'Romvill provides territorial analysis and intelligence services on the Spanish Mediterranean Coast. The reports are informational documents and do not constitute binding legal, financial or real estate advice. Each report is prepared on a personalised basis under the professional criteria of the Romvill team and delivered within the timeframe agreed with the client.','fr'=>'Romvill fournit des services d\'analyse et d\'intelligence territoriale sur la Côte Méditerranéenne espagnole. Les rapports sont des documents d\'information et ne constituent pas un conseil juridique, financier ou immobilier contraignant. Chaque rapport est élaboré de façon personnalisée selon les critères professionnels de l\'équipe Romvill et livré dans le délai convenu avec le client.','de'=>'Romvill bietet territoriale Analyse- und Intelligenzdienstleistungen an der spanischen Mittelmeerküste an. Die Berichte sind Informationsdokumente und stellen keine verbindliche rechtliche, finanzielle oder immobilienbezogene Beratung dar. Jeder Bericht wird personalisiert und innerhalb der vereinbarten Frist geliefert.','ru'=>'Romvill предоставляет услуги территориального анализа и аналитики на испанском средиземноморском побережье. Отчёты носят информационный характер и не являются юридической, финансовой или риелторской консультацией. Каждый отчёт готовится индивидуально по профессиональным критериям команды Romvill и передаётся в согласованный с клиентом срок.' ],
        'terms.s2.title'      => [ 'es'=>'Limitación de responsabilidad','en'=>'Limitation of liability','fr'=>'Limitation de responsabilité','de'=>'Haftungsbeschränkung','ru'=>'Ограничение ответственности' ],
        'terms.s2.body'       => [ 'es'=>'Romvill no garantiza que los datos incluidos en el informe sean exhaustivos o completamente actualizados en el momento de su entrega. La información proporcionada no debe usarse como único criterio para tomar decisiones de compra, inversión o traslado. Romvill no se hace responsable de las decisiones tomadas basándose en los informes ni de los daños y perjuicios que pudieran derivarse.','en'=>'Romvill does not guarantee that the data included in the report is exhaustive or fully up-to-date at the time of delivery. The information should not be used as the sole criterion for purchase, investment or relocation decisions. Romvill is not responsible for decisions made based on the reports nor for any resulting damages.','fr'=>'Romvill ne garantit pas que les données sont exhaustives ou entièrement à jour. Les informations fournies ne doivent pas être utilisées comme seul critère décisionnel. Romvill n\'est pas responsable des décisions prises sur la base des rapports.','de'=>'Romvill garantiert nicht, dass die Berichtsdaten vollständig oder aktuell sind. Die Informationen sollten nicht als alleiniges Entscheidungskriterium genutzt werden. Romvill übernimmt keine Haftung für auf Basis der Berichte getroffene Entscheidungen.','ru'=>'Romvill не гарантирует исчерпывающей актуальности данных на момент доставки. Информация не должна использоваться как единственный критерий решения. Romvill не несёт ответственности за решения на основе отчётов.' ],
        'terms.s3.title'      => [ 'es'=>'Propiedad intelectual','en'=>'Intellectual property','fr'=>'Propriété intellectuelle','de'=>'Geistiges Eigentum','ru'=>'Интеллектуальная собственность' ],
        'terms.s3.body'       => [ 'es'=>'Todos los informes, metodologías y contenidos del sitio web son propiedad intelectual de Romvill. Queda prohibida su reproducción total o parcial sin autorización escrita. El cliente puede usar el informe para uso personal o interno de su empresa, pero no para redistribución comercial ni publicación sin consentimiento.','en'=>'All reports, methodologies and website content are the intellectual property of Romvill. Their total or partial reproduction without written authorisation is prohibited. The client may use the report for personal or internal business use, but not for commercial redistribution or publication without consent.','fr'=>'Tous les rapports, méthodologies et contenus sont la propriété intellectuelle de Romvill. Leur reproduction sans autorisation écrite est interdite. Le client peut utiliser le rapport à des fins personnelles, mais non pour la redistribution commerciale.','de'=>'Alle Berichte, Methoden und Website-Inhalte sind geistiges Eigentum von Romvill. Reproduktion ohne schriftliche Genehmigung ist verboten. Der Kunde darf den Bericht für persönliche Zwecke nutzen, nicht zur kommerziellen Weitergabe.','ru'=>'Все отчёты, методологии и контент являются интеллектуальной собственностью Romvill. Воспроизведение без письменного разрешения запрещено. Клиент может использовать отчёт в личных целях, но не для коммерческого распространения.' ],
        'terms.s4.title'      => [ 'es'=>'Ley aplicable','en'=>'Governing law','fr'=>'Loi applicable','de'=>'Anwendbares Recht','ru'=>'Применимое право' ],
        'terms.s4.body'       => [ 'es'=>'Estos términos se rigen por la legislación española. Cualquier disputa que surja será sometida a los tribunales de la ciudad de Alicante, salvo que la normativa de protección al consumidor aplicable establezca otro fuero competente.','en'=>'These terms are governed by Spanish law. Any dispute arising will be submitted to the courts of the city of Alicante, unless applicable consumer protection regulations provide for a different jurisdiction.','fr'=>'Ces conditions sont régies par le droit espagnol. Tout litige sera soumis aux tribunaux d\'Alicante, sauf disposition contraire de la réglementation applicable sur la protection des consommateurs.','de'=>'Diese Bedingungen unterliegen dem spanischen Recht. Streitigkeiten werden den Gerichten der Stadt Alicante vorgelegt, sofern das Verbraucherschutzrecht nichts anderes vorsieht.','ru'=>'Условия регулируются испанским законодательством. Споры передаются в суды Аликанте, если только применимое законодательство о защите прав потребителей не предусматривает иного.' ],
        // ── SCHEMA JSON-LD ───────────────────────────────────────
        'schema.service.express.name' => [ 'es'=>'Informe Esencial de Zona','en'=>'Essential Area Report','fr'=>'Rapport Essentiel de Zone','de'=>'Essential-Gebietsbericht','ru'=>'Отчёт по зоне «Основной»' ],
        'schema.service.express.desc' => [ 'es'=>'Radiografía rápida de zona con indicadores clave de seguridad, servicios y entorno. Entrega en 3-4 días.','en'=>'Quick area overview with key safety, services and environment indicators. Delivery in 3-4 days.','fr'=>'Aperçu rapide de zone avec indicateurs clés de sécurité, services et environnement. Livraison en 3-4 jours.','de'=>'Schneller Gebietsüberblick mit Schlüsselindikatoren zu Sicherheit, Dienstleistungen und Umgebung. Lieferung in 3-4 Tagen.','ru'=>'Быстрый обзор зоны с ключевыми показателями безопасности, услуг и окружения. Доставка за 3-4 дня.' ],
        'schema.service.analysis.name' => [ 'es'=>'Informe Superior de Zona','en'=>'Superior Area Report','fr'=>'Rapport Supérieur de Zone','de'=>'Superior-Gebietsbericht','ru'=>'Отчёт по зоне «Супериор»' ],
        'schema.service.analysis.desc' => [ 'es'=>'Análisis territorial completo: seguridad, demografía, servicios, transporte, entorno y planificación pública. Entrega en 5-7 días.','en'=>'Complete territorial analysis: safety, demographics, services, transport, environment and public planning. Delivery in 5-7 days.','fr'=>'Analyse territoriale complète : sécurité, démographie, services, transports, environnement et planification publique. Livraison en 5-7 jours.','de'=>'Vollständige Gebietsanalyse: Sicherheit, Demographie, Dienstleistungen, Verkehr, Umgebung und öffentliche Planung. Lieferung in 5-7 Tagen.','ru'=>'Полный территориальный анализ: безопасность, демография, услуги, транспорт, окружение и государственное планирование. Доставка за 5-7 дней.' ],
        'schema.service.premium.name' => [ 'es'=>'Informe Premium de Zona','en'=>'Premium Area Report','fr'=>'Rapport Premium de Zone','de'=>'Premium-Gebietsbericht','ru'=>'Премиум-отчёт по зоне' ],
        'schema.service.premium.desc' => [ 'es'=>'Análisis profundo con contexto de inversión, verificación presencial y acompañamiento dedicado. Entrega en 7-14 días.','en'=>'In-depth analysis with investment context, on-site verification and dedicated support. Delivery in 7-14 days.','fr'=>'Analyse approfondie avec contexte d\'investissement, vérification sur site et accompagnement dédié. Livraison en 7-14 jours.','de'=>'Tiefgehende Analyse mit Investitionskontext, Vor-Ort-Überprüfung und persönlicher Betreuung. Lieferung in 7-14 Tagen.','ru'=>'Углублённый анализ с инвестиционным контекстом, проверкой на месте и персональным сопровождением. Доставка за 7-14 дней.' ],
        'schema.faq1.q' => [ 'es'=>'¿Es realmente independiente?','en'=>'Is it truly independent?','fr'=>'Est-ce vraiment indépendant ?','de'=>'Ist es wirklich unabhängig?','ru'=>'Это действительно независимый анализ?' ],
        'schema.faq1.a' => [ 'es'=>'Sí. No vendemos inmuebles ni cobramos comisiones de agencias o promotores. Solo analizamos.','en'=>'Yes. We don\'t sell properties or earn commissions from agencies or developers. We only analyse.','fr'=>'Oui. Nous ne vendons pas de biens immobiliers et ne percevons aucune commission. Nous analysons uniquement.','de'=>'Ja. Wir verkaufen keine Immobilien und erhalten keine Provisionen von Agenturen oder Bauträgern. Wir analysieren ausschließlich.','ru'=>'Да. Мы не продаём недвижимость и не получаем комиссий от агентств или застройщиков. Мы только анализируем.' ],
        'schema.faq2.q' => [ 'es'=>'¿Y si necesito más profundidad después?','en'=>'What if I need more depth later?','fr'=>'Et si j\'ai besoin de plus de profondeur ensuite ?','de'=>'Was, wenn ich später mehr Tiefe brauche?','ru'=>'Что если мне потом понадобится более глубокий анализ?' ],
        'schema.faq2.a' => [ 'es'=>'Durante los 60 días siguientes, te descontamos íntegramente lo que pagaste por tu informe si decides pasar a un nivel superior. Solo abonas la diferencia.','en'=>'For the next 60 days, we deduct in full what you paid for your report if you decide to move up to a higher level. You only pay the difference.','fr'=>'Pendant les 60 jours suivants, nous déduisons intégralement ce que vous avez payé pour votre rapport si vous décidez de passer à un niveau supérieur. Vous ne réglez que la différence.','de'=>'In den folgenden 60 Tagen rechnen wir den für Ihren Bericht gezahlten Betrag vollständig an, wenn Sie sich für eine höhere Stufe entscheiden. Sie zahlen nur die Differenz.','ru'=>'В течение следующих 60 дней мы полностью вычитаем сумму, уплаченную за ваш отчёт, если вы решите перейти на более высокий уровень. Вы доплачиваете только разницу.' ],
        'schema.faq3.q' => [ 'es'=>'¿Sobre qué zonas trabajáis?','en'=>'Which areas do you cover?','fr'=>'Quelles zones couvrez-vous ?','de'=>'Welche Gebiete decken Sie ab?','ru'=>'Какие зоны вы охватываете?' ],
        'schema.faq3.a' => [ 'es'=>'Costa Mediterránea: Alicante, Málaga y Marbella y su entorno. Otras zonas, a consultar.','en'=>'Mediterranean Coast: Alicante, Málaga and Marbella and surrounding areas. Other areas available on request.','fr'=>'Côte Méditerranéenne : Alicante, Málaga et Marbella et environs. Autres zones sur demande.','de'=>'Mittelmeerküste: Alicante, Málaga und Marbella und Umgebung. Weitere Gebiete auf Anfrage.','ru'=>'Средиземноморское побережье: Аликанте, Малага и Марбелья с окрестностями. Другие зоны — по запросу.' ],

        // ══════════ VERIFICACIÓN DE AUTENTICIDAD (/verificar/) ══════════
        'seo.title.verificar' => [ 'es'=>'Verificación de autenticidad | ROMVILL','en'=>'Verification of authenticity | ROMVILL','fr'=>'Vérification d\'authenticité | ROMVILL','de'=>'Echtheitsprüfung | ROMVILL','ru'=>'Проверка подлинности | ROMVILL' ],
        'seo.desc.verificar'  => [ 'es'=>'Compruebe que su expediente es un original emitido por ROMVILL: introduzca la referencia del documento y la contrastamos con nuestro registro de expedientes.','en'=>'Confirm that your report is an original issued by ROMVILL: enter the document reference and we check it against our register of issued reports.','fr'=>'Assurez-vous que votre dossier est un original émis par ROMVILL : saisissez la référence du document et nous la vérifions dans notre registre.','de'=>'Prüfen Sie, ob Ihr Dossier ein von ROMVILL ausgestelltes Original ist: Geben Sie die Referenz des Dokuments ein, wir gleichen sie mit unserem Register ab.','ru'=>'Убедитесь, что Ваше досье — оригинал, выданный ROMVILL: введите номер документа, и он будет сверен с нашим реестром.' ],
        'verif.kicker'        => [ 'es'=>'Registro de expedientes','en'=>'Register of issued reports','fr'=>'Registre des dossiers','de'=>'Dossier-Register','ru'=>'Реестр досье' ],
        'verif.title'         => [ 'es'=>'Verificación de autenticidad','en'=>'Verification of authenticity','fr'=>'Vérification d\'authenticité','de'=>'Echtheitsprüfung','ru'=>'Проверка подлинности' ],
        'verif.sub'           => [ 'es'=>'Compruebe que su expediente es un original emitido por ROMVILL. Introduzca la referencia que figura en la portada del documento.','en'=>'Confirm that your report is an original issued by ROMVILL. Enter the reference shown on the cover of your document.','fr'=>'Assurez-vous que votre dossier est un original émis par ROMVILL. Saisissez la référence figurant sur la couverture du document.','de'=>'Prüfen Sie, ob Ihr Dossier ein von ROMVILL ausgestelltes Original ist. Geben Sie die Referenz vom Deckblatt des Dokuments ein.','ru'=>'Убедитесь, что Ваше досье — оригинал, выданный ROMVILL. Введите номер, указанный на обложке документа.' ],
        'verif.label'         => [ 'es'=>'Referencia del expediente','en'=>'Report reference','fr'=>'Référence du dossier','de'=>'Dossier-Referenz','ru'=>'Номер досье' ],
        'verif.hint'          => [ 'es'=>'Formato: RV-AAAA-XXXX-XXX-NNNN, tal como figura en su documento.','en'=>'Format: RV-YYYY-XXXX-XXX-NNNN, as shown on your document.','fr'=>'Format : RV-AAAA-XXXX-XXX-NNNN, telle qu\'elle figure sur votre document.','de'=>'Format: RV-JJJJ-XXXX-XXX-NNNN, wie auf Ihrem Dokument angegeben.','ru'=>'Формат: RV-ГГГГ-XXXX-XXX-NNNN, как указано в документе.' ],
        'verif.btn'           => [ 'es'=>'Verificar referencia','en'=>'Verify reference','fr'=>'Vérifier la référence','de'=>'Referenz prüfen','ru'=>'Проверить номер' ],
        'verif.ok.title'      => [ 'es'=>'Documento auténtico','en'=>'Authentic document','fr'=>'Document authentique','de'=>'Authentisches Dokument','ru'=>'Подлинный документ' ],
        'verif.ok.sub'        => [ 'es'=>'Emitido por ROMVILL. Hemos comprobado esta referencia en nuestro registro de expedientes.','en'=>'Issued by ROMVILL. We have verified this reference against our register.','fr'=>'Émis par ROMVILL. Nous avons vérifié cette référence dans notre registre.','de'=>'Ausgestellt von ROMVILL. Die Prüfung im Register hat die Referenz bestätigt.','ru'=>'Выдан ROMVILL. Номер подтверждён по реестру досье.' ],
        'verif.field.ref'     => [ 'es'=>'Referencia','en'=>'Reference','fr'=>'Référence','de'=>'Referenz','ru'=>'Номер' ],
        'verif.field.zona'    => [ 'es'=>'Zona analizada','en'=>'Area analysed','fr'=>'Zone analysée','de'=>'Analysiertes Gebiet','ru'=>'Анализируемая зона' ],
        'verif.field.emitido' => [ 'es'=>'Fecha de emisión','en'=>'Date of issue','fr'=>'Date d\'émission','de'=>'Ausstellungsdatum','ru'=>'Дата выдачи' ],
        'verif.field.estado'  => [ 'es'=>'Estado','en'=>'Status','fr'=>'Statut','de'=>'Status','ru'=>'Статус' ],
        'verif.estado.vigente'=> [ 'es'=>'Vigente','en'=>'Valid','fr'=>'En vigueur','de'=>'Gültig','ru'=>'Действителен' ],
        'verif.estado.ensayo' => [ 'es'=>'Ensayo (cliente ficticio)','en'=>'Trial (fictitious client)','fr'=>'Essai (client fictif)','de'=>'Testlauf (fiktiver Kunde)','ru'=>'Пробный выпуск (вымышленный клиент)' ],
        'verif.ko.title'      => [ 'es'=>'Referencia no registrada','en'=>'Reference not on record','fr'=>'Référence non enregistrée','de'=>'Referenz nicht registriert','ru'=>'Номер не зарегистрирован' ],
        'verif.ko.body'       => [ 'es'=>'Esta referencia no consta en nuestro registro. Si figura en un documento que le han entregado, contacte con nosotros de inmediato.','en'=>'This reference does not appear in our register. If it is shown on a document you have been given, please contact us immediately.','fr'=>'Cette référence ne figure pas dans notre registre. Si elle apparaît sur un document qui vous a été remis, contactez-nous immédiatement.','de'=>'Diese Referenz ist in unserem Register nicht verzeichnet. Sollte sie auf einem Ihnen übergebenen Dokument stehen, kontaktieren Sie uns bitte umgehend.','ru'=>'Данный номер в нашем реестре не значится. Если он указан в переданном Вам документе, незамедлительно свяжитесь с нами.' ],
        'verif.ko.cta'        => [ 'es'=>'Contactar con ROMVILL','en'=>'Contact ROMVILL','fr'=>'Contacter ROMVILL','de'=>'ROMVILL kontaktieren','ru'=>'Связаться с ROMVILL' ],
        'verif.note'          => [ 'es'=>'Cada expediente ROMVILL se emite con una referencia única. Este registro es la fuente oficial de verificación.','en'=>'Every ROMVILL report is issued with a unique reference. This register is the official source of verification.','fr'=>'Chaque dossier ROMVILL est émis avec une référence unique. Ce registre constitue la source officielle de vérification.','de'=>'Jedes ROMVILL-Dossier wird mit einer eindeutigen Referenz ausgestellt. Dieses Register ist die offizielle Prüfquelle.','ru'=>'Каждое досье ROMVILL выдаётся с уникальным номером. Настоящий реестр — официальный источник проверки.' ],

