        'conc.subject'    => [ 'es'=>'Su plaza en el Programa Inaugural de ROMVILL','en'=>'Your place on the ROMVILL Inaugural Programme','fr'=>'Votre place au Programme Inaugural de ROMVILL','de'=>'Ihr Platz im ROMVILL-Eröffnungsprogramm','ru'=>'Ваше место в Стартовой программе ROMVILL' ],
        'conc.saludo'     => [ 'es'=>'Estimado/a %s:','en'=>'Dear %s,','fr'=>'Madame, Monsieur,','de'=>'Guten Tag %s,','ru'=>'Уважаемый(-ая) %s,' ],
        'conc.p1'         => [ 'es'=>'Hemos evaluado su solicitud y le confirmamos una plaza en el Programa Inaugural de ROMVILL: un análisis completo de nivel %s, sin coste alguno.','en'=>'We have assessed your application and can confirm your place on the ROMVILL Inaugural Programme: a complete %s-level analysis, at no cost.','fr'=>'Nous avons étudié votre demande et nous vous confirmons une place au Programme Inaugural de ROMVILL : une analyse complète de niveau %s, sans aucun frais.','de'=>'Wir haben Ihre Anfrage geprüft und bestätigen Ihnen einen Platz im ROMVILL-Eröffnungsprogramm: eine vollständige Analyse der Stufe %s, ohne jegliche Kosten.','ru'=>'Ваша заявка рассмотрена. Подтверждаем Ваше место в Стартовой программе ROMVILL: полный анализ уровня «%s» без какой-либо оплаты.' ],
        'conc.p2'         => [ 'es'=>'La contraprestación es una sola: su valoración honesta en nuestra ficha de Google una vez recibido y examinado su expediente.','en'=>'We ask for one thing in return: your honest review on our Google listing once you have received and examined your dossier.','fr'=>'La contrepartie est unique : votre avis honnête sur notre fiche Google, une fois votre dossier reçu et examiné.','de'=>'Die Gegenleistung besteht aus einem einzigen Punkt: Ihrer ehrlichen Bewertung auf unserem Google-Profil, sobald Sie Ihr Dossier erhalten und geprüft haben.','ru'=>'Встречное условие одно: Ваш честный отзыв в нашем профиле Google после получения и изучения досье.' ],
        'conc.p2b'        => [ 'es'=>'Sus primeras reseñas son el cimiento de nuestra reputación; las tratamos como lo que son: un pago en confianza.','en'=>'Our first reviews are the foundation of our reputation; we treat them as what they are: payment in trust.','fr'=>'Vos premiers avis constituent le socle de notre réputation ; nous les traitons pour ce qu\'ils sont : un paiement en confiance.','de'=>'Die ersten Bewertungen sind das Fundament unseres Rufs; wir behandeln sie als das, was sie sind: eine Zahlung in Vertrauen.','ru'=>'Первые отзывы — основа нашей репутации; мы относимся к ним как к тому, чем они являются: платой доверием.' ],
        'conc.codigo.lbl' => [ 'es'=>'Su código personal','en'=>'Your personal code','fr'=>'Votre code personnel','de'=>'Ihr persönlicher Code','ru'=>'Ваш персональный код' ],
        'conc.p3'         => [ 'es'=>'Este código es único, intransferible y de un solo uso.','en'=>'This code is unique, non-transferable and valid for a single use.','fr'=>'Ce code est unique, incessible et valable pour un usage unique.','de'=>'Dieser Code ist einmalig, nicht übertragbar und nur ein einziges Mal gültig.','ru'=>'Код уникален, не подлежит передаче и действителен для однократного использования.' ],
        'conc.p3b'        => [ 'es'=>'Para activarlo, complete el cuestionario en romvill.com/presupuesto-bloque-1 e introdúzcalo en el campo «Código de invitación» antes de enviar.','en'=>'To activate it, complete the questionnaire at romvill.com/presupuesto-bloque-1 and enter it in the “Invitation code” field before submitting.','fr'=>'Pour l\'activer, complétez le questionnaire sur romvill.com/presupuesto-bloque-1 et saisissez-le dans le champ « Code d\'invitation » avant l\'envoi.','de'=>'Zur Aktivierung füllen Sie den Fragebogen unter romvill.com/presupuesto-bloque-1 aus und tragen den Code vor dem Absenden in das Feld „Einladungscode“ ein.','ru'=>'Для активации заполните анкету на romvill.com/presupuesto-bloque-1 и укажите код в поле «Код приглашения» перед отправкой.' ],
        'conc.btn'        => [ 'es'=>'Completar el cuestionario','en'=>'Complete the questionnaire','fr'=>'Compléter le questionnaire','de'=>'Zum Fragebogen','ru'=>'Заполнить анкету' ],
        'conc.p4'         => [ 'es'=>'Quedamos a su disposición.','en'=>'Please do not hesitate to contact us.','fr'=>'Nous restons à votre disposition. Bien cordialement,','de'=>'Für Rückfragen stehen wir Ihnen zur Verfügung.','ru'=>'Будем рады ответить на Ваши вопросы.' ],
        'conc.firma'      => [ 'es'=>'Criterio antes de decidir.','en'=>'Informed decisions. Every time.','fr'=>'Le discernement avant la décision.','de'=>'Klarheit, bevor Sie entscheiden.','ru'=>'Знание — прежде решения.' ],

