        'fb.checks.hint'   => [ 'es'=>'Puede marcar varias. No es necesario redactar nada.','en'=>'You may tick several. No writing is required.','fr'=>'Vous pouvez en cocher plusieurs. Aucune rédaction n\'est nécessaire.','de'=>'Mehrfachauswahl möglich. Ein Text ist nicht erforderlich.','ru'=>'Можно отметить несколько. Писать текст не требуется.' ],
