        'fb.mejora.label'  => [ 'es'=>'¿Qué mejoraría?','en'=>'What would you improve?','fr'=>'Que souhaiteriez-vous améliorer ?','de'=>'Was würden Sie verbessern?','ru'=>'Что бы Вы улучшили?' ],
        'fb.valioso.label' => [ 'es'=>'¿Qué le resultó más valioso?','en'=>'What did you find most valuable?','fr'=>'Qu\'avez-vous trouvé de plus utile ?','de'=>'Was war für Sie am wertvollsten?','ru'=>'Что оказалось наиболее ценным?' ],
