        'fb.btn'           => [ 'es'=>'Enviar mi valoración','en'=>'Submit my assessment','fr'=>'Envoyer mon évaluation','de'=>'Bewertung absenden','ru'=>'Отправить оценку' ],
        'fb.btn.sending'   => [ 'es'=>'Enviando…','en'=>'Submitting…','fr'=>'Envoi en cours…','de'=>'Wird gesendet…','ru'=>'Отправка…' ],
        'fb.err.rating'    => [ 'es'=>'Indique su valoración global antes de enviar.','en'=>'Please indicate your overall assessment before submitting.','fr'=>'Veuillez indiquer votre évaluation globale avant l\'envoi.','de'=>'Bitte geben Sie vor dem Absenden Ihre Gesamtbewertung an.','ru'=>'Укажите общую оценку перед отправкой.' ],
        'fb.err.conn'      => [ 'es'=>'No hemos podido registrar su valoración. Inténtelo de nuevo o escríbanos a contacto@romvill.com.','en'=>'We were unable to record your assessment. Please try again or write to contacto@romvill.com.','fr'=>'Nous n\'avons pas pu enregistrer votre évaluation. Veuillez réessayer ou nous écrire à contacto@romvill.com.','de'=>'Ihre Bewertung konnte nicht erfasst werden. Bitte versuchen Sie es erneut oder schreiben Sie an contacto@romvill.com.','ru'=>'Не удалось зарегистрировать Вашу оценку. Повторите попытку или напишите на contacto@romvill.com.' ],
        'fb.ok.title'      => [ 'es'=>'Valoración registrada','en'=>'Assessment recorded','fr'=>'Évaluation enregistrée','de'=>'Bewertung erfasst','ru'=>'Оценка зарегистрирована' ],
        'fb.ok.body'       => [ 'es'=>'Gracias por su valoración. Cada observación de nuestros primeros clientes mejora los expedientes que emitiremos después.','en'=>'Thank you for your assessment. Every observation from our first clients improves the dossiers we issue thereafter.','fr'=>'Nous vous remercions de votre évaluation. Chaque observation de nos premiers clients améliore les dossiers que nous émettrons ensuite.','de'=>'Wir danken Ihnen für Ihre Bewertung. Jede Anmerkung unserer ersten Kunden verbessert die Dossiers, die wir danach erstellen.','ru'=>'Благодарим за оценку. Каждое замечание наших первых клиентов улучшает досье, которые мы выпустим впоследствии.' ],
        'fb.ok.google'     => [ 'es'=>'Si el expediente le ha resultado útil, le agradeceremos que comparta su valoración públicamente en nuestra ficha de Google. Es una invitación, no una condición: escriba lo que realmente piense.','en'=>'If you have found the dossier useful, we should be grateful if you would share your assessment publicly on our Google listing. This is an invitation, not a condition: please write what you genuinely think.','fr'=>'Si le dossier vous a été utile, nous vous serions reconnaissants de partager publiquement votre évaluation sur notre fiche Google. Il s\'agit d\'une invitation, non d\'une condition : écrivez ce que vous pensez réellement.','de'=>'Wenn Ihnen das Dossier von Nutzen war, würden wir uns über Ihre öffentliche Bewertung in unserem Google-Profil freuen. Dies ist eine Einladung, keine Bedingung: Schreiben Sie, was Sie tatsächlich denken.','ru'=>'Если досье оказалось для Вас полезным, будем признательны, если Вы поделитесь своей оценкой публично в нашем профиле Google. Это приглашение, а не условие: напишите то, что думаете на самом деле.' ],
        'fb.ok.btn'        => [ 'es'=>'Dejar mi reseña en Google','en'=>'Leave my review on Google','fr'=>'Laisser mon avis sur Google','de'=>'Bewertung bei Google abgeben','ru'=>'Оставить отзыв в Google' ],
        // Consentimiento de publicación (casilla NO marcada por defecto). Sin ella,
        // la valoración es de uso exclusivamente interno. Marco legal aprobado por
        // dirección: publicar exige consentimiento explícito + moderación humana.
        'fb.consent'       => [ 'es'=>'Autorizo a ROMVILL a publicar mi valoración como testimonio, identificada únicamente con mi nombre de pila e inicial y la zona analizada.','en'=>'I authorise ROMVILL to publish my assessment as a testimonial, identified solely by my first name and initial and the area analysed.','fr'=>'J\'autorise ROMVILL à publier mon évaluation à titre de témoignage, identifiée uniquement par mon prénom, l\'initiale de mon nom et la zone analysée.','de'=>'Ich willige ein, dass ROMVILL meine Bewertung als Referenz veröffentlicht, gekennzeichnet ausschließlich mit meinem Vornamen, dem Anfangsbuchstaben meines Nachnamens und dem untersuchten Gebiet.','ru'=>'Разрешаю ROMVILL опубликовать мою оценку в качестве отзыва с указанием только имени, инициала фамилии и проанализированной зоны.' ],
        'fb.consent.hint'  => [ 'es'=>'Casilla voluntaria. Si no la marca, su valoración se usa solo internamente. Puede retirar esta autorización escribiendo a contacto@romvill.com.','en'=>'This box is voluntary. If you leave it unticked, your assessment is used internally only. You may withdraw this authorisation by writing to contacto@romvill.com.','fr'=>'Case facultative. Si vous ne la cochez pas, votre évaluation est utilisée uniquement en interne. Vous pouvez retirer cette autorisation en écrivant à contacto@romvill.com.','de'=>'Freiwilliges Feld. Ohne Ihre Zustimmung wird Ihre Bewertung ausschließlich intern verwendet. Sie können diese Einwilligung jederzeit unter contacto@romvill.com widerrufen.','ru'=>'Поле необязательное. Без отметки оценка используется только внутри компании. Отозвать разрешение можно, написав на contacto@romvill.com.' ],
        'fb.privacidad'    => [ 'es'=>'Sus observaciones se tratan con la misma confidencialidad que su expediente. Solo se publican como testimonio si usted lo autoriza expresamente en la casilla anterior, y siempre después de revisión por una persona de ROMVILL.','en'=>'Your observations are treated with the same confidentiality as your dossier. They are published as a testimonial only if you expressly authorise it in the box above, and always after review by a member of ROMVILL.','fr'=>'Vos observations sont traitées avec la même confidentialité que votre dossier. Elles ne sont publiées à titre de témoignage que si vous l\'autorisez expressément dans la case ci-dessus, et toujours après examen par une personne de ROMVILL.','de'=>'Ihre Anmerkungen werden mit derselben Vertraulichkeit behandelt wie Ihr Dossier. Eine Veröffentlichung als Referenz erfolgt nur mit Ihrer ausdrücklichen Zustimmung im obenstehenden Feld und stets nach Prüfung durch eine Person von ROMVILL.','ru'=>'Ваши замечания обрабатываются с той же конфиденциальностью, что и досье. Они публикуются в качестве отзыва только при Вашем прямом разрешении в поле выше и всегда после проверки сотрудником ROMVILL.' ],

        // ══════════ TESTIMONIOS (bloque público) ══════════
        // Línea de transparencia legal obligatoria junto a CUALQUIER bloque de
